import React, { createContext, useContext, useEffect, useState, useRef } from "react";
import { supabase } from "@/integrations/supabase/client";
import type { User, Session } from "@supabase/supabase-js";

export interface UserPermissions {
  isAdmin: boolean;
  isClient: boolean;
  empresaId?: string;
  userId?: string;
  modules: {
    societario: boolean;
    fiscal: boolean;
    pessoal: boolean;
    certificados: boolean;
    procuracoes: boolean;
    vencimentos: boolean;
    parcelamentos: boolean;
    recalculos: boolean;
    honorarios: boolean;
    licencas: boolean;
    certidoes: boolean;
    declaracoes_mensais: boolean;
    declaracoes_anuais: boolean;
    agendamentos: boolean;
  };
  nome?: string;
  email?: string;
  cpf?: string;
  departamento?: string;
  profileCompleted?: boolean;
  termsAccepted?: boolean;
  firstAccessDone?: boolean;
}

interface AuthContextType {
  user: User | null;
  session: Session | null;
  userData: UserPermissions | null;
  loading: boolean;
  login: (email: string, password: string) => Promise<void>;
  logout: () => Promise<void>;
  refreshUserData: () => Promise<void>;
  loginAsClient: (cnpj: string, password: string) => Promise<void>;
}

const AuthContext = createContext<AuthContextType | null>(null);

export const useAuth = () => {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error("useAuth must be used within AuthProvider");
  return ctx;
};

const allModulesTrue = {
  societario: true, fiscal: true, pessoal: true, certificados: true,
  procuracoes: true, vencimentos: true, parcelamentos: true, recalculos: true,
  honorarios: true, licencas: true, certidoes: true, declaracoes_mensais: true,
  declaracoes_anuais: true, agendamentos: true,
};

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [userData, setUserData] = useState<UserPermissions | null>(null);
  const [loading, setLoading] = useState(true);
  const loadingUserRef = useRef<string | null>(null);

  const loadUserData = async (currentUser: User) => {
    if (loadingUserRef.current === currentUser.id) return;
    loadingUserRef.current = currentUser.id;

    try {
      const { data: roles } = await supabase.from("user_roles").select("role").eq("user_id", currentUser.id);

      const { data: profile, error: profileError } = await supabase
        .from("profiles")
        .select("*")
        .eq("user_id", currentUser.id)
        .maybeSingle();

      const { data: access } = await supabase
        .from("empresa_acessos")
        .select("empresa_id")
        .eq("user_id", currentUser.id)
        .maybeSingle();

      if (profileError && profileError.name !== 'AbortError') {
        console.error("AuthProvider: Error fetching profile for user", currentUser.id, profileError);
      }

      // Robust state derivation
      const profileData = profile as any;
      const profileCompleted = profileData ? (profileData.profile_completed ?? true) : true;
      const termsAccepted = profileData ? !!profileData.terms_accepted_at : true;
      const firstAccessDone = profileData ? (profileData.first_access_done ?? true) : true;

      const metadata = currentUser.user_metadata || {};
      const isAdmin = (roles?.some(r => r.role === "admin") || profileData?.role === "admin" || metadata.role === "admin") || false;
      const isClient = (metadata.role === "client" || profileData?.role === "client" || !!access) || false;
      const empresaId = access?.empresa_id || metadata.empresa_id || profileData?.empresa_id || undefined;

      if (isAdmin) {
        setUserData({
          isAdmin: true,
          isClient: false,
          empresaId: undefined,
          userId: currentUser.id,
          modules: allModulesTrue,
          nome: profileData?.nome_completo || currentUser.user_metadata?.full_name || currentUser.email || "Admin",
          email: currentUser.email || "",
          cpf: profileData?.cpf || "",
          departamento: profileData?.departamento || "Administração",
          profileCompleted,
          termsAccepted,
          firstAccessDone,
        });
      } else {
        const { data: perms } = await supabase.from("user_module_permissions").select("module_name").eq("user_id", currentUser.id);
        const moduleSet = new Set(perms?.map(p => p.module_name) || []);
        setUserData({
          isAdmin: false,
          isClient: isClient,
          empresaId: empresaId,
          userId: currentUser.id,
          modules: {
            societario: moduleSet.has("societario"),
            fiscal: moduleSet.has("fiscal"),
            pessoal: moduleSet.has("pessoal"),
            certificados: moduleSet.has("certificados"),
            procuracoes: moduleSet.has("procuracoes"),
            vencimentos: moduleSet.has("vencimentos"),
            parcelamentos: moduleSet.has("parcelamentos"),
            recalculos: moduleSet.has("recalculos"),
            honorarios: moduleSet.has("honorarios"),
            licencas: moduleSet.has("licencas"),
            certidoes: moduleSet.has("certidoes"),
            declaracoes_mensais: moduleSet.has("declaracoes_mensais"),
            declaracoes_anuais: moduleSet.has("declaracoes_anuais"),
            agendamentos: moduleSet.has("agendamentos"),
          },
          nome: profileData?.nome_completo || currentUser.user_metadata?.full_name || currentUser.email || "Usuário",
          email: currentUser.email || "",
          cpf: profileData?.cpf || "",
          departamento: profileData?.departamento || "",
          profileCompleted,
          termsAccepted,
          firstAccessDone,
        });
      }
    } catch (err) {
      console.error("AuthProvider: Critical error loading user data", err);
    } finally {
      setTimeout(() => { loadingUserRef.current = null; }, 1000); // Allow refreshing after a second
    }
  };

  const refreshUserData = async () => {
    if (user) await loadUserData(user);
  };

  // Decoupled effect to fetch user data whenever `user` state changes.
  // This breaks the deadlock caused by fetching inside `onAuthStateChange` callback.
  useEffect(() => {
    let mounted = true;

    if (user && !userData) {
      loadUserData(user).then(() => {
        if (mounted) setLoading(false);
      });
    } else if (!user) {
      if (mounted) {
        setUserData(null);
        setLoading(false);
      }
    }

    return () => { mounted = false; };
  }, [user]);

  useEffect(() => {
    let mounted = true;

    const { data: { subscription } } = supabase.auth.onAuthStateChange((event, newSession) => {
      if (!mounted) return;
      setSession(newSession);
      const newUser = newSession?.user ?? null;
      setUser(newUser);

      // Trava de segurança para links de recuperação de senha enviados por e-mail
      if (event === "PASSWORD_RECOVERY" && window.location.pathname !== "/reset-password") {
        window.location.href = "/reset-password";
      }
    });

    supabase.auth.getSession().then(({ data: { session: existing } }) => {
      if (!mounted) return;
      setSession(existing);
      setUser(existing?.user ?? null);
      if (!existing?.user) {
        setLoading(false);
      }
    });

    return () => {
      mounted = false;
      subscription.unsubscribe();
    };
  }, []);

  const login = async (email: string, password: string) => {
    const { error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) throw error;
  };

  const logout = async () => {
    await supabase.auth.signOut();
    setUserData(null);
  };

  const loginAsClient = async (cnpj: string, password: string) => {
    const cleanCNPJ = cnpj.replace(/\D/g, "");
    if (!cleanCNPJ || cleanCNPJ.length !== 14) {
      throw new Error("CNPJ inválido. Digite os 14 números.");
    }

    const email = `${cleanCNPJ}@audipreve.com`;
    const cleanPassword = password.replace(/\D/g, "");

    // Tenta primeiro com a senha como digitada
    let { error } = await supabase.auth.signInWithPassword({ email, password });

    // Se falhar e a senha parecer um CNPJ com máscara, tenta com a senha limpa
    if (error && cleanPassword.length === 14 && password !== cleanPassword) {
      const { error: error2 } = await supabase.auth.signInWithPassword({
        email,
        password: cleanPassword
      });
      if (!error2) error = null;
    }

    if (error) {
      console.error("Login Error:", error);
      if (error.message === "Invalid login credentials" || error.message === "Invalid credentials") {
        throw new Error("CNPJ ou senha inválidos. Utilize o CNPJ (apenas números) como senha inicial.");
      }
      if (error.message.includes("Email not confirmed")) {
        throw new Error("O e-mail deste acesso ainda não foi confirmado. Por favor, solicite ao administrador para sincronizar os acessos.");
      }
      throw error;
    }
  };

  return (
    <AuthContext.Provider value={{ user, session, userData, loading, login, logout, refreshUserData, loginAsClient }}>
      {children}
    </AuthContext.Provider>
  );
};

import { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";

export const useEmpresas = (moduloId: string) => {
    const { user } = useAuth();
    const [empresas, setEmpresas] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        let mounted = true;

        const fetchEmpresas = async () => {
            setLoading(true);
            try {
                if (!user) return;

                let query = supabase.from("empresas").select("*").order("nome_empresa");

                if (moduloId && moduloId !== "declaracoes_mensais") {
                    query = query.contains("modulos_ativos", [moduloId]);
                }

                const { data: emps, error: empsError } = await query;

                if (empsError) throw empsError;
                if (!emps) {
                    if (mounted) { setEmpresas([]); setLoading(false); }
                    return;
                }

                // 2. Fetch specific access records for the current user
                const { data: acessos } = await supabase
                    .from("empresa_acessos")
                    .select("empresa_id, modulos_permitidos")
                    .eq("user_id", user.id);

                const acessosMap = new Map<string, string[]>();
                if (acessos) {
                    acessos.forEach((a) => {
                        acessosMap.set(a.empresa_id, a.modulos_permitidos);
                    });
                }

                // 3. Filter the companies
                const filtered = emps.filter((emp) => {
                    const modulosPermitidos = acessosMap.get(emp.id);
                    // If no row exists in empresa_acessos for this user, they have full access (return true)
                    // If row exists, check if modulos_permitidos includes the current moduloId
                    if (!modulosPermitidos) return true;
                    return modulosPermitidos.includes(moduloId);
                });

                if (mounted) {
                    setEmpresas(filtered);
                }
            } catch (err) {
                console.error("Error fetching empresas:", err);
            } finally {
                if (mounted) setLoading(false);
            }
        };

        fetchEmpresas();

        return () => {
            mounted = false;
        };
    }, [moduloId, user]);

    return { empresas, loading };
};

import { useState, useEffect, useRef } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";

export interface Notification {
    id: string;
    recipient_id: string;
    title: string;
    message: string;
    type: string;
    link?: string;
    is_read: boolean;
    created_at: string;
    metadata?: any;
}

export const useNotifications = () => {
    const { user } = useAuth();
    const [notifications, setNotifications] = useState<Notification[]>([]);
    const [unreadCount, setUnreadCount] = useState(0);
    const [loading, setLoading] = useState(true);

    const isFetchingRef = useRef(false);

    const fetchNotifications = async () => {
        if (!user || isFetchingRef.current) return;
        isFetchingRef.current = true;

        try {
            const { data, error } = await (supabase as any)
                .from("notification_recipients")
                .select(`
            id,
            is_read,
            created_at,
            notifications (
            id,
            title,
            message,
            type,
            link,
            metadata
            )
        `)
                .eq("user_id", user.id)
                .eq("is_deleted", false)
                .order("created_at", { ascending: false });

            if (error && error.name !== 'AbortError') {
                console.error("Error fetching notifications:", error);
                return;
            }

            const formatted: Notification[] = (data || [])
                .filter((item: any) => item.notifications !== null)
                .map((item: any) => ({
                    id: item.notifications.id,
                    recipient_id: item.id,
                    title: item.notifications.title,
                    message: item.notifications.message,
                    type: item.notifications.type,
                    link: item.notifications.link,
                    is_read: item.is_read,
                    created_at: item.created_at,
                    metadata: item.notifications.metadata,
                }));

            setNotifications(formatted);
            setUnreadCount(formatted.filter((n) => !n.is_read).length);
        } finally {
            setLoading(false);
            setTimeout(() => { isFetchingRef.current = false; }, 1000);
        }
    };

    useEffect(() => {
        fetchNotifications();

        if (!user) return;

        // Realtime subscription
        const channel = (supabase as any)
            .channel("public:notification_recipients")
            .on(
                "postgres_changes",
                {
                    event: "*",
                    schema: "public",
                    table: "notification_recipients",
                    filter: `user_id=eq.${user.id}`,
                },
                () => {
                    fetchNotifications();
                }
            )
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    }, [user]);

    const markAsRead = async (recipientId: string) => {
        const { error } = await (supabase as any)
            .from("notification_recipients")
            .update({ is_read: true, read_at: new Date().toISOString() })
            .eq("id", recipientId);

        if (error) console.error("Error marking notification as read:", error);
        else fetchNotifications();
    };

    const markAllAsRead = async () => {
        if (!user) return;
        const { error } = await (supabase as any)
            .from("notification_recipients")
            .update({ is_read: true, read_at: new Date().toISOString() })
            .eq("user_id", user.id)
            .eq("is_read", false);

        if (error) console.error("Error marking all notifications as read:", error);
        else fetchNotifications();
    };

    const deleteNotification = async (recipientId: string) => {
        const { error } = await (supabase as any)
            .from("notification_recipients")
            .update({ is_deleted: true })
            .eq("id", recipientId);

        if (error) console.error("Error deleting notification:", error);
        else fetchNotifications();
    };

    return {
        notifications,
        unreadCount,
        loading,
        markAsRead,
        markAllAsRead,
        deleteNotification,
        refresh: fetchNotifications,
    };
};

import { supabase } from "@/integrations/supabase/client";

export type AuditAction = 'VIEW' | 'CREATE' | 'EDIT' | 'DELETE' | 'LOGIN' | 'DOWNLOAD';

export const logAction = async (
    userId: string | undefined,
    action: AuditAction,
    tableName: string,
    recordId: string,
    oldData: any = null,
    newData: any = null
) => {
    if (!userId) return;

    try {
        const { error } = await supabase.from('audit_logs' as any).insert([
            {
                user_id: userId,
                action,
                table_name: tableName,
                record_id: recordId,
                old_data: oldData,
                new_data: newData,
            },
        ]);

        if (error) {
            console.error('AuditLog Error:', error.message);
        }
    } catch (err) {
        console.error('AuditLog critical error:', err);
    }
};

import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

/**
 * Utility to sync all active companies from the 'empresas' table
 * to the 'auth.users' and 'profiles' tables as client users.
 */
export const syncCompanyClients = async (onProgress?: (current: number, total: number) => void) => {
    try {
        // 1. Fetch all companies
        const { data: companies, error: empError } = await supabase
            .from("empresas")
            .select("id, nome_empresa, cnpj");

        if (empError) throw empError;
        if (!companies) return;

        const { data: { session } } = await supabase.auth.getSession();
        if (!session?.access_token) throw new Error("Não autenticado");

        let synced = 0;
        let errors = 0;

        for (let i = 0; i < companies.length; i++) {
            const company = companies[i];
            if (onProgress) onProgress(i + 1, companies.length);

            if (!company.cnpj) continue;

            const cleanCNPJ = company.cnpj.replace(/\D/g, "");
            if (!cleanCNPJ) continue;

            const email = `${cleanCNPJ}@audipreve.com`;
            const password = cleanCNPJ; // Default password is CNPJ

            try {
                const { error } = await supabase.functions.invoke("create-user", {
                    body: {
                        email,
                        nome: company.nome_empresa,
                        password,
                        role: 'client',
                        empresa_id: company.id
                    }
                });

                if (error) {
                    console.error(`Error invoking function for ${company.nome_empresa}:`, error);
                    let msg = error.message;
                    try {
                        const body = await (error as any).context?.json();
                        if (body?.code === "user_already_exists") {
                            synced++; // Consider it as success/synced
                            continue;
                        }
                        if (body?.error) msg = body.error;
                    } catch (e) { }
                    console.error(`Detail for ${company.nome_empresa}: ${msg}`);
                    errors++;
                } else {
                    synced++;
                }
            } catch (err) {
                console.error(`Fatal error syncing ${company.nome_empresa}:`, err);
                errors++;
            }
        }

        return { synced, errors, total: companies.length };
    } catch (error) {
        console.error("Error syncing clients:", error);
        throw error;
    }
};

import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { useNavigate } from "react-router-dom";
import { Calendar, Clock, User, Save, ArrowLeft, ClipboardList } from "lucide-react";
