  const [usuarios, setUsuarios] = useState<Usuario[]>([]);
  const [loadingUsers, setLoadingUsers] = useState(true);
  const [activeTab, setActiveTab] = useState<'interna' | 'cliente'>('interna');

  const loadUsers = async () => {
    try {
      setLoadingUsers(true);
      console.log("[ConfiguracoesPage] Iniciando carregamento de usuários...");
      const { data: profiles, error: profilesError } = await supabase.from("profiles").select("*");
      console.log("[ConfiguracoesPage] Profiles retornados:", profiles?.length, "Erro:", profilesError);
      if (profilesError) {
        console.error("Erro ao carregar perfis:", profilesError);
        return;
      }
      if (!profiles || profiles.length === 0) {
        console.warn("[ConfiguracoesPage] Nenhum perfil encontrado na tabela profiles");
        return;
      }

      const userIds = profiles.map(p => p.user_id);

      const { data: roles } = await supabase.from("user_roles").select("user_id, role").in("user_id", userIds);
      const { data: perms } = await supabase.from("user_module_permissions").select("user_id, module_name").in("user_id", userIds);
      const { data: access } = await supabase.from("empresa_acessos").select("user_id, empresa_id").in("user_id", userIds);

      const rolesByUserId = roles?.reduce((acc: any, curr: any) => {
        if (!acc[curr.user_id]) acc[curr.user_id] = [];
        acc[curr.user_id].push(curr.role);
        return acc;
      }, {}) || {};

      const permsByUserId = perms?.reduce((acc: any, curr: any) => {
        if (!acc[curr.user_id]) acc[curr.user_id] = [];
        acc[curr.user_id].push(curr.module_name);
        return acc;
      }, {}) || {};

      const accessByUserId = access?.reduce((acc: any, curr: any) => {
        acc[curr.user_id] = true;
        return acc;
      }, {}) || {};

      const users: Usuario[] = [];
      for (const p of profiles) {
        const userRoles = rolesByUserId[p.user_id] || [];
        const userPerms = permsByUserId[p.user_id] || [];

        const modules: Record<string, boolean> = {};
        userPerms.forEach((m: string) => { modules[m] = true; });

        // A user is a client if they have the 'client' role OR if they have enterprise accesses
        const isClient = userRoles.includes('client') || accessByUserId[p.user_id] === true;
        const isAdmin = userRoles.includes('admin');

        users.push({
          id: p.user_id,
          nome: p.nome_completo || "Sem nome",
          email: "",
          isAdmin,
          isClient,
          departamento: "",
          modules,
        });
      }
      console.log("[ConfiguracoesPage] Usuários carregados:", users.length, users.map(u => u.nome));
      setUsuarios(users);
    } catch (err) {
      console.error("Erro ao carregar usuários:", err);
    } finally {
      setLoadingUsers(false);
    }
  };

  useEffect(() => { loadUsers(); }, []);

  // Aguardar userData carregar antes de decidir redirect
  if (!userData) return null;
  if (!userData.isAdmin) return <Navigate to="/dashboard" replace />;

  const toggleModule = async (userId: string, module: string, current: boolean) => {
    try {
      const res = await supabase.functions.invoke("manage-user", {
        body: { action: "toggleModule", target_user_id: userId, module, enable: !current }
      });
      if (res.error) throw res.error;
      toast.success(`${moduleLabels[module]} ${!current ? "habilitado" : "desabilitado"}`);
      loadUsers();
    } catch (err: any) {
      console.error("Erro no toggleModule:", err);
      toast.error("Erro ao alterar módulo: " + (err.message || "Falha na requisição"));
    }
  };

  const toggleAdmin = async (userId: string, current: boolean) => {
    try {
      const res = await supabase.functions.invoke("manage-user", {
        body: { action: "toggleAdmin", target_user_id: userId, enable: !current }
      });
      if (res.error) throw res.error;
      toast.success(!current ? "Promovido a admin" : "Removido de admin");
      loadUsers();
    } catch (err: any) {
      console.error("Erro no toggleAdmin:", err);
      toast.error("Erro ao alterar permissão de admin: " + (err.message || "Falha na requisição"));
    }
  };

  const handleDelete = async (userId: string) => {
    if (!window.confirm("Excluir este usuário do sistema?")) return;
    try {
      const res = await supabase.functions.invoke("manage-user", {
        body: { action: "deleteUser", target_user_id: userId }
      });
      if (res.error) throw res.error;
      toast.success("Usuário removido!");
      loadUsers();
    } catch (err: any) {
      console.error("Erro no handleDelete:", err);
      toast.error("Erro ao excluir usuário: " + (err.message || "Falha na requisição"));
    }
  };

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex items-center justify-between">
        <h3 className="text-lg font-bold text-card-foreground">Gerenciamento de Usuários</h3>
        <button onClick={() => navigate("/configuracoes/usuarios/novo")} className="flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold text-primary-foreground shadow-md" style={{ background: "var(--gradient-primary)" }}>
          <Plus size={16} /> Novo Usuário
        </button>
      </div>

      <div className="flex border-b border-border mb-6">
        <button
          onClick={() => setActiveTab('interna')}
          className={`flex items-center gap-2 px-6 py-3 border-b-2 font-medium transition-colors ${activeTab === 'interna' ? 'border-primary text-primary' : 'border-transparent text-muted-foreground hover:text-foreground'}`}
        >
          <Users size={18} /> Equipe Interna
        </button>
        <button
          onClick={() => setActiveTab('cliente')}
          className={`flex items-center gap-2 px-6 py-3 border-b-2 font-medium transition-colors ${activeTab === 'cliente' ? 'border-primary text-primary' : 'border-transparent text-muted-foreground hover:text-foreground'}`}
        >
          <Building size={18} /> Portal Cliente
        </button>
      </div>

      <div className="space-y-4">
        {usuarios.filter(u => activeTab === 'interna' ? !u.isClient : u.isClient).map(u => (
          <div key={u.id} className="module-card">
            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-full bg-primary flex items-center justify-center">
                  <span className="text-primary-foreground text-sm font-bold">{(u.nome || "U").slice(0, 2).toUpperCase()}</span>
                </div>
                <div>
                  <p className="font-semibold text-card-foreground">{u.nome || "Sem nome"}</p>
                  <p className="text-xs text-muted-foreground">{u.email} {u.departamento ? `• ${u.departamento}` : ""}</p>
                </div>
              </div>
              <div className="flex items-center gap-2">
                <button onClick={() => toggleAdmin(u.id, u.isAdmin)} className={`p-2 rounded-lg transition-colors ${u.isAdmin ? "bg-primary/10 text-primary" : "bg-muted text-muted-foreground hover:text-primary"}`} title={u.isAdmin ? "Remover admin" : "Tornar admin"}>
                  {u.isAdmin ? <Shield size={16} /> : <ShieldOff size={16} />}
                </button>
                <button onClick={() => handleDelete(u.id)} className="p-2 rounded-lg hover:bg-destructive/10 text-muted-foreground hover:text-destructive"><Trash2 size={16} /></button>
              </div>
            </div>
            {activeTab === 'interna' && (
              <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-5 gap-2 mt-4 pt-4 border-t border-border">
                {Object.entries(moduleLabels).map(([key, label]) => (
                  <button
                    key={key}
                    onClick={() => toggleModule(u.id, key, u.modules?.[key] || false)}
                    className={`px-3 py-2 rounded-lg text-xs font-medium transition-all border ${u.isAdmin || u.modules?.[key]
                      ? "border-success/30 bg-success/5 text-success"
                      : "border-border bg-muted/30 text-muted-foreground hover:border-primary/30"
                      }`}
                  >
                    {label}
                  </button>
                ))}
              </div>
            )}
          </div>
        ))}
        {loadingUsers ? (
          <div className="module-card text-center py-8">
            <p className="text-muted-foreground">Carregando usuários...</p>
          </div>
        ) : usuarios.filter(u => activeTab === 'interna' ? !u.isClient : u.isClient).length === 0 ? (
          <div className="module-card text-center py-8">
            <p className="text-muted-foreground">Nenhum usuário cadastrado</p>
          </div>
        ) : null}
      </div>

      <div className="space-y-6 pt-6 border-t border-border">
        <h3 className="text-lg font-bold text-card-foreground">Configurações de Notificações</h3>
        <NotificationConfig />
      </div>
    </div>
  );
};

const NotificationConfig: React.FC = () => {
  const [types, setTypes] = useState<any[]>([]);

  const loadData = async () => {
    const { data: nTypes } = await (supabase as any).from("notification_types").select("*");
    setTypes(nTypes || []);
  };

  useEffect(() => { loadData(); }, []);

  const toggleType = async (id: string, current: boolean) => {
    await (supabase as any).from("notification_types").update({ is_enabled: !current }).eq("id", id);
    toast.success("Configuração atualizada");
    loadData();
  };

  return (
    <div className="module-card">
      <h4 className="font-semibold text-sm mb-4">Gatilhos de Notificação</h4>
      <div className="space-y-3">
        {types.map(t => (
          <div key={t.id} className="flex items-center justify-between p-3 bg-muted/30 rounded-lg border border-border">
            <div>
              <p className="text-sm font-medium">{t.label}</p>
              <p className="text-xs text-muted-foreground">{t.description}</p>
            </div>
            <button
              onClick={() => toggleType(t.id, t.is_enabled)}
              className={`w-12 h-6 rounded-full transition-colors relative ${t.is_enabled ? "bg-primary" : "bg-muted-foreground/30"}`}
            >
              <div className={`absolute top-1 w-4 h-4 rounded-full bg-white transition-all ${t.is_enabled ? "left-7" : "left-1"}`} />
            </button>
          </div>
        ))}
      </div>
    </div>
  );
};

export default ConfiguracoesPage;

import React, { useEffect, useState } from "react";
import { useAuth } from "@/contexts/AuthContext";
import { supabase } from "@/integrations/supabase/client";
import { Building2, Clock, AlertTriangle, Award } from "lucide-react";
import { TableSkeleton, PageHeaderSkeleton } from "@/components/PageSkeleton";

const DashboardPage: React.FC = () => {
  const { userData } = useAuth();
  const [stats, setStats] = useState({ total: 0, ativas: 0, paralisadas: 0, baixadas: 0 });
  const [empresas, setEmpresas] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let mounted = true;

    const load = async () => {
      setLoading(true);
      // 1. Get recent companies
      const { data: recents } = await supabase.from("empresas").select("id, nome_empresa, cnpj, situacao").order("created_at", { ascending: false }).limit(10);
      if (mounted) setEmpresas(recents || []);

      // 2. Get all statuses
      const { data: allStatuses } = await supabase.from("empresas").select("situacao");
      if (allStatuses && mounted) {
        let ativas = 0;
        let paralisadas = 0;
        let baixadas = 0;
        allStatuses.forEach(emp => {
          if (!emp.situacao || emp.situacao === 'ativa') ativas++;
          else if (emp.situacao === 'paralisada') paralisadas++;
          else if (emp.situacao === 'baixada') baixadas++;
        });
        setStats({ total: allStatuses.length, ativas, paralisadas, baixadas });
      }
      if (mounted) setLoading(false);
    };
    load();

    return () => { mounted = false; };
  }, []);

  const statCards = [
    { label: "Total de Empresas", value: stats.total, icon: <Building2 size={22} />, color: "bg-primary/10 text-primary" },
    { label: "Empresas Ativas", value: stats.ativas, icon: <Award size={22} />, color: "bg-success/10 text-success" },
    { label: "Paralisadas", value: stats.paralisadas, icon: <Clock size={22} />, color: "bg-warning/10 text-warning" },
    { label: "Baixadas", value: stats.baixadas, icon: <AlertTriangle size={22} />, color: "bg-destructive/10 text-destructive" },
  ];

  return (
    <div className="space-y-6 animate-fade-in">
      {loading ? (
        <div className="space-y-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
            {[1, 2, 3, 4].map(i => <div key={i} className="stat-card h-24 animate-pulse bg-muted" />)}
          </div>
          <TableSkeleton rows={5} />
        </div>
      ) : (
        <>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
            {statCards.map((card) => (
              <div key={card.label} className="stat-card"><div className="flex items-center justify-between"><div><p className="text-sm text-muted-foreground font-medium">{card.label}</p><h3 className="text-2xl font-bold text-card-foreground mt-1">{card.value}</h3></div><div className={`w-12 h-12 rounded-xl flex items-center justify-center ${card.color}`}>{card.icon}</div></div></div>
            ))}
          </div>
          <div className="module-card">
            <h3 className="text-lg font-bold text-card-foreground mb-4">Empresas Recentes</h3>
            {empresas.length === 0 ? <p className="text-muted-foreground text-sm py-8 text-center">Nenhuma empresa cadastrada</p> : (
              <div className="overflow-x-auto"><table className="data-table"><thead><tr><th>Empresa</th><th>CNPJ</th><th>Status</th></tr></thead><tbody>{empresas.map((emp) => (
                <tr key={emp.id}><td className="font-medium text-card-foreground">{emp.nome_empresa || "—"}</td><td className="text-muted-foreground">{emp.cnpj || "—"}</td><td><span className={`badge-status ${emp.situacao === "baixada" ? "badge-danger" : emp.situacao === "paralisada" ? "badge-warning" : "badge-success"}`}>{emp.situacao || "Ativa"}</span></td></tr>
              ))}</tbody></table></div>
            )}
          </div>
        </>
      )}
    </div>
  );
};

export default DashboardPage;

import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import {
    ClipboardList, Search, Calendar, CheckCircle,
    Circle, Save, Filter, Users, Building2,
    AlertCircle, Info
} from "lucide-react";
import { toast } from "sonner";

interface Empresa {
    id: string;
    nome_empresa: string;
    cnpj: string | null;
    regime_tributario: string | null;
    porte_empresa: string | null;
    situacao: string | null;
}

interface Socio {
    id: string;
    nome: string;
    cpf: string | null;
    empresa_id: string;
    empresa_nome?: string;
}

interface DeclaracaoAnual {
    id?: string;
    empresa_id: string;
    ano: number;
    tipo_declaracao: string;
    obrigatorio: boolean;
    enviada: boolean;
    data_envio: string | null;
}

interface DeclaracaoIRPF {
    id?: string;
    socio_id: string;
    ano: number;
    faz_pelo_escritorio: boolean;
    transmitida: boolean;
    data_transmissao: string | null;
    quem_transmitiu: string | null;
}

const DeclaracoesAnuaisPage: React.FC = () => {
    const [empresas, setEmpresas] = useState<Empresa[]>([]);
    const [socios, setSocios] = useState<Socio[]>([]);
    const [declaracoes, setDeclaracoes] = useState<Record<string, DeclaracaoAnual>>({});
    const [declaracoesIRPF, setDeclaracoesIRPF] = useState<Record<string, DeclaracaoIRPF>>({});
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [search, setSearch] = useState("");
    const [ano, setAno] = useState(new Date().getFullYear());
    const [activeTab, setActiveTab] = useState<"defis" | "ecd_ecf" | "dasn_simei" | "dirf" | "irpf">("defis");

    const prazos: Record<string, string> = {
        defis: "31/03",
        ecd_ecf: "31/07",
        dasn_simei: "31/05",
        dirf: "27/02",
        irpf: "31/05"
    };

    const loadData = async () => {
        setLoading(true);
        try {
            const { data: emps } = await supabase.from("empresas").select("*").order("nome_empresa");
            setEmpresas(emps || []);

            const { data: socs } = await supabase.from("socios").select("*, empresas(nome_empresa)");
            setSocios((socs || []).map((s: any) => ({
                ...s,
                empresa_nome: s.empresas?.nome_empresa
            })));

            const { data: decls } = await (supabase.from("declaracoes_anuais" as any) as any).select("*").eq("ano", ano);
            const declMap: Record<string, DeclaracaoAnual> = {};
            (decls as any[])?.forEach(d => {
                declMap[`${d.empresa_id}_${d.tipo_declaracao}`] = d;
            });
            setDeclaracoes(declMap);

            const { data: irpfs } = await (supabase.from("declaracoes_irpf" as any) as any).select("*").eq("ano", ano);
            const irpfMap: Record<string, DeclaracaoIRPF> = {};
            (irpfs as any[])?.forEach(i => {
                irpfMap[i.socio_id] = i;
            });
            setDeclaracoesIRPF(irpfMap);
        } catch (err: any) {
            toast.error("Erro ao carregar dados: " + err.message);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadData();
    }, [ano]);

    const handleToggleObrigatorio = (empresaId: string, tipo: string) => {
        const key = `${empresaId}_${tipo}`;
        const current = declaracoes[key] || {
            empresa_id: empresaId,
            ano,
            tipo_declaracao: tipo,
            obrigatorio: false,
            enviada: false,
            data_envio: null
        };

        setDeclaracoes(prev => ({
            ...prev,
            [key]: { ...current, obrigatorio: !current.obrigatorio }
        }));
    };

    const handleToggleEnviada = (empresaId: string, tipo: string) => {
        const key = `${empresaId}_${tipo}`;
        const current = declaracoes[key] || {
            empresa_id: empresaId,
            ano,
            tipo_declaracao: tipo,
            obrigatorio: true,
            enviada: false,
            data_envio: null
        };

        setDeclaracoes(prev => ({
            ...prev,
            [key]: {
                ...current,
                enviada: !current.enviada,
                data_envio: !current.enviada ? new Date().toISOString().split('T')[0] : null
            }
        }));
    };

    const updateDeclaracao = (empresaId: string, tipo: string, field: string, value: any) => {
        const key = `${empresaId}_${tipo}`;
        const current = declaracoes[key] || {
            empresa_id: empresaId,
            ano,
            tipo_declaracao: tipo,
            obrigatorio: true,
            enviada: false,
            data_envio: null
        };

        setDeclaracoes(prev => ({
            ...prev,
            [key]: { ...current, [field]: value }
        }));
    };

    const saveDeclaracao = async (empresaId: string, tipo: string) => {
        setSaving(true);
        const key = `${empresaId}_${tipo}`;
        const data = declaracoes[key];
        if (!data) return;

        try {
            if (data.id) {
                await (supabase.from("declaracoes_anuais" as any) as any).update({
                    obrigatorio: data.obrigatorio,
                    enviada: data.enviada,
                    data_envio: data.data_envio
                }).eq("id", data.id);
            } else {
                const { data: inserted } = await (supabase.from("declaracoes_anuais" as any) as any).insert(data).select().single();
                if (inserted) {
                    setDeclaracoes(prev => ({ ...prev, [key]: inserted as DeclaracaoAnual }));
                }
            }
            toast.success("Declaração salva!");
        } catch (err: any) {
            toast.error("Erro ao salvar: " + err.message);
        } finally {
            setSaving(false);
        }
    };

    // IRPF handlers
    const updateIRPF = (socioId: string, field: string, value: any) => {
        const current = declaracoesIRPF[socioId] || {
            socio_id: socioId,
            ano,
            faz_pelo_escritorio: false,
            transmitida: false,
            data_transmissao: null,
            quem_transmitiu: null
        };

        setDeclaracoesIRPF(prev => ({
            ...prev,
            [socioId]: { ...current, [field]: value }
        }));
    };

    const saveIRPF = async (socioId: string) => {
        setSaving(true);
        const data = declaracoesIRPF[socioId];
        if (!data) return;

        try {
            if (data.id) {
                await (supabase.from("declaracoes_irpf" as any) as any).update({
                    faz_pelo_escritorio: data.faz_pelo_escritorio,
                    transmitida: data.transmitida,
                    data_transmissao: data.data_transmissao,
                    quem_transmitiu: data.quem_transmitiu
                }).eq("id", data.id);
            } else {
                const { data: inserted } = await (supabase.from("declaracoes_irpf" as any) as any).insert(data).select().single();
                if (inserted) {
                    setDeclaracoesIRPF(prev => ({ ...prev, [socioId]: inserted as DeclaracaoIRPF }));
                }
            }
            toast.success("IRPF salvo!");
        } catch (err: any) {
            toast.error("Erro ao salvar IRPF: " + err.message);
        } finally {
            setSaving(false);
        }
    };

    const filterCompanies = () => {
        return empresas.filter(e => {
            const matchSearch = e.nome_empresa?.toLowerCase().includes(search.toLowerCase()) || e.cnpj?.includes(search);

            let matchTab = false;
            if (activeTab === "defis") {
                matchTab = e.regime_tributario === "simples";
            } else if (activeTab === "ecd_ecf") {
                matchTab = e.regime_tributario === "lucro_presumido" || e.regime_tributario === "lucro_real";
            } else if (activeTab === "dasn_simei") {
                matchTab = e.porte_empresa === "mei";
            } else if (activeTab === "dirf") {
                matchTab = e.porte_empresa !== "mei";
            } else {
                matchTab = true; // For IRPF we list socios
            }

            // Check for manual override (obrigatorio)
            const key = `${e.id}_${activeTab}`;
            const decl = declaracoes[key];
            if (decl?.obrigatorio) matchTab = true;

            return matchSearch && matchTab;
        });
    };

    const filterSocios = () => {
        return socios.filter(s =>
            s.nome.toLowerCase().includes(search.toLowerCase()) ||
            (s.cpf && s.cpf.includes(search)) ||
            (s.empresa_nome && s.empresa_nome.toLowerCase().includes(search.toLowerCase()))
        );
    };

    if (loading) {
        return <div className="flex items-center justify-center h-64"><div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>;
    }

    const filteredItems = activeTab === "irpf" ? filterSocios() : filterCompanies();

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="flex flex-col sm:flex-row items-start sm:items-center justify-end gap-4">
                <div className="flex items-center gap-3">
                    <span className="text-sm font-medium text-muted-foreground uppercase">Ano Base:</span>
                    <select
                        value={ano}
                        onChange={e => setAno(parseInt(e.target.value))}
                        className="px-4 py-2 border border-border rounded-xl bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none font-bold shadow-sm"
                    >
                        {[...Array(10)].map((_, i) => {
                            const year = new Date().getFullYear() - 5 + i;
                            return <option key={year} value={year}>{year}</option>;
                        })}
                    </select>
                </div>
            </div>

            <div className="module-card">
                <div className="flex flex-col sm:flex-row gap-4 items-center mb-6">
                    <div className="relative flex-1 w-full">
                        <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
                        <input
                            type="text"
                            placeholder={activeTab === "irpf" ? "Buscar por nome, CPF ou empresa..." : "Buscar por nome ou CNPJ..."}
                            value={search}
                            onChange={e => setSearch(e.target.value)}
                            className="w-full pl-9 pr-4 py-2.5 border border-border rounded-xl bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none"
                        />
                    </div>
                    <div className="flex items-center gap-2 bg-muted/30 p-1 rounded-xl border border-border w-full sm:w-auto overflow-x-auto no-scrollbar">
                        {[
                            { id: "defis", label: "DEFIS" },
                            { id: "ecd_ecf", label: "ECD/ECF" },
                            { id: "dasn_simei", label: "DASN-SIMEI" },
                            { id: "dirf", label: "DIRF" },
                            { id: "irpf", label: "IRPF" }
                        ].map(tab => (
                            <button
                                key={tab.id}
                                onClick={() => setActiveTab(tab.id as any)}
                                className={`px-4 py-2 rounded-lg text-xs font-semibold whitespace-nowrap transition-all ${activeTab === tab.id ? "bg-card text-primary shadow-sm" : "text-muted-foreground hover:text-foreground"}`}
                            >
                                {tab.label}
                            </button>
                        ))}
                    </div>
                </div>

                <div className="bg-info/10 border border-info/20 rounded-xl p-4 mb-6 flex gap-3 items-start">
                    <Info size={18} className="text-info mt-0.5 flex-shrink-0" />
                    <div className="text-sm text-info">
                        <p className="font-semibold">Obrigação para {prazos[activeTab]}</p>
                    </div>
                </div>

                <div className="space-y-3">
                    {activeTab !== "irpf" ? (
                        // Empresas List
                        (filteredItems as Empresa[]).map(emp => {
                            const key = `${emp.id}_${activeTab}`;
                            // Lógica de obrigatoriedade automática
                            const isAutoObligatory =
                                (activeTab === "defis" && emp.regime_tributario === "simples") ||
                                (activeTab === "ecd_ecf" && (emp.regime_tributario === "lucro_presumido" || emp.regime_tributario === "lucro_real")) ||
                                (activeTab === "dasn_simei" && emp.porte_empresa === "mei") ||
                                (activeTab === "dirf" && emp.porte_empresa !== "mei");

                            const decl = declaracoes[key] || {
                                empresa_id: emp.id,
                                ano,
                                tipo_declaracao: activeTab,
                                obrigatorio: isAutoObligatory,
                                enviada: false,
                                data_envio: null
                            };

                            return (
                                <div key={emp.id} className="p-4 bg-card border border-border rounded-xl hover:shadow-md transition-shadow">
                                    <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4">
                                        <div className="flex items-center gap-3">
                                            <div className={`w-10 h-10 rounded-full flex items-center justify-center ${decl.obrigatorio ? "bg-primary/10 text-primary" : "bg-muted text-muted-foreground"}`}>
                                                <Building2 size={20} />
                                            </div>
                                            <div>
                                                <p className="font-bold text-card-foreground">{emp.nome_empresa}</p>
                                                <p className="text-xs text-muted-foreground flex items-center gap-2">
                                                    {emp.cnpj || "—"} •
                                                    <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase ${decl.obrigatorio ? "bg-info/20 text-info" : "bg-muted text-muted-foreground"}`}>
                                                        {decl.obrigatorio ? "Obrigatória" : "Não Obrigatória"}
                                                    </span>
                                                </p>
                                            </div>
                                        </div>

                                        <div className="grid grid-cols-1 sm:grid-cols-4 items-center gap-4">
                                            {/* Obrigação Manual */}
                                            <label className="flex items-center gap-2 cursor-pointer">
                                                <input
                                                    type="checkbox"
                                                    checked={decl.obrigatorio}
                                                    onChange={() => handleToggleObrigatorio(emp.id, activeTab)}
                                                    className="w-4 h-4 rounded border-border text-primary focus:ring-primary"
                                                />
                                                <span className="text-sm font-medium">Obrigatória</span>
                                            </label>

                                            {/* Enviada */}
                                            <label className={`flex items-center gap-2 cursor-pointer ${!decl.obrigatorio ? "opacity-30 pointer-events-none" : ""}`}>
                                                <input
                                                    type="checkbox"
                                                    disabled={!decl.obrigatorio}
                                                    checked={decl.enviada}
                                                    onChange={() => handleToggleEnviada(emp.id, activeTab)}
                                                    className="w-4 h-4 rounded border-border text-success focus:ring-success"
                                                />
                                                <span className="text-sm font-medium">Enviada</span>
                                            </label>

                                            {/* Data de Envio */}
                                            <div className={!decl.obrigatorio ? "opacity-30 pointer-events-none" : ""}>
                                                <input
                                                    type="date"
                                                    disabled={!decl.obrigatorio}
                                                    value={decl.data_envio || ""}
                                                    onChange={e => updateDeclaracao(emp.id, activeTab, "data_envio", e.target.value)}
                                                    className="w-full px-2 py-1.5 border border-border rounded-lg bg-background text-xs"
                                                />
                                            </div>

                                            {/* Botão Salvar */}
                                            <button
                                                onClick={() => saveDeclaracao(emp.id, activeTab)}
                                                disabled={saving}
                                                className="flex items-center justify-center gap-2 px-4 py-2 rounded-lg bg-primary text-primary-foreground text-xs font-bold hover:bg-primary/90 transition-colors disabled:opacity-50"
                                            >
                                                <Save size={14} /> Salvar
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            );
                        })
                    ) : (
                        // IRPF List
                        (filteredItems as Socio[]).map(socio => {
                            const decl = declaracoesIRPF[socio.id] || {
                                socio_id: socio.id,
                                ano,
                                faz_pelo_escritorio: false,
                                transmitida: false,
                                data_transmissao: null,
                                quem_transmitiu: null
                            };

                            return (
                                <div key={socio.id} className="p-4 bg-card border border-border rounded-xl hover:shadow-md transition-shadow">
                                    <div className="flex flex-col xl:flex-row xl:items-center justify-between gap-4">
                                        <div className="flex items-center gap-3">
                                            <div className="w-10 h-10 rounded-full bg-warning/10 text-warning flex items-center justify-center">
                                                <Users size={20} />
                                            </div>
                                            <div>
                                                <p className="font-bold text-card-foreground">{socio.nome}</p>
                                                <p className="text-xs text-muted-foreground">
                                                    CPF: {socio.cpf || "—"} • Empresa: {socio.empresa_nome || "—"}
                                                </p>
                                            </div>
                                        </div>

                                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 items-center gap-3">
                                            {/* Pelo Escritório */}
                                            <label className="flex items-center gap-2 cursor-pointer">
                                                <input
                                                    type="checkbox"
                                                    checked={decl.faz_pelo_escritorio}
                                                    onChange={e => updateIRPF(socio.id, "faz_pelo_escritorio", e.target.checked)}
                                                    className="w-4 h-4 rounded border-border text-primary focus:ring-primary"
                                                />
                                                <span className="text-xs font-medium">Pelo Escritório?</span>
                                            </label>

                                            {/* Transmitida */}
                                            <label className="flex items-center gap-2 cursor-pointer">
                                                <input
                                                    type="checkbox"
                                                    checked={decl.transmitida}
                                                    onChange={e => updateIRPF(socio.id, "transmitida", e.target.checked)}
                                                    className="w-4 h-4 rounded border-border text-success focus:ring-success"
                                                />
                                                <span className="text-xs font-medium">Transmitida?</span>
                                            </label>

                                            {/* Data Transmissão */}
                                            <div>
                                                <input
                                                    type="date"
                                                    value={decl.data_transmissao || ""}
                                                    onChange={e => updateIRPF(socio.id, "data_transmissao", e.target.value)}
                                                    className="w-full px-2 py-1.5 border border-border rounded-lg bg-background text-xs"
                                                />
                                            </div>

                                            {/* Quem Transmitiu */}
                                            <div>
                                                <input
                                                    type="text"
                                                    placeholder="Quem transmitiu?"
                                                    value={decl.quem_transmitiu || ""}
                                                    onChange={e => updateIRPF(socio.id, "quem_transmitiu", e.target.value)}
                                                    className="w-full px-2 py-1.5 border border-border rounded-lg bg-background text-xs"
                                                />
                                            </div>

                                            {/* Botão Salvar */}
                                            <button
                                                onClick={() => saveIRPF(socio.id)}
                                                disabled={saving}
                                                className="flex items-center justify-center gap-2 px-4 py-2 rounded-lg bg-primary text-primary-foreground text-xs font-bold hover:bg-primary/90 transition-colors disabled:opacity-50"
                                            >
                                                <Save size={14} /> Salvar
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            );
                        })
                    )}

                    {filteredItems.length === 0 && (
                        <div className="text-center py-12 bg-muted/20 rounded-xl border border-dashed border-border">
                            <ClipboardList size={40} className="mx-auto text-muted-foreground/30 mb-3" />
                            <p className="text-muted-foreground font-medium">Nenhum registro encontrado para esta categoria.</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default DeclaracoesAnuaisPage;

import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Search, Save, CheckCircle, Circle } from "lucide-react";
import { toast } from "sonner";
import { useEmpresas } from "@/hooks/useEmpresas";

const DeclaracoesMensaisPage: React.FC = () => {
    // We use "pessoal" here to ensure the user has access to edit this, 
    // or we could use a new module permission if declared.
    const { empresas, loading } = useEmpresas("declaracoes_mensais");
    const [pessoalData, setPessoalData] = useState<Record<string, any>>({});
    const [search, setSearch] = useState("");
    const [competencia, setCompetencia] = useState(new Date().toISOString().slice(0, 7));
    const [editForm, setEditForm] = useState<Record<string, any>>({});
    const [isSaving, setIsSaving] = useState(false);
    const [activeTab, setActiveTab] = useState<"ativas" | "mei" | "paralisadas" | "baixadas">("ativas");

    useEffect(() => {
        const load = async () => {
            const { data } = await supabase.from("pessoal").select("*").eq("competencia", competencia);
            const map: Record<string, any> = {};
            const formMap: Record<string, any> = {};

            data?.forEach(p => {
                map[p.empresa_id] = p;
                formMap[p.empresa_id] = {
                    dctf_web_gerada: p.dctf_web_gerada || false,
                    dctf_web_data_envio: (p as any).dctf_web_data_envio || ""
                };
            });

            setPessoalData(map);
            setEditForm(formMap);
        };
        load();
    }, [competencia]);

    const filtered = empresas.filter(e => {
        const matchSearch = e.nome_empresa?.toLowerCase().includes(search.toLowerCase()) || e.cnpj?.includes(search);

        let matchTab = false;
        if (activeTab === "ativas") {
            matchTab = (!e.situacao || e.situacao === "ativa") && e.porte_empresa !== "mei";
        } else if (activeTab === "mei") {
            matchTab = (!e.situacao || e.situacao === "ativa") && e.porte_empresa === "mei";
        } else if (activeTab === "paralisadas") {
            matchTab = e.situacao === "paralisada";
        } else if (activeTab === "baixadas") {
            matchTab = e.situacao === "baixada";
        }

        return matchSearch && matchTab;
    });

    const updateForm = (empresaId: string, field: string, value: any) => {
        setEditForm(prev => ({
            ...prev,
            [empresaId]: {
                ...prev[empresaId],
                [field]: value
            }
        }));
    };

    const handleSave = async (empresaId: string) => {
        const form = editForm[empresaId] || {};
        const existing = pessoalData[empresaId];
        setIsSaving(true);

        try {
            const payload = {
                empresa_id: empresaId,
                competencia,
                dctf_web_gerada: form.dctf_web_gerada || false,
                dctf_web_data_envio: form.dctf_web_data_envio || null
            };

            if (existing?.id) {
                // Update only the specific fields so we don't overwrite other data from Pessoal
                await supabase.from("pessoal").update({
                    dctf_web_gerada: payload.dctf_web_gerada,
                    dctf_web_data_envio: payload.dctf_web_data_envio
                }).eq("id", existing.id);
            } else {
                // Note: Creating a new record here works, but leaves other Pessoal fields null.
                // This is fine since they default to null/false/0 in the DB.
                await supabase.from("pessoal").insert(payload);
            }

            toast.success("Dados salvos com sucesso!");

            // Reload this specific record
            const { data } = await supabase.from("pessoal").select("*").eq("empresa_id", empresaId).eq("competencia", competencia).single();
            if (data) {
                setPessoalData(prev => ({ ...prev, [empresaId]: data }));
            }
        } catch (err: any) {
            toast.error(err.message || "Erro ao salvar");
        } finally {
            setIsSaving(false);
        }
    };

    const inputCls = "w-full px-3 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none";
    const completedCount = filtered.filter(e => editForm[e.id]?.dctf_web_gerada).length;

    if (loading) {
        return <div className="flex items-center justify-center h-64"><div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>;
    }

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-card-foreground">Declarações Mensais</h1>
                    <p className="text-sm text-muted-foreground mt-1">Controle de declarações sincronizado com o Departamento Pessoal</p>
                </div>
                <input
                    type="month"
                    value={competencia}
                    onChange={e => setCompetencia(e.target.value)}
                    className="px-4 py-2.5 border border-border rounded-xl bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none font-semibold"
                />
            </div>

            <div className="grid grid-cols-3 gap-4">
                <div className="stat-card">
                    <p className="text-xs text-muted-foreground uppercase">Empresas Ativas</p>
                    <p className="text-2xl font-bold text-primary mt-1">{filtered.length}</p>
                </div>
                <div className="stat-card">
                    <p className="text-xs text-muted-foreground uppercase">Concluídas</p>
                    <p className="text-2xl font-bold text-success mt-1">{completedCount}</p>
                </div>
                <div className="stat-card">
                    <p className="text-xs text-muted-foreground uppercase">Pendentes</p>
                    <p className="text-2xl font-bold text-warning mt-1">{filtered.length - completedCount}</p>
                </div>
            </div>

            <div className="relative max-w-sm">
                <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
                <input
                    type="text"
                    placeholder="Buscar empresa por nome ou CNPJ..."
                    value={search}
                    onChange={e => setSearch(e.target.value)}
                    className="w-full pl-9 pr-4 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none"
                />
            </div>

            <div className="flex border-b border-border overflow-x-auto no-scrollbar">
                <button
                    className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "ativas"
                        ? "border-primary text-primary"
                        : "border-transparent text-muted-foreground hover:text-foreground"
                        }`}
                    onClick={() => setActiveTab("ativas")}
                >
                    Empresas Ativas
                </button>
                <button
                    className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "mei"
                        ? "border-primary text-primary"
                        : "border-transparent text-muted-foreground hover:text-foreground"
                        }`}
                    onClick={() => setActiveTab("mei")}
                >
                    Empresas MEI
                </button>
                <button
                    className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "paralisadas"
                        ? "border-primary text-primary"
                        : "border-transparent text-muted-foreground hover:text-foreground"
                        }`}
                    onClick={() => setActiveTab("paralisadas")}
                >
                    Empresas Paralisadas
                </button>
                <button
                    className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "baixadas"
                        ? "border-primary text-primary"
                        : "border-transparent text-muted-foreground hover:text-foreground"
                        }`}
                    onClick={() => setActiveTab("baixadas")}
                >
                    Empresas Baixadas
                </button>
            </div>

            <div className="bg-card border border-border rounded-xl overflow-hidden shadow-sm">
                <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left">
                        <thead className="text-xs text-muted-foreground uppercase bg-muted/50 border-b border-border">
                            <tr>
                                <th className="px-4 py-4 font-medium">Situação</th>
                                <th className="px-4 py-4 font-medium">Empresa</th>
                                <th className="px-4 py-4 font-medium">CNPJ</th>
                                <th className="px-4 py-4 font-medium">DCTF WEB</th>
                                <th className="px-4 py-4 font-medium">Data de Envio</th>
                                <th className="px-4 py-4 font-medium text-right">Ação</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-border">
                            {filtered.map((emp) => {
                                const form = editForm[emp.id] || {};
                                const isGenerated = form.dctf_web_gerada;

                                return (
                                    <tr key={emp.id} className="hover:bg-muted/20 transition-colors">
                                        <td className="px-4 py-3">
                                            {isGenerated ? (
                                                <span className="flex items-center gap-1.5 text-success font-medium">
                                                    <CheckCircle size={16} /> Gerada
                                                </span>
                                            ) : (
                                                <span className="flex items-center gap-1.5 text-muted-foreground font-medium">
                                                    <Circle size={16} /> Pendente
                                                </span>
                                            )}
                                        </td>
                                        <td className="px-4 py-3 font-medium text-card-foreground">
                                            {emp.nome_empresa}
                                        </td>
                                        <td className="px-4 py-3 text-muted-foreground whitespace-nowrap">
                                            {emp.cnpj || "—"}
                                        </td>
                                        <td className="px-4 py-3 w-48">
                                            <select
                                                value={isGenerated ? "sim" : "nao"}
                                                onChange={e => {
                                                    const val = e.target.value === "sim";
                                                    updateForm(emp.id, "dctf_web_gerada", val);
                                                    if (!val) updateForm(emp.id, "dctf_web_data_envio", "");
                                                }}
                                                className={inputCls}
                                            >
                                                <option value="nao">Não Gerada</option>
                                                <option value="sim">Gerada</option>
                                            </select>
                                        </td>
                                        <td className="px-4 py-3 w-48">
                                            {isGenerated ? (
                                                <input
                                                    type="date"
                                                    value={form.dctf_web_data_envio || ""}
                                                    onChange={e => updateForm(emp.id, "dctf_web_data_envio", e.target.value)}
                                                    className={inputCls}
                                                />
                                            ) : (
                                                <span className="text-xs text-muted-foreground italic px-2">N/A</span>
                                            )}
                                        </td>
                                        <td className="px-4 py-3 text-right">
                                            <button
                                                onClick={() => handleSave(emp.id)}
                                                disabled={isSaving}
                                                className="inline-flex items-center justify-center gap-2 px-3 py-1.5 rounded-md text-xs font-semibold text-primary-foreground shadow-sm hover:opacity-90 transition-opacity disabled:opacity-50"
                                                style={{ background: "var(--gradient-primary)" }}
                                            >
                                                <Save size={14} /> Salvar
                                            </button>
                                        </td>
                                    </tr>
                                );
                            })}

                            {filtered.length === 0 && (
                                <tr>
                                    <td colSpan={6} className="px-4 py-8 text-center text-muted-foreground">
                                        Nenhuma empresa encontrada com os filtros atuais.
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

export default DeclaracoesMensaisPage;

import React, { useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useNavigate, Link } from "react-router-dom";
import { Loader2, Fingerprint, Mail, ArrowLeft, AlertCircle } from "lucide-react";
import { toast } from "sonner";
import logoAudipreve from "@/assets/logo-audipreve.png";
import { maskCPF } from "@/lib/utils";


const EsqueciSenhaPage: React.FC = () => {
    const navigate = useNavigate();
    const [email, setEmail] = useState("");
    const [cpf, setCpf] = useState("");
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");
    const [success, setSuccess] = useState(false);



    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError("");
        setLoading(true);

        try {
            // 1. Verificar usando a função RPC segura que ignora RLS (lê perfis e auth anonimamente de forma controlada)
            const { data: isMatch, error: matchError } = await supabase.rpc('check_cpf_email_match', {
                p_cpf: cpf,
                p_email: email
            });

            if (matchError || !isMatch) {
                throw new Error("CPF não encontrado ou e-mail divergente do cadastro.");
            }

            const { error: resetError } = await supabase.auth.resetPasswordForEmail(email, {
                redirectTo: window.location.origin + "/reset-password",
            });

            if (resetError) throw resetError;

            setSuccess(true);
        } catch (err: any) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
    };

    if (success) {
        return (
            <div className="min-h-screen flex items-center justify-center p-4">
                <div className="bg-card border border-border rounded-2xl shadow-xl w-full max-w-md p-8 text-center space-y-6">
                    <div className="w-16 h-16 bg-success/10 text-success rounded-full flex items-center justify-center mx-auto">
                        <Mail size={32} />
                    </div>
                    <h2 className="text-2xl font-bold">Verifique seu E-mail</h2>
                    <p className="text-muted-foreground">
                        Enviamos um link de recuperação para <strong>{email}</strong>. Por favor, verifique sua caixa de entrada e spam.
                    </p>
                    <Link to="/login" className="block w-full py-3 rounded-xl font-bold bg-muted hover:bg-muted/80 transition-all">
                        Voltar para o Login
                    </Link>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen flex items-center justify-center p-4">
            <div className="bg-card border border-border rounded-2xl shadow-xl w-full max-w-md overflow-hidden p-8 space-y-8 animate-fade-in">
                <div className="text-center">
                    <img src={logoAudipreve} alt="Audipreve" className="w-20 h-20 object-contain mx-auto mb-6" />
                    <h2 className="text-2xl font-bold text-card-foreground">Recuperar Senha</h2>
                    <p className="text-muted-foreground mt-2 text-sm">Informe seu CPF e e-mail cadastrados.</p>
                </div>

                <form onSubmit={handleSubmit} className="space-y-6">
                    <div className="space-y-4">
                        <div>
                            <label className="block text-sm font-semibold text-muted-foreground mb-1.5 ml-1">CPF</label>
                            <div className="relative">
                                <Fingerprint size={18} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-muted-foreground" />
                                <input
                                    type="text"
                                    placeholder="000.000.000-00"
                                    value={cpf}
                                    onChange={e => setCpf(maskCPF(e.target.value))}

                                    required
                                    className="w-full pl-11 pr-4 py-3 border border-border rounded-xl bg-background focus:ring-2 focus:ring-primary outline-none transition-all"
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-semibold text-muted-foreground mb-1.5 ml-1">E-mail Cadastrado</label>
                            <div className="relative">
                                <Mail size={18} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-muted-foreground" />
                                <input
                                    type="email"
                                    placeholder="seu@email.com"
                                    value={email}
                                    onChange={e => setEmail(e.target.value)}
                                    required
                                    className="w-full pl-11 pr-4 py-3 border border-border rounded-xl bg-background focus:ring-2 focus:ring-primary outline-none transition-all"
                                />
                            </div>
                        </div>
                    </div>

                    {error && (
                        <div className="flex gap-3 p-4 bg-destructive/10 border border-destructive/20 rounded-xl text-destructive">
                            <AlertCircle size={18} className="shrink-0 mt-0.5" />
                            <p className="text-sm font-medium">{error}</p>
                        </div>
                    )}

                    <button
                        type="submit"
                        disabled={loading}
                        className="w-full py-4 rounded-xl font-bold text-primary-foreground shadow-lg transition-all hover:scale-[1.02] disabled:opacity-50"
                        style={{ background: "var(--gradient-primary)" }}
                    >
                        {loading ? <Loader2 className="animate-spin mx-auto" size={20} /> : "Enviar Link de Recuperação"}
                    </button>
                </form>

                <div className="text-center">
                    <Link to="/login" className="inline-flex items-center gap-2 text-sm font-medium text-muted-foreground hover:text-primary transition-colors">
                        <ArrowLeft size={16} /> Voltar para o Login
                    </Link>
                </div>
            </div>
        </div>
    );
};

export default EsqueciSenhaPage;

import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Search, ChevronDown, ChevronUp, Save, CheckCircle, Circle } from "lucide-react";
import { toast } from "sonner";
import { useEmpresas } from "@/hooks/useEmpresas";

const regimeLabels: Record<string, string> = { simples: "Simples Nacional", lucro_presumido: "Lucro Presumido", lucro_real: "Lucro Real", mei: "MEI" };

const FiscalPage: React.FC = () => {
  const { empresas, loading } = useEmpresas("fiscal");
  const [fiscalData, setFiscalData] = useState<Record<string, any>>({});
  const [search, setSearch] = useState("");
  const [competencia, setCompetencia] = useState(new Date().toISOString().slice(0, 7));
  const [expanded, setExpanded] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Record<string, any>>({});
  const [activeTab, setActiveTab] = useState<"ativas" | "mei" | "paralisadas" | "baixadas">("ativas");

  useEffect(() => {
    const load = async () => {
      const { data } = await supabase.from("fiscal").select("*").eq("competencia", competencia);
      const map: Record<string, any> = {};
      data?.forEach(f => { map[f.empresa_id] = f; });
      setFiscalData(map);
    };
    load();
  }, [competencia]);

  const filtered = empresas.filter(e => {
    const matchSearch = e.nome_empresa?.toLowerCase().includes(search.toLowerCase()) || e.cnpj?.includes(search);

    let matchTab = false;
    if (activeTab === "ativas") {
      matchTab = (!e.situacao || e.situacao === "ativa") && e.porte_empresa !== "mei";
    } else if (activeTab === "mei") {
      matchTab = (!e.situacao || e.situacao === "ativa") && e.porte_empresa === "mei";
    } else if (activeTab === "paralisadas") {
      matchTab = e.situacao === "paralisada";
    } else if (activeTab === "baixadas") {
      matchTab = e.situacao === "baixada";
    }

    return matchSearch && matchTab;
  });

  const toggleExpand = async (id: string) => {
    if (expanded === id) { setExpanded(null); return; }
    setExpanded(id);
    const existing = fiscalData[id] || {};
    let fixedFields = {
      tipo_nota: "", recebimento_arquivos: "", aliquota: "", ramo_empresarial: "",
      aliquota_irpj: "", aliquota_csll: "", aliquota_pis: "", aliquota_cofins: "",
      aliquota_icms: "", aliquota_iss: "", aliquota_cbs: "", aliquota_ibs: ""
    };

    if (!existing.id) {
      const { data: prev } = await supabase.from("fiscal").select("*").eq("empresa_id", id).order("competencia", { ascending: false }).limit(1);
      if (prev?.[0]) {
        fixedFields = {
          tipo_nota: prev[0].tipo_nota || "", recebimento_arquivos: prev[0].recebimento_arquivos || "", aliquota: prev[0].aliquota?.toString() || "", ramo_empresarial: prev[0].ramo_empresarial || "",
          aliquota_irpj: prev[0].aliquota_irpj?.toString() || "", aliquota_csll: prev[0].aliquota_csll?.toString() || "",
          aliquota_pis: prev[0].aliquota_pis?.toString() || "", aliquota_cofins: prev[0].aliquota_cofins?.toString() || "",
          aliquota_icms: prev[0].aliquota_icms?.toString() || "", aliquota_iss: prev[0].aliquota_iss?.toString() || "",
          aliquota_cbs: prev[0].aliquota_cbs?.toString() || "", aliquota_ibs: prev[0].aliquota_ibs?.toString() || ""
        };
      }
    } else {
      fixedFields = {
        tipo_nota: existing.tipo_nota || "", recebimento_arquivos: existing.recebimento_arquivos || "", aliquota: existing.aliquota?.toString() || "", ramo_empresarial: existing.ramo_empresarial || "",
        aliquota_irpj: existing.aliquota_irpj?.toString() || "", aliquota_csll: existing.aliquota_csll?.toString() || "",
        aliquota_pis: existing.aliquota_pis?.toString() || "", aliquota_cofins: existing.aliquota_cofins?.toString() || "",
        aliquota_icms: existing.aliquota_icms?.toString() || "", aliquota_iss: existing.aliquota_iss?.toString() || "",
        aliquota_cbs: existing.aliquota_cbs?.toString() || "", aliquota_ibs: existing.aliquota_ibs?.toString() || ""
      };
    }

    setEditForm(prev => ({
      ...prev, [id]: {
        ...fixedFields, forma_envio: existing.forma_envio || "",
        status_guia: existing.status_guia || "pendente", data_envio: existing.data_envio || "",
        irpj_csll_status: existing.irpj_csll_status || "pendente", irpj_csll_data_envio: existing.irpj_csll_data_envio || "",
        pis_cofins_status: existing.pis_cofins_status || "pendente", pis_cofins_data_envio: existing.pis_cofins_data_envio || "",
        icms_status: existing.icms_status || "pendente", icms_data_envio: existing.icms_data_envio || "",
        iss_status: existing.iss_status || "pendente", iss_data_envio: existing.iss_data_envio || "",
        cbs_status: existing.cbs_status || "pendente", cbs_data_envio: existing.cbs_data_envio || "",
        ibs_status: existing.ibs_status || "pendente", ibs_data_envio: existing.ibs_data_envio || "",
        observacoes: existing.observacoes || {},
      }
    }));
  };

  const handleSave = async (empresaId: string) => {
    const form = editForm[empresaId];
    const existing = fiscalData[empresaId];
    try {
      const payload = {
        empresa_id: empresaId, competencia, tipo_nota: form.tipo_nota || null,
        recebimento_arquivos: form.recebimento_arquivos || null, forma_envio: form.forma_envio || null,
        aliquota: form.aliquota ? parseFloat(form.aliquota) : null,
        status_guia: form.status_guia || "pendente", data_envio: form.data_envio || null,
        observacoes: form.observacoes || {}, ramo_empresarial: form.ramo_empresarial || null,

        aliquota_irpj: form.aliquota_irpj ? parseFloat(form.aliquota_irpj) : null,
        aliquota_csll: form.aliquota_csll ? parseFloat(form.aliquota_csll) : null,
        irpj_csll_status: form.irpj_csll_status || "pendente",
        irpj_csll_data_envio: form.irpj_csll_data_envio || null,

        aliquota_pis: form.aliquota_pis ? parseFloat(form.aliquota_pis) : null,
        aliquota_cofins: form.aliquota_cofins ? parseFloat(form.aliquota_cofins) : null,
        pis_cofins_status: form.pis_cofins_status || "pendente",
        pis_cofins_data_envio: form.pis_cofins_data_envio || null,

        aliquota_icms: form.aliquota_icms ? parseFloat(form.aliquota_icms) : null,
        icms_status: form.icms_status || "pendente",
        icms_data_envio: form.icms_data_envio || null,

        aliquota_iss: form.aliquota_iss ? parseFloat(form.aliquota_iss) : null,
        iss_status: form.iss_status || "pendente",
        iss_data_envio: form.iss_data_envio || null,

        aliquota_cbs: form.aliquota_cbs ? parseFloat(form.aliquota_cbs) : null,
        cbs_status: form.cbs_status || "pendente",
        cbs_data_envio: form.cbs_data_envio || null,

        aliquota_ibs: form.aliquota_ibs ? parseFloat(form.aliquota_ibs) : null,
        ibs_status: form.ibs_status || "pendente",
        ibs_data_envio: form.ibs_data_envio || null,
      };
      if (existing?.id) {
        await supabase.from("fiscal").update(payload).eq("id", existing.id);
      } else {
        await supabase.from("fiscal").insert(payload);
      }
      toast.success("Dados fiscais salvos!");
      const { data } = await supabase.from("fiscal").select("*").eq("competencia", competencia);
      const map: Record<string, any> = {};
      data?.forEach(f => { map[f.empresa_id] = f; });
      setFiscalData(map);
    } catch (err: any) { toast.error(err.message); }
  };

  const updateForm = (empresaId: string, field: string, value: any) => {
    setEditForm(prev => ({ ...prev, [empresaId]: { ...prev[empresaId], [field]: value } }));
  };

  const inputCls = "w-full px-3 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none";
  const labelCls = "block text-xs font-medium text-muted-foreground mb-1";

  const completedCount = filtered.filter(e => fiscalData[e.id]?.status_guia === "enviada" || fiscalData[e.id]?.status_guia === "gerada").length;

  if (loading) {
    return <div className="flex items-center justify-center h-64"><div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>;
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-end gap-4">
        <input type="month" value={competencia} onChange={e => setCompetencia(e.target.value)} className="px-4 py-2.5 border border-border rounded-xl bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none font-semibold" />
      </div>
      <div className="grid grid-cols-3 gap-4">
        <div className="stat-card"><p className="text-xs text-muted-foreground uppercase">Empresas</p><p className="text-2xl font-bold text-primary mt-1">{filtered.length}</p></div>
        <div className="stat-card"><p className="text-xs text-muted-foreground uppercase">Concluídas</p><p className="text-2xl font-bold text-success mt-1">{completedCount}</p></div>
        <div className="stat-card"><p className="text-xs text-muted-foreground uppercase">Pendentes</p><p className="text-2xl font-bold text-warning mt-1">{filtered.length - completedCount}</p></div>
      </div>
      <div className="relative max-w-sm"><Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" /><input type="text" placeholder="Buscar empresa..." value={search} onChange={e => setSearch(e.target.value)} className="w-full pl-9 pr-4 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" /></div>

      <div className="flex border-b border-border overflow-x-auto no-scrollbar">
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "ativas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("ativas")}
        >
          Empresas Ativas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "mei"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("mei")}
        >
          Empresas MEI
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "paralisadas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("paralisadas")}
        >
          Empresas Paralisadas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "baixadas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("baixadas")}
        >
          Empresas Baixadas
        </button>
      </div>

      <div className="space-y-3">
        {filtered.map(emp => {
          const isOpen = expanded === emp.id;
          const form = editForm[emp.id] || {};
          const done = emp.regime_tributario === "lucro_real"
            ? (fiscalData[emp.id]?.irpj_csll_status === "enviada" || fiscalData[emp.id]?.irpj_csll_status === "gerada")
            : (fiscalData[emp.id]?.status_guia === "enviada" || fiscalData[emp.id]?.status_guia === "gerada");
          return (
            <div key={emp.id} className="module-card !p-0 overflow-hidden">
              <div className="flex items-center justify-between p-4 cursor-pointer hover:bg-muted/30 transition-colors" onClick={() => toggleExpand(emp.id)}>
                <div className="flex items-center gap-3">{done ? <CheckCircle size={18} className="text-success" /> : <Circle size={18} className="text-muted-foreground" />}<div><p className="font-medium text-card-foreground">{emp.nome_empresa}</p><p className="text-xs text-muted-foreground">{emp.cnpj || "—"} • {regimeLabels[emp.regime_tributario] || "—"}</p></div></div>
                <div className="flex items-center gap-2"><span className={`badge-status ${done ? "badge-success" : "badge-warning"}`}>{done ? "Concluído" : "Pendente"}</span>{isOpen ? <ChevronUp size={16} className="text-muted-foreground" /> : <ChevronDown size={16} className="text-muted-foreground" />}</div>
              </div>
              {isOpen && (
                <div className="border-t border-border p-5 space-y-5 bg-muted/10">
                  {/* Informações Iniciais Comuns */}
                  <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                    <div><label className={labelCls}>Tipo de Nota</label><input value={form.tipo_nota || ""} onChange={e => updateForm(emp.id, "tipo_nota", e.target.value)} className={inputCls} placeholder="NFE, NFCE, NFSE" /></div>
                    <div><label className={labelCls}>Recebimento de Arquivos</label><input value={form.recebimento_arquivos || ""} onChange={e => updateForm(emp.id, "recebimento_arquivos", e.target.value)} className={inputCls} placeholder="Ex: Email, WhatsApp..." /></div>
                    <div><label className={labelCls}>Forma de Envio</label><input value={form.forma_envio || ""} onChange={e => updateForm(emp.id, "forma_envio", e.target.value)} className={inputCls} placeholder="Ex: Email, WhatsApp..." /></div>
                    <div><label className={labelCls}>Ramo Empresarial</label><input value={form.ramo_empresarial || ""} onChange={e => updateForm(emp.id, "ramo_empresarial", e.target.value)} className={inputCls} placeholder="Ex: Comércio, Serviços..." /></div>
                  </div>

                  {emp.regime_tributario === "lucro_real" ? (
                    <div className="space-y-6">
                      {/* Impostos Federais */}
                      <div className="bg-card p-4 rounded-xl border border-border shadow-sm space-y-4">
                        <h4 className="text-sm font-bold text-foreground border-b border-border pb-2">Impostos Federais</h4>

                        <div className="space-y-2">
                          <p className="text-xs font-semibold text-muted-foreground uppercase">IRPJ / CSLL</p>
                          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                            <div><label className={labelCls}>Alíquota IRPJ (%)</label><input value={form.aliquota_irpj || ""} onChange={e => updateForm(emp.id, "aliquota_irpj", e.target.value)} className={inputCls} placeholder="Ex: 15" /></div>
                            <div><label className={labelCls}>Alíquota CSLL (%)</label><input value={form.aliquota_csll || ""} onChange={e => updateForm(emp.id, "aliquota_csll", e.target.value)} className={inputCls} placeholder="Ex: 9" /></div>
                            <div><label className={labelCls}>Status (IRPJ/CSLL)</label><select value={form.irpj_csll_status || "pendente"} onChange={e => updateForm(emp.id, "irpj_csll_status", e.target.value)} className={inputCls}><option value="pendente">Pendente</option><option value="gerada">Gerada</option><option value="enviada">Enviada</option></select></div>
                            <div><label className={labelCls}>Data de Envio</label><input type="date" value={form.irpj_csll_data_envio || ""} onChange={e => updateForm(emp.id, "irpj_csll_data_envio", e.target.value)} className={inputCls} /></div>
                          </div>
                        </div>

                        <div className="space-y-2 pt-2">
                          <p className="text-xs font-semibold text-muted-foreground uppercase">PIS / COFINS</p>
                          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                            <div><label className={labelCls}>Alíquota PIS (%)</label><input value={form.aliquota_pis || ""} onChange={e => updateForm(emp.id, "aliquota_pis", e.target.value)} className={inputCls} placeholder="Ex: 1.65" /></div>
                            <div><label className={labelCls}>Alíquota COFINS (%)</label><input value={form.aliquota_cofins || ""} onChange={e => updateForm(emp.id, "aliquota_cofins", e.target.value)} className={inputCls} placeholder="Ex: 7.6" /></div>
                            <div><label className={labelCls}>Status (PIS/COFINS)</label><select value={form.pis_cofins_status || "pendente"} onChange={e => updateForm(emp.id, "pis_cofins_status", e.target.value)} className={inputCls}><option value="pendente">Pendente</option><option value="gerada">Gerada</option><option value="enviada">Enviada</option></select></div>
                            <div><label className={labelCls}>Data de Envio</label><input type="date" value={form.pis_cofins_data_envio || ""} onChange={e => updateForm(emp.id, "pis_cofins_data_envio", e.target.value)} className={inputCls} /></div>
                          </div>
                        </div>
                      </div>

                      {/* Impostos Estaduais */}
                      <div className="bg-card p-4 rounded-xl border border-border shadow-sm space-y-4">
                        <h4 className="text-sm font-bold text-foreground border-b border-border pb-2">Impostos Estaduais (ICMS)</h4>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                          <div><label className={labelCls}>Alíquota ICMS (%)</label><input value={form.aliquota_icms || ""} onChange={e => updateForm(emp.id, "aliquota_icms", e.target.value)} className={inputCls} placeholder="Ex: 18" /></div>
                          <div><label className={labelCls}>Status da Guia</label><select value={form.icms_status || "pendente"} onChange={e => updateForm(emp.id, "icms_status", e.target.value)} className={inputCls}><option value="pendente">Pendente</option><option value="gerada">Gerada</option><option value="enviada">Enviada</option></select></div>
                          <div><label className={labelCls}>Data de Envio</label><input type="date" value={form.icms_data_envio || ""} onChange={e => updateForm(emp.id, "icms_data_envio", e.target.value)} className={inputCls} /></div>
                        </div>
                      </div>

                      {/* Impostos Municipais */}
                      <div className="bg-card p-4 rounded-xl border border-border shadow-sm space-y-4">
                        <h4 className="text-sm font-bold text-foreground border-b border-border pb-2">Impostos Municipais (ISS)</h4>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                          <div><label className={labelCls}>Alíquota ISS (%)</label><input value={form.aliquota_iss || ""} onChange={e => updateForm(emp.id, "aliquota_iss", e.target.value)} className={inputCls} placeholder="Ex: 5" /></div>
                          <div><label className={labelCls}>Status da Guia</label><select value={form.iss_status || "pendente"} onChange={e => updateForm(emp.id, "iss_status", e.target.value)} className={inputCls}><option value="pendente">Pendente</option><option value="gerada">Gerada</option><option value="enviada">Enviada</option></select></div>
                          <div><label className={labelCls}>Data de Envio</label><input type="date" value={form.iss_data_envio || ""} onChange={e => updateForm(emp.id, "iss_data_envio", e.target.value)} className={inputCls} /></div>
                        </div>
                      </div>

                      {/* Reforma Tributária */}
                      <div className="bg-card p-4 rounded-xl border border-border shadow-sm space-y-4">
                        <h4 className="text-sm font-bold text-foreground border-b border-border pb-2">Reforma Tributária</h4>
                        <div className="space-y-2">
                          <p className="text-xs font-semibold text-muted-foreground uppercase">Federal (CBS)</p>
                          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            <div><label className={labelCls}>Alíquota CBS (%)</label><input value={form.aliquota_cbs || ""} onChange={e => updateForm(emp.id, "aliquota_cbs", e.target.value)} className={inputCls} placeholder="Ex: 8.8" /></div>
                            <div><label className={labelCls}>Status da Guia</label><select value={form.cbs_status || "pendente"} onChange={e => updateForm(emp.id, "cbs_status", e.target.value)} className={inputCls}><option value="pendente">Pendente</option><option value="gerada">Gerada</option><option value="enviada">Enviada</option></select></div>
                            <div><label className={labelCls}>Data de Envio</label><input type="date" value={form.cbs_data_envio || ""} onChange={e => updateForm(emp.id, "cbs_data_envio", e.target.value)} className={inputCls} /></div>
                          </div>
                        </div>
                        <div className="space-y-2 pt-2">
                          <p className="text-xs font-semibold text-muted-foreground uppercase">Estadual/Municipal (IBS)</p>
                          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            <div><label className={labelCls}>Alíquota IBS (%)</label><input value={form.aliquota_ibs || ""} onChange={e => updateForm(emp.id, "aliquota_ibs", e.target.value)} className={inputCls} placeholder="Ex: 17.7" /></div>
                            <div><label className={labelCls}>Status da Guia</label><select value={form.ibs_status || "pendente"} onChange={e => updateForm(emp.id, "ibs_status", e.target.value)} className={inputCls}><option value="pendente">Pendente</option><option value="gerada">Gerada</option><option value="enviada">Enviada</option></select></div>
                            <div><label className={labelCls}>Data de Envio</label><input type="date" value={form.ibs_data_envio || ""} onChange={e => updateForm(emp.id, "ibs_data_envio", e.target.value)} className={inputCls} /></div>
                          </div>
                        </div>
                      </div>

                    </div>
                  ) : (
                    <div className="bg-card p-4 rounded-xl border border-border shadow-sm">
                      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                        <div><label className={labelCls}>Alíquota Geral Única (%)</label><input value={form.aliquota || ""} onChange={e => updateForm(emp.id, "aliquota", e.target.value)} className={inputCls} placeholder="Ex: 6" /></div>
                        <div><label className={labelCls}>Status da Guia Única</label><select value={form.status_guia || "pendente"} onChange={e => updateForm(emp.id, "status_guia", e.target.value)} className={inputCls}><option value="pendente">Pendente</option><option value="gerada">Gerada</option><option value="enviada">Enviada</option></select></div>
                        <div><label className={labelCls}>Data de Envio</label><input type="date" value={form.data_envio || ""} onChange={e => updateForm(emp.id, "data_envio", e.target.value)} className={inputCls} /></div>
                      </div>
                    </div>
                  )}

                  <div className="flex justify-end pt-2"><button onClick={() => handleSave(emp.id)} className="flex items-center gap-2 px-6 py-2 rounded-lg text-sm font-semibold text-primary-foreground shadow-md hover:brightness-110 transition-all" style={{ background: "var(--gradient-primary)" }}><Save size={16} /> Salvar Alterações</button></div>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default FiscalPage;

import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Search, ChevronDown, ChevronUp, Save, Building2, Plus, Calendar, DollarSign, Clock, CheckCircle, Trash2 } from "lucide-react";
import { toast } from "sonner";
import { format } from "date-fns";
import { useEmpresas } from "@/hooks/useEmpresas";

type TabType = "configuracao" | "mensal";
type MainTabType = "empresas" | "geral";

const HonorariosPage: React.FC = () => {
  const { empresas, loading } = useEmpresas("honorarios");
  const [search, setSearch] = useState("");
  const [mainTab, setMainTab] = useState<MainTabType>("empresas");
  const [globalCompetencia, setGlobalCompetencia] = useState(new Date().toISOString().slice(0, 7));
  const [geralData, setGeralData] = useState<any[]>([]);

  // View: Empresas States
  const [expanded, setExpanded] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<Record<string, TabType>>({});
  const [activeStatusTab, setActiveStatusTab] = useState<"ativas" | "mei" | "paralisadas" | "baixadas">("ativas");

  // Data States for View: Empresas
  const [configs, setConfigs] = useState<Record<string, any>>({});
  const [mensalData, setMensalData] = useState<Record<string, any[]>>({});
  const [configForm, setConfigForm] = useState<Record<string, any>>({});
  const [mensalForm, setMensalForm] = useState<Record<string, any>>({});
  const [competenciaSelecionada, setCompetenciaSelecionada] = useState<Record<string, string>>({});

  useEffect(() => {
    if (mainTab === "geral") {
      loadGeralData();
    }
  }, [mainTab, globalCompetencia]);

  const loadGeralData = async () => {
    const { data: records, error } = await supabase
      .from("honorarios_mensal")
      .select(`
        *,
        empresas (nome_empresa)
      `)
      .eq("competencia", globalCompetencia);

    if (error) {
      toast.error("Erro ao carregar dados do mês: " + error.message);
      return;
    }

    setGeralData(records || []);
  };

  const toggleGlobalPago = async (id: string, currentValue: boolean) => {
    try {
      await supabase.from("honorarios_mensal").update({ pago: !currentValue }).eq("id", id);
      toast.success(`Status de pagamento atualizado.`);
      loadGeralData();
    } catch (err: any) {
      toast.error("Erro ao atualizar status: " + err.message);
    }
  };

  // ------------------ Existing Logic for View: Empresas ------------------ //
  const toggleExpand = async (empresaId: string) => {
    if (expanded === empresaId) {
      setExpanded(null);
      return;
    }
    setExpanded(empresaId);
    if (!activeTab[empresaId]) setActiveTab(prev => ({ ...prev, [empresaId]: "mensal" }));
    if (!competenciaSelecionada[empresaId]) setCompetenciaSelecionada(prev => ({ ...prev, [empresaId]: new Date().toISOString().slice(0, 7) }));
    await loadConfig(empresaId);
    await loadMensal(empresaId);
  };

  const loadConfig = async (empresaId: string) => {
    const { data } = await supabase.from("honorarios_config").select("*").eq("empresa_id", empresaId).maybeSingle();
    const config = data || { valor_honorario: 0, valor_por_funcionario: 0, valor_por_recalculo: 0, valor_trabalhista: 0, outros_servicos: [] };
    if (config && !config.outros_servicos) config.outros_servicos = [];
    setConfigs(prev => ({ ...prev, [empresaId]: config }));
    setConfigForm(prev => ({ ...prev, [empresaId]: { ...config } }));
  };

  const loadMensal = async (empresaId: string) => {
    const { data } = await supabase.from("honorarios_mensal").select("*").eq("empresa_id", empresaId).order('competencia', { ascending: false });
    setMensalData(prev => ({ ...prev, [empresaId]: data || [] }));
  };

  const handleSaveConfig = async (empresaId: string) => {
    const form = configForm[empresaId];
    try {
      const payload = {
        empresa_id: empresaId,
        valor_honorario: parseFloat(form.valor_honorario) || 0,
        valor_por_funcionario: parseFloat(form.valor_por_funcionario) || 0,
        valor_por_recalculo: parseFloat(form.valor_por_recalculo) || 0,
        valor_trabalhista: parseFloat(form.valor_trabalhista) || 0,
        outros_servicos: form.outros_servicos || []
      };
      if (configs[empresaId]?.id) await supabase.from("honorarios_config").update(payload).eq("id", configs[empresaId].id);
      else await supabase.from("honorarios_config").insert(payload);
      toast.success("Configuração de honorários salva!");
      loadConfig(empresaId);
    } catch (err: any) { toast.error("Erro ao salvar: " + err.message); }
  };

  const calculateTotal = (config: any, qtdFunc: number, qtdRecalculos: number, teveTrabalhista: boolean) => {
    const honorario = Number(config?.valor_honorario || 0);
    const funcVlr = Number(config?.valor_por_funcionario || 0) * qtdFunc;
    const recVlr = Number(config?.valor_por_recalculo || 0) * qtdRecalculos;
    const trabVlr = teveTrabalhista ? Number(config?.valor_trabalhista || 0) : 0;
    const outrosVlr = (config?.outros_servicos || []).reduce((sum: number, item: any) => sum + Number(item.valor || 0), 0);

    const detalhes = [
      { rotulo: "Honorário Base", qtd: 1, vlrUnit: honorario, vlrTotal: honorario },
      ...(qtdFunc > 0 ? [{ rotulo: "Funcionários/Pró-labore", qtd: qtdFunc, vlrUnit: Number(config?.valor_por_funcionario || 0), vlrTotal: funcVlr }] : []),
      ...(qtdRecalculos > 0 ? [{ rotulo: "Recálculos", qtd: qtdRecalculos, vlrUnit: Number(config?.valor_por_recalculo || 0), vlrTotal: recVlr }] : []),
      ...(teveTrabalhista ? [{ rotulo: "Encargos Trabalhistas", qtd: 1, vlrUnit: Number(config?.valor_trabalhista || 0), vlrTotal: trabVlr }] : []),
      ...(config?.outros_servicos || []).map((s: any) => ({ rotulo: s.descricao || "Serviço Adicional", qtd: 1, vlrUnit: Number(s.valor || 0), vlrTotal: Number(s.valor || 0) }))
    ];

    return { total: honorario + funcVlr + recVlr + trabVlr + outrosVlr, detalhes };
  };

  const handleGenerateMonth = async (empresaId: string) => {
    const comp = competenciaSelecionada[empresaId];
    if (!comp) return;
    try {
      const config = configs[empresaId];
      if (!config || typeof config.valor_honorario === 'undefined') {
        toast.error("Configure os valores base primeiro na aba Configuração");
        return;
      }
      const { data: pessoalData } = await supabase.from("pessoal").select("*").eq("empresa_id", empresaId).eq("competencia", comp).maybeSingle();
      const qtdFunc = pessoalData?.qtd_funcionarios || 0;
      const teveTrabalhista = pessoalData?.possui_vt || pessoalData?.possui_va || pessoalData?.possui_vc;
      const { count: qtdRecalculos } = await supabase.from("recalculos").select("*", { count: 'exact', head: true }).eq("empresa_id", empresaId).eq("competencia", comp);

      const { total: valorTotal, detalhes } = calculateTotal(config, qtdFunc, qtdRecalculos || 0, teveTrabalhista || false);

      setMensalForm(prev => ({
        ...prev, [empresaId]: {
          competencia: comp, qtd_funcionarios: qtdFunc, qtd_recalculos: qtdRecalculos || 0,
          teve_encargo_trabalhista: teveTrabalhista || false, valor_total: valorTotal,
          detalhes_calculo: detalhes,
          data_vencimento: "", data_envio: "", forma_envio: "", status: "pendente", pago: false, observacoes: ""
        }
      }));
    } catch (err: any) { toast.error("Erro ao gerar mês: " + err.message); }
  };

  const handleSaveMensal = async (empresaId: string) => {
    const form = mensalForm[empresaId];
    if (!form) return;
    try {
      const payload = {
        empresa_id: empresaId, competencia: form.competencia, qtd_funcionarios: form.qtd_funcionarios,
        qtd_recalculos: form.qtd_recalculos, teve_encargo_trabalhista: form.teve_encargo_trabalhista,
        valor_total: form.valor_total, data_vencimento: form.data_vencimento || null, data_envio: form.data_envio || null,
        forma_envio: form.forma_envio || null, status: form.status, pago: form.pago,
        detalhes_calculo: form.detalhes_calculo || [],
        observacoes: form.observacoes ? { texto: form.observacoes } : null
      };

      const existingRecord = mensalData[empresaId]?.find((m: any) => m.competencia === form.competencia);
      if (existingRecord) await supabase.from("honorarios_mensal").update(payload).eq("id", existingRecord.id);
      else await supabase.from("honorarios_mensal").insert(payload);

      toast.success("Controle mensal salvo!");
      setMensalForm(prev => { const newForm = { ...prev }; delete newForm[empresaId]; return newForm; });
      loadMensal(empresaId);
    } catch (err: any) { toast.error("Erro ao salvar controle: " + err.message); }
  };

  const startEditMensal = (empresaId: string, record: any) => {
    setCompetenciaSelecionada(prev => ({ ...prev, [empresaId]: record.competencia }));
    setMensalForm(prev => ({ ...prev, [empresaId]: { ...record, observacoes: record.observacoes?.texto || "", detalhes_calculo: record.detalhes_calculo || [] } }));
  };

  const updateConfigForm = (id: string, field: string, value: any) => {
    setConfigForm(prev => ({ ...prev, [id]: { ...prev[id], [field]: value } }));
  };

  const updateMensalForm = (id: string, field: string, value: any) => {
    setMensalForm(prev => ({ ...prev, [id]: { ...prev[id], [field]: value } }));
  };

  const addOutroServico = (empresaId: string) => {
    setConfigForm(prev => {
      const form = prev[empresaId] || {};
      const outros = form.outros_servicos || [];
      return { ...prev, [empresaId]: { ...form, outros_servicos: [...outros, { descricao: "", valor: 0 }] } };
    });
  };

  const updateOutroServico = (empresaId: string, index: number, field: string, value: any) => {
    setConfigForm(prev => {
      const form = prev[empresaId];
      const outros = [...(form.outros_servicos || [])];
      outros[index] = { ...outros[index], [field]: value };
      return { ...prev, [empresaId]: { ...form, outros_servicos: outros } };
    });
  };

  const removeOutroServico = (empresaId: string, index: number) => {
    setConfigForm(prev => {
      const form = prev[empresaId];
      const outros = [...(form.outros_servicos || [])];
      outros.splice(index, 1);
      return { ...prev, [empresaId]: { ...form, outros_servicos: outros } };
    });
  };

  const filtered = empresas.filter(e => {
    const matchSearch = e.nome_empresa?.toLowerCase().includes(search.toLowerCase()) || e.cnpj?.includes(search);

    let matchTab = false;
    if (activeStatusTab === "ativas") {
      matchTab = (!e.situacao || e.situacao === "ativa") && e.porte_empresa !== "mei";
    } else if (activeStatusTab === "mei") {
      matchTab = (!e.situacao || e.situacao === "ativa") && e.porte_empresa === "mei";
    } else if (activeStatusTab === "paralisadas") {
      matchTab = e.situacao === "paralisada";
    } else if (activeStatusTab === "baixadas") {
      matchTab = e.situacao === "baixada";
    }

    return matchSearch && matchTab;
  });
  const inputCls = "w-full px-3 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none";
  const labelCls = "block text-xs font-medium text-muted-foreground mb-1";
  const formatCurrency = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  // Derived calculations for Geral View
  const totalValorAgregado = geralData.reduce((acc, curr) => acc + Number(curr.valor_total || 0), 0);
  const totalPago = geralData.filter(d => d.pago).reduce((acc, curr) => acc + Number(curr.valor_total || 0), 0);
  const totalPendente = totalValorAgregado - totalPago;

  if (loading) {
    return <div className="flex items-center justify-center h-64"><div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>;
  }

  return (
    <div className="space-y-6 animate-fade-in">


      {/* Main Tab Switcher */}
      <div className="flex bg-muted/30 p-1 rounded-xl w-full sm:w-fit">
        <button
          className={`flex-1 sm:flex-none uppercase tracking-wider text-xs font-bold px-6 py-2.5 rounded-lg transition-all duration-200 ${mainTab === "empresas" ? "bg-background text-primary shadow-sm ring-1 ring-border" : "text-muted-foreground hover:text-foreground"}`}
          onClick={() => setMainTab("empresas")}
        >
          Painel de Empresas
        </button>
        <button
          className={`flex-1 sm:flex-none uppercase tracking-wider text-xs font-bold px-6 py-2.5 rounded-lg transition-all duration-200 ${mainTab === "geral" ? "bg-background text-primary shadow-sm ring-1 ring-border" : "text-muted-foreground hover:text-foreground"}`}
          onClick={() => setMainTab("geral")}
        >
          Controle Geral (Resumo)
        </button>
      </div>

      {/* VIEW: CONTROLE GERAL */}
      {mainTab === "geral" && (
        <div className="space-y-6 animate-fade-in">
          <div className="flex flex-col sm:flex-row items-center justify-between bg-card border border-border p-4 rounded-xl shadow-sm gap-4">
            <h2 className="font-semibold text-card-foreground">Resumo de Honorários Mensais</h2>
            <div className="flex items-center gap-3 w-full sm:w-auto">
              <label className="text-sm font-medium text-muted-foreground whitespace-nowrap">Competência:</label>
              <input
                type="month"
                value={globalCompetencia}
                onChange={(e) => setGlobalCompetencia(e.target.value)}
                className="px-4 py-2 border border-border rounded-lg bg-background text-sm font-semibold text-foreground focus:ring-2 focus:ring-primary w-full sm:w-auto"
              />
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="bg-card border border-border rounded-xl p-5 shadow-sm">
              <div className="flex items-center justify-between mb-2">
                <p className="text-sm font-medium text-muted-foreground uppercase">Total Calculado</p>
                <div className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center">
                  <DollarSign size={16} className="text-primary" />
                </div>
              </div>
              <p className="text-2xl font-bold text-card-foreground">{formatCurrency(totalValorAgregado)}</p>
              <p className="text-xs text-muted-foreground mt-1">De todos os honorários gerados no mês</p>
            </div>

            <div className="bg-success/10 border border-success/20 rounded-xl p-5 shadow-sm">
              <div className="flex items-center justify-between mb-2">
                <p className="text-sm font-medium text-success uppercase">Total Recebido (Pago)</p>
                <div className="w-8 h-8 rounded-full bg-success/20 flex items-center justify-center">
                  <CheckCircle size={16} className="text-success" />
                </div>
              </div>
              <p className="text-2xl font-bold text-success">{formatCurrency(totalPago)}</p>
              <p className="text-xs text-success/80 mt-1">Valores marcados como pagos</p>
            </div>

            <div className="bg-warning/10 border border-warning/20 rounded-xl p-5 shadow-sm">
              <div className="flex items-center justify-between mb-2">
                <p className="text-sm font-medium text-warning uppercase">Pendente / Em Aberto</p>
                <div className="w-8 h-8 rounded-full bg-warning/20 flex items-center justify-center">
                  <Clock size={16} className="text-warning" />
                </div>
              </div>
              <p className="text-2xl font-bold text-warning">{formatCurrency(totalPendente)}</p>
              <p className="text-xs text-warning/80 mt-1">Aguardando recebimento</p>
            </div>
          </div>

          <div className="bg-card border border-border rounded-xl shadow-sm overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-sm text-left whitespace-nowrap">
                <thead className="bg-muted/50 text-xs uppercase text-muted-foreground">
                  <tr>
                    <th className="px-5 py-4 font-semibold">Empresa</th>
                    <th className="px-5 py-4 font-semibold text-right">Valor Calculado</th>
                    <th className="px-5 py-4 font-semibold text-center">Vencimento</th>
                    <th className="px-5 py-4 font-semibold text-center">Status</th>
                    <th className="px-5 py-4 font-semibold text-center">Pagamento</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-border">
                  {geralData.length === 0 ? (
                    <tr>
                      <td colSpan={5} className="px-5 py-8 text-center text-muted-foreground">
                        Nenhum honorário registrado para a competência {globalCompetencia}.
                      </td>
                    </tr>
                  ) : (
                    geralData.map((record) => (
                      <tr key={record.id} className="hover:bg-muted/30 transition-colors">
                        <td className="px-5 py-4 font-medium text-card-foreground">
                          {record.empresas?.nome_empresa}
                        </td>
                        <td className="px-5 py-4 font-bold text-primary text-right">
                          {formatCurrency(record.valor_total)}
                        </td>
                        <td className="px-5 py-4 text-center text-muted-foreground">
                          {record.data_vencimento ? format(new Date(record.data_vencimento), 'dd/MM/yyyy') : '—'}
                        </td>
                        <td className="px-5 py-4 text-center">
                          <span className={`px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${record.status === "enviada" ? "bg-success/10 text-success border border-success/20" :
                            record.status === "gerada" ? "bg-primary/10 text-primary border border-primary/20" : "bg-warning/10 text-warning border border-warning/20"
                            }`}>
                            {record.status}
                          </span>
                        </td>
                        <td className="px-5 py-4 text-center">
                          <button
                            onClick={() => toggleGlobalPago(record.id, record.pago)}
                            className={`flex items-center gap-2 justify-center w-32 mx-auto px-3 py-1.5 rounded-lg text-xs font-bold transition-all ${record.pago
                              ? "bg-success text-success-foreground shadow-md hover:bg-success/90"
                              : "bg-muted text-muted-foreground border border-border hover:bg-muted/80 hover:text-foreground"
                              }`}
                          >
                            {record.pago ? <><CheckCircle size={14} /> PAGO</> : <><Clock size={14} /> PENDENTE</>}
                          </button>
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {/* VIEW: EMPRESAS (Existing content) */}
      {mainTab === "empresas" && (
        <div className="space-y-4 animate-fade-in">

          <div className="flex border-b border-border overflow-x-auto no-scrollbar">
            <button
              className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeStatusTab === "ativas"
                ? "border-primary text-primary"
                : "border-transparent text-muted-foreground hover:text-foreground"
                }`}
              onClick={() => setActiveStatusTab("ativas")}
            >
              Empresas Ativas
            </button>
            <button
              className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeStatusTab === "mei"
                ? "border-primary text-primary"
                : "border-transparent text-muted-foreground hover:text-foreground"
                }`}
              onClick={() => setActiveStatusTab("mei")}
            >
              Empresas MEI
            </button>
            <button
              className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeStatusTab === "paralisadas"
                ? "border-primary text-primary"
                : "border-transparent text-muted-foreground hover:text-foreground"
                }`}
              onClick={() => setActiveStatusTab("paralisadas")}
            >
              Empresas Paralisadas
            </button>
            <button
              className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeStatusTab === "baixadas"
                ? "border-primary text-primary"
                : "border-transparent text-muted-foreground hover:text-foreground"
                }`}
              onClick={() => setActiveStatusTab("baixadas")}
            >
              Empresas Baixadas
            </button>
          </div>

          <div className="relative max-w-sm"><Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" /><input type="text" placeholder="Buscar empresa..." value={search} onChange={e => setSearch(e.target.value)} className={inputCls + " pl-9"} /></div>
          <div className="space-y-3">
            {filtered.map(emp => {
              const isOpen = expanded === emp.id;
              const tab = activeTab[emp.id] || "mensal";
              const cForm = configForm[emp.id] || {};
              const mForm = mensalForm[emp.id];
              const hasMensalRecords = mensalData[emp.id] && mensalData[emp.id].length > 0;

              return (
                <div key={emp.id} className="module-card !p-0 overflow-hidden">
                  <div className="flex items-center justify-between p-4 cursor-pointer hover:bg-muted/30 transition-colors" onClick={() => toggleExpand(emp.id)}>
                    <div className="flex items-center gap-3"><div className="w-9 h-9 rounded-lg bg-primary/10 flex items-center justify-center"><Building2 size={16} className="text-primary" /></div><div><p className="font-medium text-card-foreground">{emp.nome_empresa}</p><p className="text-xs text-muted-foreground">{emp.cnpj || "—"}</p></div></div>
                    {isOpen ? <ChevronUp size={16} className="text-muted-foreground" /> : <ChevronDown size={16} className="text-muted-foreground" />}
                  </div>

                  {isOpen && (
                    <div className="border-t border-border bg-muted/10">
                      <div className="flex border-b border-border">
                        <button className={`flex-1 py-3 text-sm font-medium transition-colors ${tab === "mensal" ? "text-primary border-b-2 border-primary bg-background/50" : "text-muted-foreground hover:bg-muted/50"}`} onClick={() => setActiveTab(prev => ({ ...prev, [emp.id]: "mensal" }))}>Controle Mensal</button>
                        <button className={`flex-1 py-3 text-sm font-medium transition-colors ${tab === "configuracao" ? "text-primary border-b-2 border-primary bg-background/50" : "text-muted-foreground hover:bg-muted/50"}`} onClick={() => setActiveTab(prev => ({ ...prev, [emp.id]: "configuracao" }))}>Configuração</button>
                      </div>

                      <div className="p-5">
                        {tab === "configuracao" && (
                          <div className="space-y-4">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                              <div><label className={labelCls}>Valor Base (Honorário Mensal)</label><div className="relative"><span className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground text-sm">R$</span><input type="number" step="0.01" value={cForm.valor_honorario || ""} onChange={e => updateConfigForm(emp.id, "valor_honorario", e.target.value)} className={`${inputCls} pl-9`} placeholder="0.00" /></div></div>
                              <div><label className={labelCls}>Valor Adicion. por Funcionário</label><div className="relative"><span className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground text-sm">R$</span><input type="number" step="0.01" value={cForm.valor_por_funcionario || ""} onChange={e => updateConfigForm(emp.id, "valor_por_funcionario", e.target.value)} className={`${inputCls} pl-9`} placeholder="0.00" /></div></div>
                              <div><label className={labelCls}>Valor Adicion. por Recálculo</label><div className="relative"><span className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground text-sm">R$</span><input type="number" step="0.01" value={cForm.valor_por_recalculo || ""} onChange={e => updateConfigForm(emp.id, "valor_por_recalculo", e.target.value)} className={`${inputCls} pl-9`} placeholder="0.00" /></div></div>
                              <div><label className={labelCls}>Valor Adicion. Trabalhista (Fixo)</label><div className="relative"><span className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground text-sm">R$</span><input type="number" step="0.01" value={cForm.valor_trabalhista || ""} onChange={e => updateConfigForm(emp.id, "valor_trabalhista", e.target.value)} className={`${inputCls} pl-9`} placeholder="0.00" /></div></div>
                            </div>

                            <div className="mt-6 pt-6 border-t border-border">
                              <div className="flex items-center justify-between mb-4">
                                <h4 className="text-sm font-bold text-card-foreground">Serviços Adicionais (Extra)</h4>
                                <button onClick={() => addOutroServico(emp.id)} className="flex items-center gap-1 text-xs font-semibold text-primary hover:text-primary/80">
                                  <Plus size={14} /> Adicionar Serviço
                                </button>
                              </div>
                              <div className="space-y-3">
                                {cForm.outros_servicos?.map((servico: any, idx: number) => (
                                  <div key={idx} className="flex flex-col sm:flex-row gap-3 items-start sm:items-end bg-background p-3 rounded-lg border border-border">
                                    <div className="flex-1 w-full text-left">
                                      <label className={labelCls}>Descrição</label>
                                      <input type="text" value={servico.descricao || ""} onChange={e => updateOutroServico(emp.id, idx, "descricao", e.target.value)} className={inputCls} placeholder="Ex: Imposto Sindical, Taxa Extra..." />
                                    </div>
                                    <div className="w-full sm:w-1/3 text-left">
                                      <label className={labelCls}>Valor</label>
                                      <div className="relative">
                                        <span className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground text-sm">R$</span>
                                        <input type="number" step="0.01" value={servico.valor || ""} onChange={e => updateOutroServico(emp.id, idx, "valor", e.target.value)} className={`${inputCls} pl-9`} placeholder="0.00" />
                                      </div>
                                    </div>
                                    <button onClick={() => removeOutroServico(emp.id, idx)} className="p-2 sm:mb-[2px] rounded-lg bg-destructive/10 text-destructive hover:bg-destructive hover:text-white transition-colors" title="Excluir Serviço">
                                      <Trash2 size={18} />
                                    </button>
                                  </div>
                                ))}
                                {(!cForm.outros_servicos || cForm.outros_servicos.length === 0) && (
                                  <p className="text-xs text-muted-foreground italic">Nenhum serviço adicional configurado.</p>
                                )}
                              </div>
                            </div>

                            <div className="flex justify-end pt-4"><button onClick={() => handleSaveConfig(emp.id)} className="flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold text-primary-foreground shadow-md" style={{ background: "var(--gradient-primary)" }}><Save size={16} /> Salvar Configuração</button></div>
                          </div>
                        )}

                        {tab === "mensal" && (
                          <div className="space-y-6">
                            {!mForm && (
                              <div className="flex flex-col sm:flex-row items-end gap-3 bg-background p-4 rounded-lg border border-border">
                                <div className="flex-1 w-full"><label className={labelCls}>Nova Competência</label><input type="month" value={competenciaSelecionada[emp.id] || ""} onChange={e => setCompetenciaSelecionada(prev => ({ ...prev, [emp.id]: e.target.value }))} className={inputCls} /></div>
                                <button onClick={() => handleGenerateMonth(emp.id)} className="w-full sm:w-auto flex items-center justify-center gap-2 px-4 py-2 bg-primary/10 text-primary hover:bg-primary/20 rounded-lg text-sm font-semibold transition-colors"><Plus size={16} /> Gerar ou Editar Mês</button>
                              </div>
                            )}

                            {mForm && (
                              <div className="bg-background p-5 rounded-lg border border-primary/20 shadow-sm space-y-4">
                                <div className="flex items-center justify-between border-b border-border pb-3">
                                  <h3 className="text-sm font-bold text-card-foreground flex items-center gap-2"><Calendar size={16} className="text-primary" /> Competência: {mForm.competencia}</h3>
                                  <button onClick={() => setMensalForm(prev => { const n = { ...prev }; delete n[emp.id]; return n; })} className="text-xs text-muted-foreground hover:text-foreground">Cancelar</button>
                                </div>
                                <div className="grid grid-cols-2 md:grid-cols-4 gap-4 p-3 bg-muted/30 rounded-lg">
                                  <div><label className="block text-[10px] uppercase text-muted-foreground font-semibold mb-1">Qtd. Funcionários</label><p className="text-sm text-card-foreground font-medium">{mForm.qtd_funcionarios}</p></div>
                                  <div><label className="block text-[10px] uppercase text-muted-foreground font-semibold mb-1">Qtd. Recálculos</label><p className="text-sm text-card-foreground font-medium">{mForm.qtd_recalculos}</p></div>
                                  <div><label className="block text-[10px] uppercase text-muted-foreground font-semibold mb-1">Encargos Trab.</label><p className="text-sm text-card-foreground font-medium">{mForm.teve_encargo_trabalhista ? "Sim" : "Não"}</p></div>
                                  <div><label className="block text-[10px] uppercase text-primary font-bold mb-1">Valor Total Calculado</label><p className="text-lg text-primary font-bold">{formatCurrency(mForm.valor_total)}</p></div>
                                </div>

                                {mForm.detalhes_calculo && mForm.detalhes_calculo.length > 0 && (
                                  <div className="bg-muted/10 border border-border rounded-lg p-4">
                                    <h4 className="text-xs font-bold uppercase text-muted-foreground mb-3 flex items-center gap-2">
                                      <DollarSign size={14} /> Detalhamento do Cálculo
                                    </h4>
                                    <div className="space-y-2">
                                      <div className="grid grid-cols-4 text-[10px] font-bold text-muted-foreground uppercase border-b border-border pb-1">
                                        <div className="col-span-2">Descrição</div>
                                        <div className="text-right">Qtd x Valor</div>
                                        <div className="text-right">Total</div>
                                      </div>
                                      {mForm.detalhes_calculo.map((det: any, idx: number) => (
                                        <div key={idx} className="grid grid-cols-4 text-xs items-center py-1">
                                          <div className="col-span-2 font-medium text-card-foreground line-clamp-1" title={det.rotulo}>{det.rotulo}</div>
                                          <div className="text-right text-muted-foreground">
                                            {det.qtd} x {formatCurrency(det.vlrUnit)}
                                          </div>
                                          <div className="text-right font-bold text-card-foreground">
                                            {formatCurrency(det.vlrTotal)}
                                          </div>
                                        </div>
                                      ))}
                                    </div>
                                  </div>
                                )}

                                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                  <div><label className={labelCls}>Data Vencimento</label><input type="date" value={mForm.data_vencimento || ""} onChange={e => updateMensalForm(emp.id, "data_vencimento", e.target.value)} className={inputCls} /></div>
                                  <div><label className={labelCls}>Data Envio</label><input type="date" value={mForm.data_envio || ""} onChange={e => updateMensalForm(emp.id, "data_envio", e.target.value)} className={inputCls} /></div>
                                  <div><label className={labelCls}>Forma Envio</label><input type="text" value={mForm.forma_envio || ""} onChange={e => updateMensalForm(emp.id, "forma_envio", e.target.value)} className={inputCls} placeholder="Ex: WhatsApp, Email" /></div>
                                </div>
                                <div className="grid grid-cols-1 md:grid-cols-3 gap-4 items-center">
                                  <div><label className={labelCls}>Status</label><select value={mForm.status || "pendente"} onChange={e => updateMensalForm(emp.id, "status", e.target.value)} className={inputCls}><option value="pendente">Pendente</option><option value="gerada">Gerada</option><option value="enviada">Enviada</option></select></div>
                                  <div className="flex items-center gap-2 pt-4"><input type="checkbox" id={`pago-${emp.id}`} checked={mForm.pago || false} onChange={e => updateMensalForm(emp.id, "pago", e.target.checked)} className="w-4 h-4 rounded text-primary border-border" /><label htmlFor={`pago-${emp.id}`} className="text-sm font-medium text-card-foreground cursor-pointer">Honorário Pago</label></div>
                                  <div><label className={labelCls}>Valor Ajustado Manualmente</label><div className="relative"><span className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground text-sm">R$</span><input type="number" step="0.01" value={mForm.valor_total || ""} onChange={e => updateMensalForm(emp.id, "valor_total", parseFloat(e.target.value) || 0)} className={`${inputCls} pl-9`} /></div></div>
                                </div>
                                <div><label className={labelCls}>Observações</label><textarea value={mForm.observacoes || ""} onChange={e => updateMensalForm(emp.id, "observacoes", e.target.value)} className={`${inputCls} min-h-[80px] resize-y`} placeholder="Observações..." /></div>
                                <div className="flex justify-end pt-2"><button onClick={() => handleSaveMensal(emp.id)} className="flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold text-primary-foreground shadow-md" style={{ background: "var(--gradient-primary)" }}><Save size={16} /> Salvar Mês</button></div>
                              </div>
                            )}

                            {hasMensalRecords && !mForm ? (
                              <div className="overflow-x-auto rounded-lg border border-border">
                                <table className="w-full text-sm text-left">
                                  <thead className="bg-muted/50 text-xs uppercase text-muted-foreground"><tr><th className="px-4 py-3 font-medium">Competência</th><th className="px-4 py-3 font-medium">Valor Total</th><th className="px-4 py-3 font-medium">Vencimento</th><th className="px-4 py-3 font-medium">Status / Pago</th><th className="px-4 py-3 font-medium text-right">Ações</th></tr></thead>
                                  <tbody className="divide-y divide-border bg-background">
                                    {mensalData[emp.id].map((record: any) => (
                                      <tr key={record.id} className="hover:bg-muted/20 transition-colors">
                                        <td className="px-4 py-3 font-medium text-card-foreground">{record.competencia}</td>
                                        <td className="px-4 py-3 text-primary font-semibold">{formatCurrency(record.valor_total)}</td>
                                        <td className="px-4 py-3 text-muted-foreground">{record.data_vencimento ? format(new Date(record.data_vencimento), 'dd/MM/yyyy') : '—'}</td>
                                        <td className="px-4 py-3">
                                          <div className="flex items-center gap-2">
                                            <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-wider ${record.status === "enviada" ? "bg-success/10 text-success" : record.status === "gerada" ? "bg-primary/10 text-primary" : "bg-warning/10 text-warning"}`}>{record.status}</span>
                                            {record.pago ? <span className="px-2 py-0.5 rounded-full text-[10px] font-bold tracking-wider bg-success/10 text-success border border-success/20">PAGO</span> : <span className="px-2 py-0.5 rounded-full text-[10px] font-bold tracking-wider text-muted-foreground border border-border">PENDENTE</span>}
                                          </div>
                                        </td>
                                        <td className="px-4 py-3 text-right"><button onClick={() => startEditMensal(emp.id, record)} className="text-primary hover:underline text-xs font-medium">Editar</button></td>
                                      </tr>
                                    ))}
                                  </tbody>
                                </table>
                              </div>
                            ) : !mForm ? <div className="text-center py-6 text-muted-foreground text-sm border border-dashed border-border rounded-lg">Nenhum controle mensal registrado para esta empresa.</div> : null}
                          </div>
                        )}
                      </div>
                    </div>
                  )}
                </div>
              );
            })}
            {filtered.length === 0 && <div className="text-center py-12 text-muted-foreground module-card">Nenhuma empresa encontrada com "{(search)}"</div>}
          </div>
        </div>
      )}
    </div>
  );
};

export default HonorariosPage;

import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import {
  Search, Building2, ChevronDown, ChevronUp,
  Shield, CheckCircle, Clock, AlertTriangle, Save,
  Upload, Eye, FileText
} from "lucide-react";
import { toast } from "sonner";
import { useEmpresas } from "@/hooks/useEmpresas";

const licencaLabels: Record<string, string> = {
  alvara: "Alvará de Funcionamento",
  vigilancia_sanitaria: "Vigilância Sanitária",
  corpo_bombeiros: "Corpo de Bombeiros",
  meio_ambiente: "Meio Ambiente"
};

const tipoStatusLabels: Record<string, { label: string; cls: string }> = {
  definitiva: { label: "Definitiva", cls: "badge-success" },
  dispensada: { label: "Dispensada", cls: "badge-gray" },
  com_vencimento: { label: "Com Vencimento", cls: "badge-warning" },
  em_processo: { label: "Em Processo", cls: "badge-info" },
};

const calcDias = (data?: string | null) => {
  if (!data) return 999;
  return Math.ceil((new Date(data).getTime() - Date.now()) / 86400000);
};

type TabType = "licencas" | "taxas";

const LicencasPage: React.FC = () => {
  const { empresas, loading } = useEmpresas("licencas");
  const [licencas, setLicencas] = useState<any[]>([]);
  const [taxas, setTaxas] = useState<any[]>([]);

  const [search, setSearch] = useState("");
  const [filterStatus, setFilterStatus] = useState("todos");
  const [expanded, setExpanded] = useState<string | null>(null);

  const [activeTab, setActiveTab] = useState<TabType>("licencas");
  const [activeStatusTab, setActiveStatusTab] = useState<"ativas" | "mei" | "paralisadas" | "baixadas">("ativas");
  const [competencia, setCompetencia] = useState(new Date().toISOString().slice(0, 7));
  const [taxasForm, setTaxasForm] = useState<Record<string, Record<string, any>>>({});

  const loadBaseData = async () => {
    const { data: lics } = await supabase.from("licencas").select("*");
    setLicencas(lics || []);
  };

  const loadTaxas = async () => {
    const { data } = await supabase.from("licencas_taxas").select("*").eq("competencia", competencia);
    setTaxas(data || []);

    // Auto-populate edit form with fetched data
    const map: Record<string, Record<string, any>> = {};
    data?.forEach(t => {
      if (!map[t.empresa_id]) map[t.empresa_id] = {};
      map[t.empresa_id][t.tipo_licenca] = {
        id: t.id,
        status: t.status,
        data_envio: t.data_envio,
        forma_envio: t.forma_envio,
        data_vencimento: t.data_vencimento
      };
    });
    setTaxasForm(map);
  };

  useEffect(() => { loadBaseData(); }, []);
  useEffect(() => { if (activeTab === "taxas") loadTaxas(); }, [competencia, activeTab]);

  const licByEmpresa = (empId: string) => licencas.filter(l => l.empresa_id === empId);

  // Filters for Licencas Tab
  const filteredLicencas = empresas.filter(e => {
    const matchSearch = e.nome_empresa?.toLowerCase().includes(search.toLowerCase()) || e.cnpj?.includes(search);
    const matchStatus = filterStatus === "todos" || licByEmpresa(e.id).some((l: any) => l.status === filterStatus);

    let matchTab = false;
    if (activeStatusTab === "ativas") {
      matchTab = (!e.situacao || e.situacao === "ativa") && e.porte_empresa !== "mei";
    } else if (activeStatusTab === "mei") {
      matchTab = (!e.situacao || e.situacao === "ativa") && e.porte_empresa === "mei";
    } else if (activeStatusTab === "paralisadas") {
      matchTab = e.situacao === "paralisada";
    } else if (activeStatusTab === "baixadas") {
      matchTab = e.situacao === "baixada";
    }

    return matchSearch && matchStatus && matchTab;
  });

  // Filters for Taxas Tab (Shows only companies that have at least one valid license)
  const filteredTaxas = empresas.filter(e => {
    const matchSearch = e.nome_empresa?.toLowerCase().includes(search.toLowerCase()) || e.cnpj?.includes(search);
    const hasAnyLicence = licByEmpresa(e.id).length > 0;

    let matchTab = false;
    if (activeStatusTab === "ativas") {
      matchTab = (!e.situacao || e.situacao === "ativa") && e.porte_empresa !== "mei";
    } else if (activeStatusTab === "mei") {
      matchTab = (!e.situacao || e.situacao === "ativa") && e.porte_empresa === "mei";
    } else if (activeStatusTab === "paralisadas") {
      matchTab = e.situacao === "paralisada";
    } else if (activeStatusTab === "baixadas") {
      matchTab = e.situacao === "baixada";
    }

    return matchSearch && hasAnyLicence && matchTab;
  });

  const counts = {
    definitiva: licencas.filter(l => l.status === "definitiva").length,
    dispensada: licencas.filter(l => l.status === "dispensada").length,
    com_vencimento: licencas.filter(l => l.status === "com_vencimento").length,
    em_processo: licencas.filter(l => l.status === "em_processo").length
  };

  // --- Handlers for Taxas Tab ---
  const handleTaxaChange = (empresaId: string, tipoLicenca: string, field: string, value: any) => {
    setTaxasForm(prev => {
      const empData = prev[empresaId] || {};
      const licData = empData[tipoLicenca] || { status: 'pendente', data_envio: '', forma_envio: '' };
      return {
        ...prev,
        [empresaId]: {
          ...empData,
          [tipoLicenca]: { ...licData, [field]: value }
        }
      }
    });
  };

  const saveTaxas = async (empresaId: string) => {
    const empTaxas = taxasForm[empresaId];
    if (!empTaxas) return;

    try {
      const promises = Object.keys(licencaLabels).map(async (tipoLicenca) => {
        const data = empTaxas[tipoLicenca];
        if (!data) return; // Only save those modified/existing in form state

        const payload = {
          empresa_id: empresaId,
          tipo_licenca: tipoLicenca,
          competencia,
          status: data.status || 'pendente',
          data_envio: data.data_envio || null,
          forma_envio: data.forma_envio || null,
          data_vencimento: data.data_vencimento || null
        };

        if (data.id) {
          return supabase.from("licencas_taxas").update(payload).eq("id", data.id);
        } else {
          return supabase.from("licencas_taxas").insert(payload);
        }
      });

      await Promise.all(promises);
      toast.success("Taxas atualizadas com sucesso!");
      loadTaxas(); // Reload to get newly inserted IDs
    } catch (err: any) {
      toast.error(err.message || "Erro ao salvar as taxas.");
    }
  };

  const inputCls = "w-full px-3 py-1.5 border border-border rounded-md bg-background text-foreground text-xs focus:ring-1 focus:ring-primary outline-none";
  const labelCls = "block text-[11px] font-semibold text-muted-foreground mb-1 uppercase tracking-wider";

  if (loading) {
    return <div className="flex items-center justify-center h-64"><div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>;
  }

  return (
    <div className="space-y-6 animate-fade-in">


      {/* Tabs */}
      <div className="flex border-b border-border">
        <button
          onClick={() => { setActiveTab("licencas"); setExpanded(null); }}
          className={`pb-3 px-4 text-sm font-semibold transition-colors border-b-2 ${activeTab === "licencas" ? "border-primary text-primary" : "border-transparent text-muted-foreground hover:text-foreground"}`}
        >
          Status das Licenças
        </button>
        <button
          onClick={() => { setActiveTab("taxas"); setExpanded(null); }}
          className={`pb-3 px-4 text-sm font-semibold transition-colors border-b-2 ${activeTab === "taxas" ? "border-primary text-primary" : "border-transparent text-muted-foreground hover:text-foreground"}`}
        >
          Taxas das Licenças
        </button>
      </div>

      {/* Status Tabs */}
      <div className="flex border-b border-border overflow-x-auto no-scrollbar pt-2">
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeStatusTab === "ativas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveStatusTab("ativas")}
        >
          Empresas Ativas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeStatusTab === "mei"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveStatusTab("mei")}
        >
          Empresas MEI
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeStatusTab === "paralisadas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveStatusTab("paralisadas")}
        >
          Empresas Paralisadas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeStatusTab === "baixadas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveStatusTab("baixadas")}
        >
          Empresas Baixadas
        </button>
      </div>

      {activeTab === "licencas" && (
        <div className="space-y-6 animate-fade-in">
          <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
            {[{ label: "Definitivas", count: counts.definitiva, cls: "text-success", bg: "bg-success/10", icon: <CheckCircle size={20} /> }, { label: "Com Vencimento", count: counts.com_vencimento, cls: "text-warning", bg: "bg-warning/10", icon: <Clock size={20} /> }, { label: "Em Processo", count: counts.em_processo, cls: "text-primary", bg: "bg-primary/10", icon: <Shield size={20} /> }, { label: "Dispensadas", count: counts.dispensada, cls: "text-muted-foreground", bg: "bg-muted", icon: <AlertTriangle size={20} /> }].map(s => (
              <div key={s.label} className="stat-card flex items-center justify-between"><div><p className="text-xs text-muted-foreground uppercase tracking-wide">{s.label}</p><p className={`text-2xl font-bold mt-1 ${s.cls}`}>{s.count}</p></div><div className={`w-10 h-10 rounded-xl flex items-center justify-center ${s.bg} ${s.cls}`}>{s.icon}</div></div>
            ))}
          </div>
          <div className="flex flex-col sm:flex-row gap-3">
            <div className="relative flex-1 max-w-sm"><Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" /><input type="text" placeholder="Buscar empresa..." value={search} onChange={e => setSearch(e.target.value)} className="w-full pl-9 pr-4 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" /></div>
            <div className="flex gap-2 flex-wrap">
              {[{ key: "todos", label: "Todos" }, { key: "definitiva", label: "Definitivas" }, { key: "com_vencimento", label: "Com Vencimento" }, { key: "em_processo", label: "Em Processo" }, { key: "dispensada", label: "Dispensadas" }].map(f => (
                <button key={f.key} onClick={() => setFilterStatus(f.key)} className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-colors ${filterStatus === f.key ? "bg-primary text-primary-foreground" : "bg-muted text-muted-foreground hover:text-foreground"}`}>{f.label}</button>
              ))}
            </div>
          </div>
          <div className="space-y-3">
            {filteredLicencas.length === 0 ? <div className="module-card text-center py-12 text-muted-foreground">Nenhuma empresa encontrada</div> : filteredLicencas.map(emp => {
              const isOpen = expanded === emp.id;
              const empLicencas = licByEmpresa(emp.id);
              return (
                <div key={emp.id} className="module-card !p-0 overflow-hidden">
                  <div className="flex items-center justify-between p-4 cursor-pointer hover:bg-muted/30 transition-colors" onClick={() => setExpanded(isOpen ? null : emp.id)}>
                    <div className="flex items-center gap-3"><div className="w-9 h-9 rounded-lg bg-primary/10 flex items-center justify-center"><Building2 size={16} className="text-primary" /></div><div><p className="font-medium text-card-foreground">{emp.nome_empresa}</p><p className="text-xs text-muted-foreground">{emp.cnpj || "—"}</p></div></div>
                    <div className="flex items-center gap-2">{empLicencas.map((l: any, i: number) => { const cfg = tipoStatusLabels[l.status] || { label: "—", cls: "badge-gray" }; return <span key={i} className={`badge-status ${cfg.cls} text-[10px]`}>{cfg.label}</span>; })}{isOpen ? <ChevronUp size={16} className="text-muted-foreground" /> : <ChevronDown size={16} className="text-muted-foreground" />}</div>
                  </div>
                  {isOpen && (
                    <div className="border-t border-border p-5 bg-muted/10">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {Object.entries(licencaLabels).map(([key, label]) => {
                          const lic = empLicencas.find((l: any) => l.tipo_licenca === key);
                          const cfg = lic ? tipoStatusLabels[lic.status] || { label: "Não definido", cls: "badge-gray" } : { label: "Não definido", cls: "badge-gray" };
                          const dias = lic?.status === "com_vencimento" ? calcDias(lic.vencimento) : null;
                          return (
                            <div key={key} className="p-4 rounded-xl border border-border bg-card">
                              <div className="flex items-center justify-between mb-2">
                                <h4 className="text-sm font-semibold text-card-foreground">{label}</h4>
                                <div className="flex items-center gap-2">
                                  <span className={`badge-status ${cfg.cls}`}>{cfg.label}</span>
                                  {lic?.file_url ? (
                                    <button
                                      onClick={() => window.open(lic.file_url, "_blank")}
                                      className="p-1.5 rounded-lg bg-primary/10 text-primary hover:bg-primary/20 transition-all"
                                      title="Visualizar anexo"
                                    >
                                      <Eye size={14} />
                                    </button>
                                  ) : (
                                    <div className="relative">
                                      <input
                                        type="file"
                                        accept=".pdf"
                                        className="hidden"
                                        id={`upload-${emp.id}-${key}`}
                                        onChange={async (e) => {
                                          const file = e.target.files?.[0];
                                          if (!file) return;

                                          toast.loading("Enviando...", { id: "up-lic" });
                                          const path = `licencas/${emp.id}/${key}_${Date.now()}.pdf`;

                                          const { error: upErr } = await supabase.storage.from("documentos").upload(path, file);
                                          if (upErr) {
                                            toast.error("Erro: " + upErr.message, { id: "up-lic" });
                                            return;
                                          }

                                          const { data: { publicUrl } } = supabase.storage.from("documentos").getPublicUrl(path);

                                          // Update database
                                          const { error: dbErr } = await supabase.from("licencas")
                                            .update({ file_url: publicUrl })
                                            .eq("empresa_id", emp.id)
                                            .eq("tipo_licenca", key);

                                          if (dbErr) {
                                            toast.error("Erro DB: " + dbErr.message, { id: "up-lic" });
                                          } else {
                                            toast.success("Anexo salvo!", { id: "up-lic" });
                                            loadBaseData();
                                          }
                                        }}
                                      />
                                      <label
                                        htmlFor={`upload-${emp.id}-${key}`}
                                        className="p-1.5 rounded-lg bg-muted hover:bg-muted/80 text-muted-foreground cursor-pointer transition-all flex items-center justify-center"
                                        title="Anexar PDF"
                                      >
                                        <Upload size={14} />
                                      </label>
                                    </div>
                                  )}
                                </div>
                              </div>
                              {lic?.status === "com_vencimento" && lic.vencimento && <div className="text-xs text-muted-foreground">Vencimento: {new Date(lic.vencimento).toLocaleDateString("pt-BR")}{dias !== null && <span className={`ml-2 font-medium ${dias < 0 ? "text-destructive" : dias <= 30 ? "text-warning" : "text-success"}`}>({dias}d)</span>}</div>}
                              {lic?.status === "em_processo" && lic.numero_processo && <div className="text-xs text-muted-foreground">Processo: {lic.numero_processo}</div>}
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      )}

      {activeTab === "taxas" && (
        <div className="space-y-6 animate-fade-in">
          <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
            <div className="relative max-w-sm w-full">
              <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
              <input type="text" placeholder="Buscar empresa..." value={search} onChange={e => setSearch(e.target.value)} className="w-full pl-9 pr-4 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
            </div>
            <div className="flex items-center gap-2">
              <span className="text-sm font-semibold text-muted-foreground">Competência:</span>
              <input type="month" value={competencia} onChange={e => setCompetencia(e.target.value)} className="px-4 py-2 border border-border rounded-lg bg-background text-foreground font-semibold text-sm outline-none focus:ring-2 focus:ring-primary" />
            </div>
          </div>

          <div className="space-y-3">
            {filteredTaxas.length === 0 ? <div className="module-card text-center py-12 text-muted-foreground">Nenhuma empresa com licenças encontradas</div> : filteredTaxas.map(emp => {
              const isOpen = expanded === emp.id;
              const empLicencas = licByEmpresa(emp.id);
              return (
                <div key={emp.id} className="module-card !p-0 overflow-hidden">
                  <div className="flex items-center justify-between p-4 cursor-pointer hover:bg-muted/30 transition-colors" onClick={() => setExpanded(isOpen ? null : emp.id)}>
                    <div className="flex items-center gap-3">
                      <div className="w-9 h-9 rounded-lg bg-primary/10 flex items-center justify-center"><Building2 size={16} className="text-primary" /></div>
                      <div>
                        <p className="font-semibold text-card-foreground">{emp.nome_empresa}</p>
                        <p className="text-xs text-muted-foreground">{emp.cnpj || "—"} • {empLicencas.length} Licença(s)</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-2">
                      {isOpen ? <ChevronUp size={16} className="text-muted-foreground" /> : <ChevronDown size={16} className="text-muted-foreground" />}
                    </div>
                  </div>

                  {isOpen && (
                    <div className="border-t border-border p-5 bg-muted/10 space-y-4">
                      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
                        {Object.entries(licencaLabels).map(([key, label]) => {
                          const lic = empLicencas.find((l: any) => l.tipo_licenca === key);
                          if (!lic) return null; // Only show taxes blocks for licenses they actually have

                          const taxaData = (taxasForm[emp.id] && taxasForm[emp.id][key]) || { status: 'pendente', data_envio: '', forma_envio: '' };

                          return (
                            <div key={key} className="p-4 rounded-xl border border-border bg-card flex flex-col gap-3">
                              <h4 className="text-sm font-bold text-primary flex items-center gap-2">
                                <Shield size={14} /> {label}
                              </h4>

                              <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
                                <div>
                                  <label className={labelCls}>Status Atual</label>
                                  <select
                                    className={inputCls}
                                    value={taxaData.status}
                                    onChange={(e) => handleTaxaChange(emp.id, key, 'status', e.target.value)}
                                  >
                                    <option value="pendente">Pendente</option>
                                    <option value="gerada">Gerada</option>
                                    <option value="enviada">Enviada</option>
                                  </select>
                                </div>
                                <div>
                                  <label className={labelCls}>Vencimento</label>
                                  <input
                                    type="date"
                                    className={inputCls}
                                    value={taxaData.data_vencimento || ''}
                                    onChange={(e) => handleTaxaChange(emp.id, key, 'data_vencimento', e.target.value)}
                                  />
                                </div>
                                <div>
                                  <label className={labelCls}>Data do Envio</label>
                                  <input
                                    type="date"
                                    className={inputCls}
                                    value={taxaData.data_envio || ''}
                                    onChange={(e) => handleTaxaChange(emp.id, key, 'data_envio', e.target.value)}
                                  />
                                </div>
                                <div>
                                  <label className={labelCls}>Envio</label>
                                  <input
                                    type="text"
                                    placeholder="Ex: WhatsApp"
                                    className={inputCls}
                                    value={taxaData.forma_envio || ''}
                                    onChange={(e) => handleTaxaChange(emp.id, key, 'forma_envio', e.target.value)}
                                  />
                                </div>
                              </div>
                            </div>
                          );
                        })}
                      </div>

                      <div className="flex justify-end pt-2 border-t border-border/50">
                        <button
                          onClick={() => saveTaxas(emp.id)}
                          className="flex items-center gap-2 px-5 py-2 rounded-lg text-sm font-semibold text-primary-foreground shadow-md transition-all hover:opacity-90 active:scale-95"
                          style={{ background: "var(--gradient-primary)" }}
                        >
                          <Save size={16} /> Salvar Taxas deste Mês
                        </button>
                      </div>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
};

export default LicencasPage;

import React, { useState } from "react";
import { useAuth } from "@/contexts/AuthContext";
import { Link, Navigate } from "react-router-dom";
import { Loader2 } from "lucide-react";
import logoAudipreve from "@/assets/logo-audipreve.png";

const LoginPage: React.FC = () => {
  const { user, loading, login } = useAuth();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [submitting, setSubmitting] = useState(false);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <img src={logoAudipreve} alt="Audipreve" className="w-20 h-20 object-contain mx-auto mb-4" />
          <Loader2 className="animate-spin mx-auto text-primary" size={24} />
          <p className="text-muted-foreground mt-3 text-sm">Carregando sistema...</p>
        </div>
      </div>
    );
  }

  if (user) return <Navigate to="/dashboard" replace />;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setSubmitting(true);
    try {
      await login(email, password);
    } catch (err: any) {
      setError(
        err.message === "Invalid login credentials" ? "Email ou senha inválidos" : err.message || "Erro ao fazer login",
      );
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-4">
      <div className="bg-card rounded-2xl shadow-xl w-full max-w-md overflow-hidden border border-border">
        <div className="p-8">
          <div className="text-center mb-8">
            <img src={logoAudipreve} alt="Audipreve" className="w-24 h-24 object-contain mx-auto mb-4" />
          </div>

          <form onSubmit={handleSubmit} className="space-y-5">
            <div>
              <label className="block text-sm font-medium text-card-foreground mb-1.5">Email</label>
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
                className="w-full px-4 py-3 border border-border rounded-lg bg-background text-foreground focus:ring-2 focus:ring-primary focus:border-primary outline-none transition-all"
                placeholder="seu@email.com"
              />
            </div>
            <div>
              <div className="space-y-1">
                <label className="text-sm font-semibold text-muted-foreground ml-1">Senha</label>
                <input
                  type="password"
                  placeholder="Sua senha"
                  className="w-full pl-4 pr-10 py-3 rounded-xl border border-border bg-background focus:ring-2 focus:ring-primary outline-none transition-all"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  required
                />
                <div className="flex justify-end pr-1">
                  <Link to="/esqueci-senha" title="Esqueci minha senha" className="text-xs font-medium text-primary hover:underline">
                    Esqueci minha senha
                  </Link>
                </div>
              </div>
            </div>
            {error && (
              <div className="p-3 bg-destructive/10 border border-destructive/20 rounded-lg">
                <p className="text-sm text-destructive">{error}</p>
              </div>
            )}
            <button
              type="submit"
              disabled={submitting}
              className="w-full py-3 rounded-lg font-semibold text-primary-foreground transition-all shadow-lg hover:shadow-xl disabled:opacity-50"
              style={{ background: "var(--gradient-primary)" }}
            >
              {submitting ? <Loader2 className="animate-spin mx-auto" size={20} /> : "Entrar no Sistema"}
            </button>
          </form>
          <p className="text-xs text-muted-foreground text-center mt-6">
            Entre em contato com o administrador para criar uma conta
          </p>
        </div>
        <div className="bg-muted/50 px-8 py-3 border-t border-border">
          <p className="text-xs text-muted-foreground text-center">© 2026 Audipreve Contabilidade. Todos os direitos reservados.</p>
        </div>
      </div>
    </div>
  );
};

export default LoginPage;

import React, { useState, useEffect } from "react";
import { useAuth } from "@/contexts/AuthContext";
import { supabase } from "@/integrations/supabase/client";
import {
    Send, User, Search, Filter,
    CheckCheck, Clock, MessageSquare
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { toast } from "sonner";

interface Message {
    id: string;
    sender_id: string;
    recipient_id: string;
    subject: string;
    content: string;
    created_at: string;
    read_at: string | null;
}

const MessagesPage: React.FC = () => {
    const { user, userData } = useAuth();
    const [messages, setMessages] = useState<Message[]>([]);
    const [loading, setLoading] = useState(true);
    const [newMessage, setNewMessage] = useState("");
    const [search, setSearch] = useState("");

    const fetchMessages = async () => {
        if (!user) return;
        setLoading(true);
        const { data, error } = await supabase
            .from("internal_messages" as any)
            .select("*")
            .or(`sender_id.eq.${user.id},recipient_id.eq.${user.id}`)
            .order("created_at", { ascending: false });

        if (error) {
            console.error("Error fetching messages:", error);
        } else {
            setMessages(data as unknown as Message[]);
        }
        setLoading(false);
    };

    useEffect(() => {
        fetchMessages();

        const channel = supabase
            .channel("messages_changes")
            .on(
                "postgres_changes",
                { event: "INSERT", schema: "public", table: "internal_messages" },
                () => fetchMessages()
            )
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    }, [user]);

    const handleSendMessage = async () => {
        if (!user || !newMessage.trim()) return;

        // For now, if client sends message, it goes to "admin" (placeholder)
        // If admin sends, it should pick a recipient. 
        // In this simplified version, we'll send to a fixed internal ID or just broadcast.
        const { error } = await supabase.from("internal_messages" as any).insert([
            {
                sender_id: user.id,
                recipient_id: userData?.isAdmin ? null : null, // Will be handled by admin response or fixed admin id
                empresa_id: userData?.empresaId,
                content: newMessage,
                subject: "Suporte",
                direcao: userData?.isAdmin ? "escritorio_para_cliente" : "cliente_para_escritorio"
            },
        ]);

        if (error) {
            toast.error("Erro ao enviar mensagem: " + error.message);
        } else {
            setNewMessage("");
            toast.success("Mensagem enviada!");
            fetchMessages();
        }
    };

    return (
        <div className="h-[calc(100vh-12rem)] flex flex-col gap-6 animate-fade-in">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold tracking-tight flex items-center gap-2">
                        <MessageSquare className="text-primary" /> Central de Mensagens
                    </h1>
                    <p className="text-muted-foreground text-sm">
                        Comunicação direta entre você e o escritório Audipreve.
                    </p>
                </div>
            </div>

            <div className="flex-1 grid grid-cols-1 lg:grid-cols-4 gap-6 overflow-hidden">
                {/* Sidebar - Conversas/Filtros */}
                <div className="lg:col-span-1 space-y-4">
                    <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" size={16} />
                        <Input
                            placeholder="Buscar mensagens..."
                            className="pl-9"
                            value={search}
                            onChange={(e) => setSearch(e.target.value)}
                        />
                    </div>
                    <div className="space-y-1">
                        <Button variant="ghost" className="w-full justify-start font-bold bg-primary/10 text-primary">
                            <MessageSquare size={18} className="mr-2" /> Todas as Mensagens
                        </Button>
                        <Button variant="ghost" className="w-full justify-start text-muted-foreground">
                            <Clock size={18} className="mr-2" /> Não Lidas
                        </Button>
                    </div>
                </div>

                {/* Chat Area */}
                <div className="lg:col-span-3 flex flex-col bg-card rounded-3xl border border-border overflow-hidden shadow-sm">
                    {/* Messages List */}
                    <div className="flex-1 overflow-y-auto p-6 space-y-6">
                        {loading ? (
                            <div className="flex items-center justify-center h-full text-muted-foreground">
                                <p className="animate-pulse">Carregando mensagens...</p>
                            </div>
                        ) : messages.length === 0 ? (
                            <div className="flex flex-col items-center justify-center h-full text-muted-foreground gap-4">
                                <div className="w-16 h-16 rounded-full bg-muted flex items-center justify-center">
                                    <MessageSquare size={32} />
                                </div>
                                <p>Nenhuma mensagem trocada ainda.</p>
                            </div>
                        ) : (
                            messages.map((msg) => {
                                const isMine = msg.sender_id === user?.id;
                                return (
                                    <div key={msg.id} className={`flex ${isMine ? "justify-end" : "justify-start"}`}>
                                        <div className={`max-w-[80%] flex items-end gap-2 ${isMine ? "flex-row-reverse" : "flex-row"}`}>
                                            <div className={`w-8 h-8 rounded-full bg-muted flex items-center justify-center flex-shrink-0`}>
                                                <User size={16} />
                                            </div>
                                            <div className={`p-4 rounded-2xl text-sm ${isMine
                                                ? "bg-primary text-primary-foreground rounded-br-none"
                                                : "bg-muted text-foreground rounded-bl-none"
                                                }`}>
                                                <p>{msg.content}</p>
                                                <div className={`flex items-center gap-1 mt-2 text-[10px] ${isMine ? "text-primary-foreground/70 justify-end" : "text-muted-foreground"}`}>
                                                    {new Date(msg.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                                    {isMine && (msg.read_at ? <CheckCheck size={12} /> : <CheckCheck size={12} className="opacity-50" />)}
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                );
                            })
                        )}
                    </div>

                    {/* Input Area */}
                    <div className="p-4 border-t border-border bg-card/50">
                        <div className="flex items-center gap-2">
                            <Input
                                placeholder="Digite sua mensagem..."
                                className="flex-1 rounded-2xl"
                                value={newMessage}
                                onChange={(e) => setNewMessage(e.target.value)}
                                onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                            />
                            <Button
                                onClick={handleSendMessage}
                                disabled={!newMessage.trim()}
                                className="rounded-2xl w-12 h-12 p-0 flex items-center justify-center"
                            >
                                <Send size={20} />
                            </Button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default MessagesPage;

import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import { FileText, Download, Building2, User, Search, Plus, Trash2, Calendar, History as HistoryIcon, Settings2, Upload, Image as ImageIcon } from "lucide-react";
import { jsPDF } from "jspdf";
import "jspdf-autotable";
import logoCaduceu from "@/assets/logo-caduceu.png";
import { UbuntuRegular, UbuntuBold } from "@/lib/fonts/ubuntu-base64";

interface HeaderConfig {
    logoUrl: string;
    title: string;
    subtitle: string;
    address: string;
    contact: string;
    titleFontSize: number;
    subtitleFontSize: number;
    infoFontSize: number;
    logoWidth: number;
    logoHeight: number;
    logoX: number;
    logoY: number;
}

const DEFAULT_HEADER: HeaderConfig = {
    logoUrl: "", // Use asset by default if empty
    title: "Audipreve Contabilidade",
    subtitle: "CRC-PR nº. 01.0093/O - 6",
    address: "Rua Jequitibá, n.º 789, 1º andar, sala 01, Bairro Nações, CEP 83823-004,",
    contact: "Fazenda Rio Grande/PR. Fone: (41) 3604-8059 | E-mail: societario@audiprevecontabilidade.com.br",
    titleFontSize: 22,
    subtitleFontSize: 10,
    infoFontSize: 8,
    logoWidth: 20,
    logoHeight: 20,
    logoX: 20,
    logoY: 10
};

interface Empresa {
    id: string;
    nome_empresa: string;
    cnpj: string | null;
    socios?: any[];
}

interface Ocorrencia {
    id: string;
    empresa_id: string;
    departamento: string;
    descricao: string;
    cidade: string;
    estado: string;
    data_ocorrencia: string;
    created_at: string;
    empresas: {
        nome_empresa: string;
        cnpj: string | null;
    };
}

const DEPARTAMENTOS = [
    "Societário",
    "Fiscal",
    "Pessoal",
    "Contábil",
    "Financeiro",
    "Administrativo"
];

const OcorrenciasPage: React.FC = () => {
    const { userData } = useAuth();
    const [empresas, setEmpresas] = useState<Empresa[]>([]);
    const [ocorrencias, setOcorrencias] = useState<Ocorrencia[]>([]);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [activeTab, setActiveTab] = useState<"geral" | "config">("geral");
    const [headerConfig, setHeaderConfig] = useState<HeaderConfig>(DEFAULT_HEADER);
    const [savingConfig, setSavingConfig] = useState(false);
    const [uploadingLogo, setUploadingLogo] = useState(false);

    // Form state
    const [selectedEmpresaId, setSelectedEmpresaId] = useState("");
    const [selectedDepto, setSelectedDepto] = useState("");
    const [descricao, setDescricao] = useState("");
    const [cidade, setCidade] = useState("Fazenda Rio Grande");
    const [estado, setEstado] = useState("PR");
    const [dataOcorrencia, setDataOcorrencia] = useState(new Date().toISOString().split('T')[0]);

    const fetchInitialData = async () => {
        try {
            const { data: empData } = await supabase.from("empresas").select("id, nome_empresa, cnpj").order("nome_empresa");
            const { data: ocData } = await (supabase.from("ocorrencias") as any).select("*, empresas(nome_empresa, cnpj)").order("created_at", { ascending: false });
            const { data: configData } = await supabase.from("app_config").select("value").eq("key", "pdf_header_config").maybeSingle();

            if (empData) setEmpresas(empData);
            if (ocData) setOcorrencias(ocData as any);
            if (configData?.value) {
                try {
                    setHeaderConfig(JSON.parse(configData.value));
                } catch (e) {
                    console.error("Erro ao parsear config:", e);
                }
            }
        } catch (error) {
            console.error("Erro ao carregar dados:", error);
            toast.error("Erro ao carregar dados");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchInitialData();
    }, []);

    const handleSave = async (generatePdf = false) => {
        if (!selectedEmpresaId || !selectedDepto || !descricao) {
            toast.error("Preencha todos os campos obrigatórios");
            return;
        }

        setSaving(true);
        try {
            const { data, error } = await (supabase.from("ocorrencias") as any).insert([
                {
                    empresa_id: selectedEmpresaId,
                    departamento: selectedDepto,
                    descricao,
                    cidade,
                    estado,
                    data_ocorrencia: dataOcorrencia,
                    usuario_id: userData?.userId
                }
            ]).select("*, empresas(nome_empresa, cnpj)").single();

            if (error) throw error;

            toast.success("Ocorrência registrada com sucesso!");
            setOcorrencias([data as any, ...ocorrencias]);

            if (generatePdf) {
                handleGeneratePdf(data as any);
            }

            // Reset form
            setSelectedEmpresaId("");
            setSelectedDepto("");
            setDescricao("");
        } catch (error: any) {
            toast.error("Erro ao salvar ocorrência: " + error.message);
        } finally {
            setSaving(false);
        }
    };

    const handleGeneratePdf = async (oc: Ocorrencia) => {
        const doc = new jsPDF();

        doc.addFileToVFS("Ubuntu-Regular.ttf", UbuntuRegular);
        doc.addFont("Ubuntu-Regular.ttf", "Ubuntu", "normal");
        doc.addFileToVFS("Ubuntu-Bold.ttf", UbuntuBold);
        doc.addFont("Ubuntu-Bold.ttf", "Ubuntu", "bold");

        const pageWidth = doc.internal.pageSize.getWidth();

        // Fetch Socio Administrador
        const { data: manager } = await supabase
            .from("socios")
            .select("nome, cpf")
            .eq("empresa_id", oc.empresa_id)
            .eq("administrador", true)
            .maybeSingle();

        // Fetch User Profile to get latest Name/CPF (avoiding stale context)
        const { data: profile } = await supabase
            .from("profiles")
            .select("nome_completo, cpf")
            .eq("user_id", userData?.userId)
            .maybeSingle();

        const usuarioNome = profile?.nome_completo || userData?.nome || "";
        const usuarioCPF = profile?.cpf || userData?.cpf || "";

        // Header - Logo and Text
        try {
            const logoToUse = headerConfig.logoUrl || logoCaduceu;

            // Safe image loading via DOM Image
            const imgData = await new Promise<HTMLImageElement | string>((resolve, reject) => {
                if (logoToUse.startsWith('data:')) {
                    resolve(logoToUse);
                } else {
                    const img = new Image();
                    if (logoToUse.startsWith('http')) {
                        img.crossOrigin = 'Anonymous';
                    }
                    img.onload = () => resolve(img);
                    img.onerror = () => reject(new Error("Image failed to load (CORS or Invalid URL)"));
                    img.src = logoToUse;
                }
            });

            let format = 'PNG';
            if (typeof imgData === 'string') {
                if (imgData.startsWith('data:image/jpeg') || imgData.startsWith('data:image/jpg')) format = 'JPEG';
                else if (imgData.startsWith('data:image/webp')) format = 'WEBP';
            }

            doc.addImage(imgData, format, headerConfig.logoX, headerConfig.logoY, headerConfig.logoWidth, headerConfig.logoHeight);
        } catch (e) {
            console.warn("Logo blocked by CORS or invalid. Generating PDF without custom logo.", e);
            if (headerConfig.logoUrl && headerConfig.logoUrl.startsWith('http')) {
                toast.error("O link da logo foi bloqueado por segurança (CORS). Por favor, baixe a imagem para o seu computador e faça o upload dela nas configurações.");
            }
            // Fallback to default if custom url failed
            try {
                if (headerConfig.logoUrl) {
                    doc.addImage(logoCaduceu, 'PNG', headerConfig.logoX, headerConfig.logoY, headerConfig.logoWidth, headerConfig.logoHeight);
                }
            } catch (fallbackError) {
                console.warn("Fallback logo failed", fallbackError);
            }
        }

        doc.setFont("Ubuntu", "bold");
        doc.setFontSize(headerConfig.titleFontSize);
        doc.text(headerConfig.title, pageWidth / 2 + 10, 20, { align: "center" });

        doc.setFontSize(headerConfig.subtitleFontSize);
        doc.setFont("Ubuntu", "normal");
        doc.text(headerConfig.subtitle, pageWidth / 2 + 10, 26, { align: "center" });

        doc.setFontSize(headerConfig.infoFontSize);
        doc.text(headerConfig.address, pageWidth / 2, 34, { align: "center" });
        doc.text(headerConfig.contact, pageWidth / 2, 38, { align: "center" });

        // Separator line
        doc.setDrawColor(0);
        doc.setLineWidth(0.5);
        doc.line(10, 42, pageWidth - 10, 42);

        // Title
        doc.setFontSize(14);
        doc.setFont("Ubuntu", "bold");
        doc.text("OCORRÊNCIA", pageWidth / 2, 55, { align: "center" });

        // Company Info
        doc.setFontSize(11);
        doc.text(`Empresa: ${oc.empresas.nome_empresa}`, 20, 70);
        doc.text(`CNPJ: ${oc.empresas.cnpj || "—"}`, 20, 76);

        // Occurrence text
        doc.setFont("Ubuntu", "normal"); // Utilizing custom Ubuntu font
        const splitDesc = doc.splitTextToSize(oc.descricao, pageWidth - 40);
        doc.text(splitDesc, 20, 90);

        const descHeight = splitDesc.length * 7;
        let lineY = 90 + descHeight + 10;


        // Date/Place
        const formattedDate = new Date(oc.data_ocorrencia).toLocaleDateString("pt-BR", { day: '2-digit', month: 'long', year: 'numeric' });
        doc.text(`${oc.cidade}/${oc.estado}, ${formattedDate}`, pageWidth - 20, lineY + 20, { align: "right" });

        // Signatures
        const sigY = lineY + 60;

        // Left side: Company/Admin
        doc.line(20, sigY, 100, sigY);
        doc.setFont("Ubuntu", "bold");
        doc.setFontSize(9);
        doc.text(oc.empresas.nome_empresa, 20, sigY + 5);
        doc.text(`CNPJ: ${oc.empresas.cnpj || ""}`, 20, sigY + 10);

        doc.text("Socio(a) Administrador(a)", 20, sigY + 18);
        doc.setFont("Ubuntu", "normal");
        doc.text(manager?.nome || "____________________________", 20, sigY + 23);
        const managerCPF = manager?.cpf ? `CPF: ${manager.cpf}` : "CPF: ________________________";
        doc.text(managerCPF, 20, sigY + 28);

        // Right side: User/Dept
        doc.line(pageWidth - 100, sigY, pageWidth - 20, sigY);
        doc.setFont("Ubuntu", "bold");
        doc.text(usuarioNome.toUpperCase(), pageWidth - 100, sigY + 5);
        doc.text(`CPF: ${usuarioCPF}`, pageWidth - 100, sigY + 10);
        doc.text(`Departamento: ${oc.departamento}`, pageWidth - 100, sigY + 15);

        doc.save(`Ocorrencia_${oc.empresas.nome_empresa.replace(/\s+/g, '_')}.pdf`);
    };

    const handleDelete = async (id: string) => {
        if (!window.confirm("Tem certeza que deseja excluir esta ocorrência?")) return;
        try {
            const { error } = await (supabase.from("ocorrencias") as any).delete().eq("id", id);
            if (error) throw error;
            setOcorrencias(ocorrencias.filter(o => o.id !== id));
            toast.success("Ocorrência excluída");
        } catch (error) {
            toast.error("Erro ao excluir");
        }
    };

    const saveHeaderConfig = async () => {
        setSavingConfig(true);
        try {
            const { error } = await supabase.from("app_config").upsert({
                key: "pdf_header_config",
                value: JSON.stringify(headerConfig)
            }, { onConflict: "key" });

            if (error) throw error;
            toast.success("Configuração de cabeçalho salva!");
        } catch (error: any) {
            toast.error("Erro ao salvar config: " + error.message);
        } finally {
            setSavingConfig(false);
        }
    };

    const handleLogoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (file.size > 2 * 1024 * 1024) {
            toast.error("A logo deve ter no máximo 2MB");
            return;
        }

        setUploadingLogo(true);
        const reader = new FileReader();
        reader.onloadend = () => {
            setHeaderConfig({ ...headerConfig, logoUrl: reader.result as string });
            setUploadingLogo(false);
            toast.success("Logo carregada localmente! Salve as configurações.");
        };
        reader.onerror = () => {
            setUploadingLogo(false);
            toast.error("Erro ao carregar a imagem selecionada.");
        };
        reader.readAsDataURL(file);
    };

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-card-foreground">Ocorrências</h1>
                    <p className="text-muted-foreground">Gerenciamento e geração de documentos de ocorrência</p>
                </div>
                <div className="flex gap-2 bg-muted p-1 rounded-lg self-start">
                    <button
                        onClick={() => setActiveTab("geral")}
                        className={`px-4 py-1.5 rounded-md text-sm font-bold transition-all ${activeTab === "geral" ? "bg-background text-primary shadow-sm" : "text-muted-foreground hover:text-foreground"}`}
                    >
                        Geral
                    </button>
                    <button
                        onClick={() => setActiveTab("config")}
                        className={`px-4 py-1.5 rounded-md text-sm font-bold transition-all flex items-center gap-2 ${activeTab === "config" ? "bg-background text-primary shadow-sm" : "text-muted-foreground hover:text-foreground"}`}
                    >
                        <Settings2 size={16} /> Configurações
                    </button>
                </div>
            </div>

            {activeTab === "config" ? (
                <div className="module-card max-w-4xl mx-auto space-y-6">
                    <h2 className="text-xl font-bold text-primary flex items-center gap-2">
                        <Settings2 size={24} /> Personalização do Cabeçalho PDF
                    </h2>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="space-y-4">
                            <h3 className="text-sm font-bold text-muted-foreground uppercase">Conteúdo</h3>
                            <div>
                                <label className="text-xs font-bold mb-1 block">Título Principal</label>
                                <input
                                    className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm"
                                    value={headerConfig.title}
                                    onChange={e => setHeaderConfig({ ...headerConfig, title: e.target.value })}
                                />
                            </div>
                            <div>
                                <label className="text-xs font-bold mb-1 block">Subtítulo (CRC, etc)</label>
                                <input
                                    className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm"
                                    value={headerConfig.subtitle}
                                    onChange={e => setHeaderConfig({ ...headerConfig, subtitle: e.target.value })}
                                />
                            </div>
                            <div>
                                <label className="text-xs font-bold mb-1 block">Endereço (Linha 1)</label>
                                <input
                                    className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm"
                                    value={headerConfig.address}
                                    onChange={e => setHeaderConfig({ ...headerConfig, address: e.target.value })}
                                />
                            </div>
                            <div>
                                <label className="text-xs font-bold mb-1 block">Contato/Email (Linha 2)</label>
                                <input
                                    className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm"
                                    value={headerConfig.contact}
                                    onChange={e => setHeaderConfig({ ...headerConfig, contact: e.target.value })}
                                />
                            </div>
                            <div>
                                <label className="text-xs font-bold mb-1 block">Logo do Cabeçalho</label>
                                <div className="flex items-center gap-4 p-4 border border-dashed border-border rounded-xl bg-muted/20">
                                    <div className="w-20 h-20 rounded-lg bg-background border border-border flex items-center justify-center overflow-hidden">
                                        {headerConfig.logoUrl ? (
                                            <img src={headerConfig.logoUrl} alt="Logo" className="max-w-full max-h-full object-contain" />
                                        ) : (
                                            <ImageIcon size={30} className="text-muted-foreground/30" />
                                        )}
                                    </div>
                                    <div className="flex-1 space-y-2">
                                        <p className="text-[10px] text-muted-foreground">Upload da logo em PNG ou JPG. <br />Tamanho recomendado: 200x200px</p>
                                        <div className="flex flex-wrap gap-2">
                                            <label className="inline-flex items-center gap-2 px-3 py-1.5 bg-primary/10 text-primary text-xs font-bold rounded-lg cursor-pointer hover:bg-primary/20 transition-all">
                                                <Upload size={14} />
                                                {uploadingLogo ? "Carregando..." : "Selecionar Logo"}
                                                <input type="file" className="hidden" accept="image/*" onChange={handleLogoUpload} disabled={uploadingLogo} />
                                            </label>

                                            {headerConfig.logoUrl && (
                                                <button
                                                    onClick={() => setHeaderConfig({ ...headerConfig, logoUrl: "" })}
                                                    className="inline-flex items-center gap-2 px-3 py-1.5 bg-destructive/10 text-destructive text-xs font-bold rounded-lg cursor-pointer hover:bg-destructive/20 transition-all"
                                                    title="Remover Logo Customizada"
                                                >
                                                    <Trash2 size={14} />
                                                    Remover
                                                </button>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>

                        <div className="space-y-4">
                            <h3 className="text-sm font-bold text-muted-foreground uppercase">Tamanhos e Posições</h3>
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="text-xs font-bold mb-1 block">Fonte Título</label>
                                    <input type="number" className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm" value={headerConfig.titleFontSize} onChange={e => setHeaderConfig({ ...headerConfig, titleFontSize: parseInt(e.target.value) })} />
                                </div>
                                <div>
                                    <label className="text-xs font-bold mb-1 block">Fonte Subtítulo</label>
                                    <input type="number" className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm" value={headerConfig.subtitleFontSize} onChange={e => setHeaderConfig({ ...headerConfig, subtitleFontSize: parseInt(e.target.value) })} />
                                </div>
                                <div>
                                    <label className="text-xs font-bold mb-1 block">Fonte Info</label>
                                    <input type="number" className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm" value={headerConfig.infoFontSize} onChange={e => setHeaderConfig({ ...headerConfig, infoFontSize: parseInt(e.target.value) })} />
                                </div>
                                <div>
                                    <label className="text-xs font-bold mb-1 block">Largura Logo</label>
                                    <input type="number" className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm" value={headerConfig.logoWidth} onChange={e => setHeaderConfig({ ...headerConfig, logoWidth: parseInt(e.target.value) })} />
                                </div>
                                <div>
                                    <label className="text-xs font-bold mb-1 block">Altura Logo</label>
                                    <input type="number" className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm" value={headerConfig.logoHeight} onChange={e => setHeaderConfig({ ...headerConfig, logoHeight: parseInt(e.target.value) })} />
                                </div>
                                <div>
                                    <label className="text-xs font-bold mb-1 block">Posição Logo X</label>
                                    <input type="number" className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm" value={headerConfig.logoX} onChange={e => setHeaderConfig({ ...headerConfig, logoX: parseInt(e.target.value) })} />
                                </div>
                                <div>
                                    <label className="text-xs font-bold mb-1 block">Posição Logo Y</label>
                                    <input type="number" className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm" value={headerConfig.logoY} onChange={e => setHeaderConfig({ ...headerConfig, logoY: parseInt(e.target.value) })} />
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="pt-6 border-t border-border flex justify-end">
                        <button
                            onClick={saveHeaderConfig}
                            disabled={savingConfig}
                            className="px-8 py-3 bg-primary text-primary-foreground font-bold rounded-xl shadow-lg transition-all hover:scale-[1.02] disabled:opacity-50"
                        >
                            {savingConfig ? "Salvando..." : "Salvar Configurações"}
                        </button>
                    </div>
                </div>
            ) : (
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    {/* Registration Form */}
                    <div className="lg:col-span-1 space-y-6">
                        <div className="module-card">
                            <h3 className="text-lg font-bold text-primary flex items-center gap-2 mb-4">
                                <Plus size={20} /> Nova Ocorrência
                            </h3>

                            <div className="space-y-4">
                                <div>
                                    <label className="text-xs font-bold text-muted-foreground block mb-1 uppercase tracking-tight">Empresa</label>
                                    <select
                                        className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm outline-none focus:ring-2 focus:ring-primary"
                                        value={selectedEmpresaId}
                                        onChange={(e) => setSelectedEmpresaId(e.target.value)}
                                    >
                                        <option value="">Selecione...</option>
                                        {empresas.map(e => <option key={e.id} value={e.id}>{e.nome_empresa}</option>)}
                                    </select>
                                </div>

                                <div>
                                    <label className="text-xs font-bold text-muted-foreground block mb-1 uppercase tracking-tight">Departamento</label>
                                    <select
                                        className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm outline-none focus:ring-2 focus:ring-primary"
                                        value={selectedDepto}
                                        onChange={(e) => setSelectedDepto(e.target.value)}
                                    >
                                        <option value="">Selecione...</option>
                                        {DEPARTAMENTOS.map(d => <option key={d} value={d}>{d}</option>)}
                                    </select>
                                </div>

                                <div>
                                    <label className="text-xs font-bold text-muted-foreground block mb-1 uppercase tracking-tight">Data</label>
                                    <input
                                        type="date"
                                        className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm outline-none focus:ring-2 focus:ring-primary"
                                        value={dataOcorrencia}
                                        onChange={(e) => setDataOcorrencia(e.target.value)}
                                    />
                                </div>

                                <div>
                                    <label className="text-xs font-bold text-muted-foreground block mb-1 uppercase tracking-tight">Ocorrência/Descrição</label>
                                    <textarea
                                        className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm outline-none focus:ring-2 focus:ring-primary min-h-[120px]"
                                        placeholder="Descreva a ocorrência..."
                                        value={descricao}
                                        onChange={(e) => setDescricao(e.target.value)}
                                    />
                                </div>

                                <div className="grid grid-cols-2 gap-2">
                                    <div>
                                        <label className="text-xs font-bold text-muted-foreground block mb-1 uppercase tracking-tight">Cidade</label>
                                        <input
                                            className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm"
                                            value={cidade}
                                            onChange={(e) => setCidade(e.target.value)}
                                        />
                                    </div>
                                    <div>
                                        <label className="text-xs font-bold text-muted-foreground block mb-1 uppercase tracking-tight">Estado</label>
                                        <input
                                            className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm"
                                            value={estado}
                                            onChange={(e) => setEstado(e.target.value)}
                                        />
                                    </div>
                                </div>

                                <div className="flex flex-col gap-2 pt-2">
                                    <button
                                        onClick={() => handleSave(false)}
                                        disabled={saving}
                                        className="w-full py-2.5 bg-muted text-foreground rounded-lg font-bold text-sm hover:bg-muted/80 transition-all flex items-center justify-center gap-2"
                                    >
                                        {saving ? "Salvando..." : "Apenas Salvar"}
                                    </button>
                                    <button
                                        onClick={() => handleSave(true)}
                                        disabled={saving}
                                        className="w-full py-2.5 bg-primary text-primary-foreground rounded-lg font-bold text-sm shadow-md hover:shadow-lg transition-all flex items-center justify-center gap-2"
                                    >
                                        {saving ? "Salvando..." : <><Download size={18} /> Salvar e Gerar PDF</>}
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* List of Recent Occurrences */}
                    <div className="lg:col-span-2 space-y-4">
                        <div className="module-card">
                            <h3 className="text-lg font-bold text-card-foreground flex items-center gap-2 mb-4">
                                <HistoryIcon size={20} className="text-primary" /> Histórico Recente
                            </h3>

                            <div className="space-y-3">
                                {ocorrencias.length === 0 && !loading && (
                                    <div className="text-center py-12 text-muted-foreground">
                                        <FileText size={40} className="mx-auto mb-3 opacity-20" />
                                        <p>Nenhuma ocorrência registrada</p>
                                    </div>
                                )}

                                {ocorrencias.map(oc => (
                                    <div key={oc.id} className="p-4 border border-border rounded-xl hover:bg-muted/30 transition-all flex items-center justify-between group">
                                        <div className="flex items-center gap-3">
                                            <div className="w-10 h-10 rounded-lg bg-primary/10 flex items-center justify-center text-primary group-hover:scale-110 transition-transform">
                                                <Building2 size={20} />
                                            </div>
                                            <div>
                                                <h4 className="font-bold text-sm text-card-foreground">{oc.empresas.nome_empresa}</h4>
                                                <div className="flex items-center gap-3 mt-1 text-[11px] text-muted-foreground font-medium">
                                                    <span className="flex items-center gap-1"><User size={12} /> {oc.departamento}</span>
                                                    <span className="flex items-center gap-1"><Calendar size={12} /> {new Date(oc.data_ocorrencia).toLocaleDateString()}</span>
                                                </div>
                                            </div>
                                        </div>
                                        <div className="flex items-center gap-1">
                                            <button
                                                onClick={() => handleGeneratePdf(oc)}
                                                className="p-2 rounded-lg hover:bg-primary/10 text-muted-foreground hover:text-primary transition-colors"
                                                title="Gerar PDF"
                                            >
                                                <Download size={18} />
                                            </button>
                                            <button
                                                onClick={() => handleDelete(oc.id)}
                                                className="p-2 rounded-lg hover:bg-destructive/10 text-muted-foreground hover:text-destructive transition-colors"
                                                title="Excluir"
                                            >
                                                <Trash2 size={18} />
                                            </button>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default OcorrenciasPage;

import React, { useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { ArrowLeft, Save } from "lucide-react";
import { useNavigate } from "react-router-dom";
import { toast } from "sonner";

const tiposParcelamento = [
    "Previdenciário",
    "Simples Nacional",
    "MEI",
    "IRPF",
    "Dívida Ativa",
    "ICMS",
    "Outros",
];

const calcPrevisao = (dataInicio: string, qtd: number) => {
    if (!dataInicio || !qtd) return "";
    const d = new Date(dataInicio);
    d.setMonth(d.getMonth() + qtd);
    return d.toISOString().slice(0, 10);
};

const ParcelamentoFormPage: React.FC = () => {
    const navigate = useNavigate();
    const [loading, setLoading] = useState(false);
    const [form, setForm] = useState({
        tipo_pessoa: "empresa",
        nome_pessoa_fisica: "",
        cpf_pessoa_fisica: "",
        tipo_parcelamento: "Simples Nacional",
        data_inicio: "",
        qtd_parcelas: "",
        forma_envio: "",
        metodo_login: "procuracao",
        login_gov_br: "",
        senha_gov_br: "",
        codigo_sn: "",
    });

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!form.nome_pessoa_fisica.trim()) {
            toast.error("Nome é obrigatório");
            return;
        }

        setLoading(true);
        const qtd = parseInt(form.qtd_parcelas) || 0;
        const payload = {
            tipo_pessoa: form.tipo_pessoa,
            nome_pessoa_fisica: form.nome_pessoa_fisica,
            cpf_pessoa_fisica: form.cpf_pessoa_fisica || null,
            tipo_parcelamento: form.tipo_parcelamento,
            data_inicio: form.data_inicio || null,
            qtd_parcelas: qtd,
            previsao_termino: calcPrevisao(form.data_inicio, qtd) || null,
            forma_envio: form.forma_envio || null,
            metodo_login: form.metodo_login,
            login_gov_br: form.metodo_login === "gov_br" ? form.login_gov_br : null,
            senha_gov_br: form.metodo_login === "gov_br" ? form.senha_gov_br : null,
            codigo_sn: form.metodo_login === "codigo_sn" ? form.codigo_sn : null,
        };

        try {
            const { error } = await supabase.from("parcelamentos").insert(payload);
            if (error) throw error;
            toast.success("Parcelamento cadastrado com sucesso!");
            navigate("/parcelamentos");
        } catch (err: any) {
            toast.error(err.message || "Erro ao salvar");
        } finally {
            setLoading(false);
        }
    };

    const inputCls =
        "w-full px-4 py-2.5 border border-border rounded-xl bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none transition-all";
    const labelCls = "block text-sm font-semibold text-card-foreground mb-1.5";

    return (
        <div className="space-y-6 animate-fade-in max-w-3xl mx-auto">
            <div className="flex items-center gap-4">
                <button
                    onClick={() => navigate(-1)}
                    className="p-2.5 rounded-xl border border-border bg-card hover:bg-muted text-card-foreground transition-colors"
                >
                    <ArrowLeft size={18} />
                </button>
            </div>

            <div className="module-card p-6 md:p-8">
                <form onSubmit={handleSave} className="space-y-6">
                    <div className="space-y-4">
                        <h3 className="text-lg font-bold border-b border-border pb-2 text-foreground">
                            Dados Gerais
                        </h3>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className={labelCls}>Tipo de Cadastro</label>
                                <select
                                    value={form.tipo_pessoa}
                                    onChange={(e) =>
                                        setForm({ ...form, tipo_pessoa: e.target.value })
                                    }
                                    className={inputCls}
                                >
                                    <option value="empresa">Empresa (PJ)</option>
                                    <option value="pessoa_fisica">Pessoa Física (PF)</option>
                                </select>
                            </div>
                            <div className="md:col-span-2">
                                <label className={labelCls}>Nome ou Razão Social *</label>
                                <input
                                    required
                                    value={form.nome_pessoa_fisica}
                                    onChange={(e) =>
                                        setForm({ ...form, nome_pessoa_fisica: e.target.value })
                                    }
                                    className={inputCls}
                                    placeholder="Nome do cliente"
                                />
                            </div>
                            <div>
                                <label className={labelCls}>
                                    {form.tipo_pessoa === "empresa" ? "CNPJ" : "CPF"}
                                </label>
                                <input
                                    value={form.cpf_pessoa_fisica}
                                    onChange={(e) =>
                                        setForm({ ...form, cpf_pessoa_fisica: e.target.value })
                                    }
                                    className={inputCls}
                                    placeholder="Apenas números"
                                />
                            </div>
                            <div>
                                <label className={labelCls}>Tipo de Parcelamento</label>
                                <select
                                    value={form.tipo_parcelamento}
                                    onChange={(e) =>
                                        setForm({ ...form, tipo_parcelamento: e.target.value })
                                    }
                                    className={inputCls}
                                >
                                    {tiposParcelamento.map((t) => (
                                        <option key={t} value={t}>
                                            {t}
                                        </option>
                                    ))}
                                </select>
                            </div>
                            <div>
                                <label className={labelCls}>Data de Início</label>
                                <input
                                    type="date"
                                    value={form.data_inicio}
                                    onChange={(e) =>
                                        setForm({ ...form, data_inicio: e.target.value })
                                    }
                                    className={inputCls}
                                />
                            </div>
                            <div>
                                <label className={labelCls}>Quantidade de Parcelas</label>
                                <input
                                    type="number"
                                    min="1"
                                    value={form.qtd_parcelas}
                                    onChange={(e) =>
                                        setForm({ ...form, qtd_parcelas: e.target.value })
                                    }
                                    className={inputCls}
                                    placeholder="Ex: 60"
                                />
                            </div>
                            <div>
                                <label className={labelCls}>Forma de Envio Padrão</label>
                                <input
                                    value={form.forma_envio}
                                    onChange={(e) =>
                                        setForm({ ...form, forma_envio: e.target.value })
                                    }
                                    className={inputCls}
                                    placeholder="Ex: WhatsApp, Email..."
                                />
                            </div>
                        </div>
                    </div>

                    <div className="space-y-4 pt-4">
                        <h3 className="text-lg font-bold border-b border-border pb-2 text-foreground">
                            Acesso e Login
                        </h3>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div className="md:col-span-2">
                                <label className={labelCls}>Método de Login</label>
                                <select
                                    value={form.metodo_login}
                                    onChange={(e) =>
                                        setForm({ ...form, metodo_login: e.target.value })
                                    }
                                    className={inputCls}
                                >
                                    <option value="procuracao">Por Procuração / Certificado</option>
                                    <option value="gov_br">Acesso Gov.br</option>
                                    <option value="codigo_sn">Código de Acesso Simples Nacional</option>
                                </select>
                            </div>

                            {form.metodo_login === "gov_br" && (
                                <>
                                    <div className="animate-fade-in">
                                        <label className={labelCls}>Login (CPF Gov.br)</label>
                                        <input
                                            required
                                            value={form.login_gov_br}
                                            onChange={(e) =>
                                                setForm({ ...form, login_gov_br: e.target.value })
                                            }
                                            className={inputCls}
                                            placeholder="CPF de acesso"
                                        />
                                    </div>
                                    <div className="animate-fade-in">
                                        <label className={labelCls}>Senha (Gov.br)</label>
                                        <input
                                            required
                                            type="password"
                                            value={form.senha_gov_br}
                                            onChange={(e) =>
                                                setForm({ ...form, senha_gov_br: e.target.value })
                                            }
                                            className={inputCls}
                                            placeholder="Senha do gov.br"
                                        />
                                    </div>
                                </>
                            )}

                            {form.metodo_login === "codigo_sn" && (
                                <div className="md:col-span-2 animate-fade-in">
                                    <label className={labelCls}>Código de Acesso SN</label>
                                    <input
                                        required
                                        value={form.codigo_sn}
                                        onChange={(e) =>
                                            setForm({ ...form, codigo_sn: e.target.value })
                                        }
                                        className={inputCls}
                                        placeholder="Ex: 123456789012"
                                    />
                                </div>
                            )}
                        </div>
                    </div>

                    <div className="flex justify-end gap-3 pt-6 border-t border-border mt-6">
                        <button
                            type="button"
                            onClick={() => navigate("-1")}
                            className="px-5 py-2.5 text-sm font-semibold text-muted-foreground bg-muted hover:bg-muted/80 rounded-xl transition-colors"
                        >
                            Cancelar
                        </button>
                        <button
                            type="submit"
                            disabled={loading}
                            className="flex items-center gap-2 px-6 py-2.5 text-sm font-semibold text-primary-foreground rounded-xl shadow-md disabled:opacity-50 transition-all hover:opacity-90 active:scale-95"
                            style={{ background: "var(--gradient-primary)" }}
                        >
                            {loading ? (
                                "Salvando..."
                            ) : (
                                <>
                                    <Save size={18} /> Salvar Parcelamento
                                </>
                            )}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default ParcelamentoFormPage;

import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import {
  Search,
  ChevronDown,
  ChevronUp,
  Save,
  CheckCircle,
  Circle,
  Plus,
  Trash2,
} from "lucide-react";
import { toast } from "sonner";
import { useNavigate } from "react-router-dom";
import { format, isBefore, isSameDay } from "date-fns";

const ParcelamentosPage: React.FC = () => {
  const navigate = useNavigate();
  const [parcelamentos, setParcelamentos] = useState<any[]>([]);
  const [mensalData, setMensalData] = useState<Record<string, any>>({});
  const [search, setSearch] = useState("");
  const [competencia, setCompetencia] = useState(
    new Date().toISOString().slice(0, 7)
  );
  const [expanded, setExpanded] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Record<string, any>>({});
  const [activeTab, setActiveTab] = useState<"andamento" | "encerrados">("andamento");

  useEffect(() => {
    const loadParcelamentos = async () => {
      const { data } = await supabase
        .from("parcelamentos")
        .select("*")
        .order("nome_pessoa_fisica");
      setParcelamentos(data || []);
    };
    loadParcelamentos();
  }, []);

  useEffect(() => {
    const loadMensal = async () => {
      const { data } = await supabase
        .from("parcelamentos_mensal")
        .select("*")
        .eq("competencia", competencia);
      const map: Record<string, any> = {};
      data?.forEach((f) => {
        map[f.parcelamento_id] = f;
      });
      setMensalData(map);
    };
    loadMensal();
  }, [competencia]);

  const calcIsEncerrado = (p: any) => {
    if (p.encerrado) return true;
    if (p.previsao_termino) {
      const hoje = new Date();
      hoje.setHours(0, 0, 0, 0);
      const previsao = new Date(p.previsao_termino);
      // Extra hour adjustment for timezone if needed, but simple comparison suffices for dates
      previsao.setHours(0, 0, 0, 0);
      if (isBefore(previsao, hoje) || isSameDay(previsao, hoje)) return true;
    }
    return false;
  };

  const filtered = parcelamentos.filter((p) => {
    const isEncerrado = calcIsEncerrado(p);
    const matchesTab = activeTab === "encerrados" ? isEncerrado : !isEncerrado;
    const matchesSearch =
      p.nome_pessoa_fisica?.toLowerCase().includes(search.toLowerCase()) ||
      p.cpf_pessoa_fisica?.includes(search);
    return matchesTab && matchesSearch;
  });

  const toggleExpand = (id: string) => {
    if (expanded === id) {
      setExpanded(null);
      return;
    }
    setExpanded(id);
    const existing = mensalData[id] || {};

    setEditForm((prev) => ({
      ...prev,
      [id]: {
        status: existing.status || "pendente",
        data_envio: existing.data_envio || "",
        observacoes: existing.observacoes || "",
      },
    }));
  };

  const handleSaveMensal = async (parcelamentoId: string) => {
    const form = editForm[parcelamentoId];
    const existing = mensalData[parcelamentoId];
    try {
      const payload = {
        parcelamento_id: parcelamentoId,
        competencia,
        status: form.status || "pendente",
        data_envio: form.data_envio || null,
        observacoes: form.observacoes || null,
      };

      if (existing?.id) {
        await supabase
          .from("parcelamentos_mensal")
          .update(payload)
          .eq("id", existing.id);
      } else {
        await supabase.from("parcelamentos_mensal").insert(payload);
      }
      toast.success("Mês atualizado com sucesso!");

      // Refresh just the month data
      const { data } = await supabase
        .from("parcelamentos_mensal")
        .select("*")
        .eq("competencia", competencia);
      const map: Record<string, any> = {};
      data?.forEach((f) => {
        map[f.parcelamento_id] = f;
      });
      setMensalData(map);
      setExpanded(null);
    } catch (err: any) {
      toast.error(err.message);
    }
  };

  const handleDeleteParcelamento = async (id: string) => {
    if (!window.confirm("Deseja realmente excluir este parcelamento? Isso removerá o histórico também.")) return;
    try {
      await supabase.from("parcelamentos").delete().eq("id", id);
      toast.success("Parcelamento excluído!");
      setParcelamentos(parcelamentos.filter((p) => p.id !== id));
    } catch (err: any) {
      toast.error(err.message);
    }
  };

  const handleToggleEncerrado = async (p: any) => {
    const isAtualmenteEncerrado = calcIsEncerrado(p);
    // Para reabrir, forçamos 'encerrado' para false E removemos a 'previsao_termino'
    // se ela já tiver passado, para não fechar automaticamente de novo.
    // Mas o mais seguro para "reabrir" é apenas setar a flag `encerrado` e
    // deixar a data original. Na lógica, `previsao_termino` ainda forçaria encerrado.
    // Como a instrução era ter um controle manual da aba, vamos usar a flag `encerrado`
    // e para forçar reabrir podemos precisar limpar a data. Para o escopo pedido,
    // o foco é encerrar manualmente.

    // Simplificando o pedido: Mudar a flag `encerrado` inverte a situação?
    // Se "Em Andamento (isEncerrado = false)", marcamos encerrado = true.
    // Se "Encerrado (isEncerrado = true)", marcamos encerrado = false E podemos ter que adiar a previsão 
    // ou apenas dar prioridade a flag false se quisermos um override? 
    // Vamos apenas rodar a flag `encerrado` boolean pra simular ação manual
    try {
      const newVal = !p.encerrado;
      // Se tentou re-abrir mas a data já passou, alertar? Ou limpar a data?
      // Vamos apagar a data de encerramento se ele explicitamente reabrir para não dar conflito 
      let payload: any = { encerrado: newVal };

      if (!newVal && p.previsao_termino) {
        const hoje = new Date();
        hoje.setHours(0, 0, 0, 0);
        const prev = new Date(p.previsao_termino);
        prev.setHours(0, 0, 0, 0);
        if (isBefore(prev, hoje) || isSameDay(prev, hoje)) {
          if (window.confirm("A previsão de término deste parcelamento já passou. Para reabri-lo, a previsão será limpa. Deseja continuar?")) {
            payload.previsao_termino = null;
          } else {
            return;
          }
        }
      }

      const { error } = await supabase.from("parcelamentos").update(payload).eq("id", p.id);
      if (error) throw error;

      toast.success(newVal ? "Parcelamento encerrado." : "Parcelamento reaberto.");
      setParcelamentos(parcelamentos.map(item => item.id === p.id ? { ...item, ...payload } : item));
    } catch (err: any) {
      toast.error(err.message);
    }
  };

  const updateForm = (id: string, field: string, value: any) => {
    setEditForm((prev) => ({
      ...prev,
      [id]: { ...prev[id], [field]: value },
    }));
  };

  const inputCls =
    "w-full px-3 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none";
  const labelCls = "block text-xs font-medium text-muted-foreground mb-1";

  const completedCount = parcelamentos.filter(
    (p) =>
      mensalData[p.id]?.status === "enviada" ||
      mensalData[p.id]?.status === "gerada"
  ).length;

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-end gap-4">
        <div className="flex gap-3">
          <input
            type="month"
            value={competencia}
            onChange={(e) => setCompetencia(e.target.value)}
            className="px-4 py-2 border border-border rounded-xl bg-background text-foreground font-semibold outline-none focus:ring-2 focus:ring-primary"
          />
          <button
            onClick={() => navigate("/parcelamentos/novo")}
            className="flex items-center gap-2 px-5 py-2.5 rounded-xl text-sm font-semibold text-primary-foreground shadow-md transition-all hover:opacity-90 active:scale-95"
            style={{ background: "var(--gradient-primary)" }}
          >
            <Plus size={18} /> Novo Parcelamento
          </button>
        </div>
      </div>

      <div className="grid grid-cols-3 gap-4">
        <div className="stat-card">
          <p className="text-xs text-muted-foreground font-medium uppercase">
            Total Cadastrados
          </p>
          <p className="text-2xl font-bold text-primary mt-1">
            {parcelamentos.length}
          </p>
        </div>
        <div className="stat-card">
          <p className="text-xs text-muted-foreground font-medium uppercase">
            Mês Concluído
          </p>
          <p className="text-2xl font-bold text-success mt-1">
            {completedCount}
          </p>
        </div>
        <div className="stat-card">
          <p className="text-xs text-muted-foreground font-medium uppercase">
            Pendentes
          </p>
          <p className="text-2xl font-bold text-warning mt-1">
            {parcelamentos.length - completedCount}
          </p>
        </div>
      </div>

      <div className="relative max-w-sm">
        <Search
          size={16}
          className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground"
        />
        <input
          type="text"
          placeholder="Buscar por nome ou CPF/CNPJ..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="w-full pl-9 pr-4 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none"
        />
      </div>

      <div className="flex border-b border-border overflow-x-auto no-scrollbar">
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "andamento"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("andamento")}
        >
          Em Andamento
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "encerrados"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("encerrados")}
        >
          Parcelamentos Encerrados
        </button>
      </div>

      <div className="space-y-3">
        {filtered.length === 0 ? (
          <div className="text-center py-12 bg-card border border-border rounded-xl text-muted-foreground">
            {search
              ? "Nenhum parcelamento encontrado na busca."
              : "Nenhum parcelamento cadastrado. Clique em Novo Parcelamento para começar."}
          </div>
        ) : (
          filtered.map((p) => {
            const isOpen = expanded === p.id;
            const form = editForm[p.id] || {};
            const done =
              mensalData[p.id]?.status === "enviada" ||
              mensalData[p.id]?.status === "gerada";

            return (
              <div key={p.id} className="module-card !p-0 overflow-hidden">
                <div
                  className="flex flex-col sm:flex-row sm:items-center justify-between p-4 cursor-pointer hover:bg-muted/30 transition-colors gap-4"
                  onClick={() => toggleExpand(p.id)}
                >
                  <div className="flex items-center gap-3">
                    {done ? (
                      <CheckCircle size={18} className="text-success" />
                    ) : (
                      <Circle size={18} className="text-muted-foreground" />
                    )}
                    <div>
                      <p className="font-semibold text-card-foreground">
                        {p.nome_pessoa_fisica}
                      </p>
                      <p className="text-xs text-muted-foreground mt-0.5">
                        {p.cpf_pessoa_fisica || "S/N"} • {p.tipo_parcelamento} •{" "}
                        {p.qtd_parcelas} Parcelas
                      </p>
                    </div>
                  </div>
                  <div className="flex items-center justify-between sm:justify-end gap-4 w-full sm:w-auto">
                    <span
                      className={`badge-status ${done ? "badge-success" : "badge-warning"
                        }`}
                    >
                      {mensalData[p.id]?.status === "enviada"
                        ? "Enviada"
                        : mensalData[p.id]?.status === "gerada"
                          ? "Gerada"
                          : "Pendente"}
                    </span>
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        handleToggleEncerrado(p);
                      }}
                      className={`px-3 py-1.5 rounded-lg text-xs font-medium border transition-colors ${calcIsEncerrado(p) ? 'border-border text-foreground bg-muted/50 hover:bg-muted' : 'border-destructive text-destructive bg-destructive/10 hover:bg-destructive/20'}`}
                    >
                      {calcIsEncerrado(p) ? 'Reabrir' : 'Encerrar'}
                    </button>
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        handleDeleteParcelamento(p.id);
                      }}
                      className="p-1.5 text-muted-foreground hover:text-destructive transition-colors ml-2"
                      title="Excluir este parcelamento de todos os meses"
                    >
                      <Trash2 size={16} />
                    </button>
                    {isOpen ? (
                      <ChevronUp size={16} className="text-muted-foreground" />
                    ) : (
                      <ChevronDown
                        size={16}
                        className="text-muted-foreground"
                      />
                    )}
                  </div>
                </div>

                {isOpen && (
                  <div className="border-t border-border bg-muted/20">
                    <div className="p-5 border-b border-border/50 grid grid-cols-2 md:grid-cols-4 gap-4 bg-muted/10 text-xs">
                      <div>
                        <span className="text-muted-foreground block mb-1">
                          Início
                        </span>
                        <span className="font-medium text-foreground">
                          {p.data_inicio
                            ? new Date(p.data_inicio).toLocaleDateString(
                              "pt-BR"
                            )
                            : "—"}
                        </span>
                      </div>
                      <div>
                        <span className="text-muted-foreground block mb-1">Previsão Término</span>
                        <span className={`font-medium ${calcIsEncerrado(p) ? 'text-destructive' : 'text-foreground'}`}>
                          {p.previsao_termino ? format(new Date(p.previsao_termino), 'dd/MM/yyyy') : "—"}
                        </span>
                      </div>
                      <div>
                        <span className="text-muted-foreground block mb-1">
                          Envio Fixo
                        </span>
                        <span className="font-medium text-foreground">
                          {p.forma_envio || "—"}
                        </span>
                      </div>
                      <div className="md:col-span-1">
                        <span className="text-muted-foreground block mb-1">
                          Acesso:{" "}
                          <strong className="text-primary font-medium">
                            {p.metodo_login === "gov_br"
                              ? "Gov.br"
                              : p.metodo_login === "codigo_sn"
                                ? "Cód. AC. Simples Nacional"
                                : "Procuração"}
                          </strong>
                        </span>
                        <span className="font-mono text-foreground tracking-tight">
                          {p.metodo_login === "gov_br" &&
                            `L: ${p.login_gov_br || "-"} | S: ${p.senha_gov_br || "-"
                            }`}
                          {p.metodo_login === "codigo_sn" &&
                            `Cód: ${p.codigo_sn || "-"}`}
                          {p.metodo_login === "procuracao" && "Acesso Padrão"}
                        </span>
                      </div>
                    </div>
                    <div className="p-5 space-y-4">
                      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                        <div>
                          <label className={labelCls}>Status no Mês</label>
                          <select
                            value={form.status || "pendente"}
                            onChange={(e) =>
                              updateForm(p.id, "status", e.target.value)
                            }
                            className={inputCls}
                          >
                            <option value="pendente">Pendente para Envio</option>
                            <option value="gerada">Em Andamento</option>
                            <option value="enviada">Concluída / Enviada</option>
                          </select>
                        </div>
                        <div>
                          <label className={labelCls}>Data do Envio (Opcional)</label>
                          <input
                            type="date"
                            value={form.data_envio || ""}
                            onChange={(e) =>
                              updateForm(p.id, "data_envio", e.target.value)
                            }
                            className={inputCls}
                          />
                        </div>
                        <div>
                          <label className={labelCls}>Anotação Breve</label>
                          <input
                            value={form.observacoes || ""}
                            onChange={(e) =>
                              updateForm(p.id, "observacoes", e.target.value)
                            }
                            className={inputCls}
                            placeholder="Ex: Falta emitir boleto atualizado"
                          />
                        </div>
                      </div>
                      <div className="flex justify-end pt-2">
                        <button
                          onClick={() => handleSaveMensal(p.id)}
                          className="flex items-center gap-2 px-6 py-2 rounded-lg text-sm font-semibold text-primary-foreground shadow-md transition-all hover:opacity-90 active:scale-95"
                          style={{ background: "var(--gradient-primary)" }}
                        >
                          <Save size={16} /> Salvar Mês de{" "}
                          {competencia.split("-").reverse().join("/")}
                        </button>
                      </div>
                    </div>
                  </div>
                )}
              </div>
            );
          })
        )}
      </div>
    </div>
  );
};

export default ParcelamentosPage;

import React, { useEffect, useState } from "react";
import { useAuth } from "@/contexts/AuthContext";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import { Save, User, Lock } from "lucide-react";
import { maskCPF } from "@/lib/utils";


interface Endereco {
  cep: string;
  logradouro: string;
  numero: string;
  complemento: string;
  bairro: string;
  cidade: string;
  estado: string;
}

const PerfilPage: React.FC = () => {
  const { user } = useAuth();
  const [saving, setSaving] = useState(false);
  const [loading, setLoading] = useState(true);
  const [form, setForm] = useState({
    nome_completo: "",
    cpf: "",
    telefone: "",
    data_nascimento: "",
    endereco: { cep: "", logradouro: "", numero: "", complemento: "", bairro: "", cidade: "", estado: "" } as Endereco,
  });

  useEffect(() => {
    const load = async () => {
      if (!user) return;
      const { data } = await supabase.from("profiles").select("*").eq("user_id", user.id).single();
      if (data) {
        const end = (data.endereco || {}) as any;
        setForm({
          nome_completo: data.nome_completo || "",
          cpf: data.cpf || "",
          telefone: data.telefone || "",
          data_nascimento: data.data_nascimento || "",
          endereco: {
            cep: end.cep || "", logradouro: end.logradouro || "", numero: end.numero || "",
            complemento: end.complemento || "", bairro: end.bairro || "", cidade: end.cidade || "", estado: end.estado || "",
          },
        });
      }
      setLoading(false);
    };
    load();
  }, [user]);



  const formatCEP = (value: string) => {
    const digits = value.replace(/\D/g, "").slice(0, 8);
    return digits.replace(/(\d{5})(\d)/, "$1-$2");
  };

  const formatTelefone = (value: string) => {
    const digits = value.replace(/\D/g, "").slice(0, 11);
    if (digits.length <= 10) return digits.replace(/(\d{2})(\d)/, "($1) $2").replace(/(\d{4})(\d)/, "$1-$2");
    return digits.replace(/(\d{2})(\d)/, "($1) $2").replace(/(\d{5})(\d)/, "$1-$2");
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.nome_completo.trim() || !form.cpf.trim()) {
      toast.error("Nome e CPF são obrigatórios");
      return;
    }
    setSaving(true);
    try {
      const { error } = await supabase.from("profiles").update({
        nome_completo: form.nome_completo,
        cpf: form.cpf,
        telefone: form.telefone,
        data_nascimento: form.data_nascimento || null,
        endereco: form.endereco as any,
      }).eq("user_id", user!.id);
      if (error) throw error;
      toast.success("Perfil atualizado com sucesso!");
    } catch (err: any) {
      toast.error("Erro: " + err.message);
    } finally {
      setSaving(false);
    }
  };

  const updateEndereco = (key: keyof Endereco, value: string) => {
    setForm(prev => ({ ...prev, endereco: { ...prev.endereco, [key]: value } }));
  };

  const estados = ["AC", "AL", "AM", "AP", "BA", "CE", "DF", "ES", "GO", "MA", "MG", "MS", "MT", "PA", "PB", "PE", "PI", "PR", "RJ", "RN", "RO", "RR", "RS", "SC", "SE", "SP", "TO"];

  if (loading) return <div className="flex items-center justify-center p-8"><p className="text-muted-foreground">Carregando...</p></div>;

  return (
    <div className="space-y-6 animate-fade-in max-w-3xl">
      <div className="flex items-center gap-3">
        <div className="w-12 h-12 rounded-full bg-primary flex items-center justify-center">
          <User size={22} className="text-primary-foreground" />
        </div>
        <div>
          <h3 className="text-lg font-bold text-card-foreground">Meu Perfil</h3>
          <p className="text-sm text-muted-foreground">Gerencie suas informações pessoais</p>
        </div>
      </div>

      <div className="module-card space-y-8">
        <form onSubmit={handleSave} className="space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-card-foreground mb-1">Nome Completo</label>
              <input value={form.nome_completo} onChange={e => setForm({ ...form, nome_completo: e.target.value })} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
            </div>
            <div>
              <label className="block text-sm font-medium text-card-foreground mb-1">CPF</label>
              <input value={form.cpf} onChange={e => setForm({ ...form, cpf: maskCPF(e.target.value) })} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />

            </div>
            <div>
              <label className="block text-sm font-medium text-card-foreground mb-1">Telefone</label>
              <input value={form.telefone} onChange={e => setForm({ ...form, telefone: formatTelefone(e.target.value) })} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
            </div>
            <div>
              <label className="block text-sm font-medium text-card-foreground mb-1">Data de Nascimento</label>
              <input type="date" value={form.data_nascimento} onChange={e => setForm({ ...form, data_nascimento: e.target.value })} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
            </div>
            <div>
              <label className="block text-sm font-medium text-card-foreground mb-1">E-mail</label>
              <input value={user?.email || ""} disabled className="w-full px-3 py-2.5 border border-border rounded-lg bg-muted/50 text-muted-foreground text-sm cursor-not-allowed" />
            </div>
          </div>

          <div className="border-t border-border pt-6">
            <h2 className="text-base font-semibold text-card-foreground mb-4">Endereço</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div>
                <label className="block text-sm font-medium text-card-foreground mb-1">CEP</label>
                <input value={form.endereco.cep} onChange={e => updateEndereco("cep", formatCEP(e.target.value))} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
              </div>
              <div className="md:col-span-2">
                <label className="block text-sm font-medium text-card-foreground mb-1">Logradouro</label>
                <input value={form.endereco.logradouro} onChange={e => updateEndereco("logradouro", e.target.value)} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
              </div>
              <div>
                <label className="block text-sm font-medium text-card-foreground mb-1">Número</label>
                <input value={form.endereco.numero} onChange={e => updateEndereco("numero", e.target.value)} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
              </div>
              <div>
                <label className="block text-sm font-medium text-card-foreground mb-1">Complemento</label>
                <input value={form.endereco.complemento} onChange={e => updateEndereco("complemento", e.target.value)} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
              </div>
              <div>
                <label className="block text-sm font-medium text-card-foreground mb-1">Bairro</label>
                <input value={form.endereco.bairro} onChange={e => updateEndereco("bairro", e.target.value)} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
              </div>
              <div>
                <label className="block text-sm font-medium text-card-foreground mb-1">Cidade</label>
                <input value={form.endereco.cidade} onChange={e => updateEndereco("cidade", e.target.value)} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
              </div>
              <div>
                <label className="block text-sm font-medium text-card-foreground mb-1">Estado</label>
                <select value={form.endereco.estado} onChange={e => updateEndereco("estado", e.target.value)} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none">
                  <option value="">Selecione</option>
                  {estados.map(uf => <option key={uf} value={uf}>{uf}</option>)}
                </select>
              </div>
            </div>
          </div>

          <div className="flex justify-end pt-4">
            <button type="submit" disabled={saving} className="flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-semibold text-primary-foreground shadow-md disabled:opacity-50" style={{ background: "var(--gradient-primary)" }}>
              <Save size={16} /> {saving ? "Salvando..." : "Salvar Alterações"}
            </button>
          </div>
        </form>

        {/* Seção Alterar Senha - Agora fora do form principal */}
        <div className="bg-card border border-border rounded-2xl overflow-hidden shadow-sm">
          <div className="p-6 border-b border-border bg-muted/30 flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-orange-500/10 text-orange-500 flex items-center justify-center">
              <Lock size={20} />
            </div>
            <div>
              <h2 className="text-lg font-bold">Alterar Senha</h2>
              <p className="text-sm text-muted-foreground">Mantenha sua conta segura</p>
            </div>
          </div>
          <div className="p-6">
            <form onSubmit={async (e) => {
              e.preventDefault();
              const target = e.currentTarget;
              const newPassword = (target.elements.namedItem("newPassword") as HTMLInputElement).value;
              const confirmPassword = (target.elements.namedItem("confirmPassword") as HTMLInputElement).value;

              if (newPassword.length < 8) {
                toast.error("A nova senha deve ter pelo menos 8 caracteres.");
                return;
              }
              if (newPassword !== confirmPassword) {
                toast.error("As senhas não coincidem.");
                return;
              }

              try {
                const { error } = await supabase.auth.updateUser({ password: newPassword });
                if (error) throw error;
                toast.success("Senha alterada com sucesso!");
                target.reset();
              } catch (err: any) {
                toast.error("Erro ao alterar senha: " + err.message);
              }
            }} className="space-y-4 max-w-md">
              <div className="space-y-2">
                <label className="text-sm font-semibold ml-1">Nova Senha</label>
                <input
                  name="newPassword"
                  type="password"
                  placeholder="No mínimo 8 caracteres"
                  className="w-full px-4 py-3 border border-border rounded-xl bg-background outline-none focus:ring-2 focus:ring-primary transition-all"
                  required
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-semibold ml-1">Confirmar Nova Senha</label>
                <input
                  name="confirmPassword"
                  type="password"
                  placeholder="Repita a nova senha"
                  className="w-full px-4 py-3 border border-border rounded-xl bg-background outline-none focus:ring-2 focus:ring-primary transition-all"
                  required
                />
              </div>
              <button
                type="submit"
                className="px-8 py-3 bg-primary text-primary-foreground font-bold rounded-xl shadow-lg transition-all hover:scale-[1.02] active:scale-[0.98]"
              >
                Atualizar Senha
              </button>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
};

export default PerfilPage;

import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Search, ChevronDown, ChevronUp, Save, CheckCircle, Circle } from "lucide-react";
import { toast } from "sonner";
import { useEmpresas } from "@/hooks/useEmpresas";

const PessoalPage: React.FC = () => {
  const { empresas, loading } = useEmpresas("pessoal");
  const [pessoalData, setPessoalData] = useState<Record<string, any>>({});
  const [search, setSearch] = useState("");
  const [competencia, setCompetencia] = useState(new Date().toISOString().slice(0, 7));
  const [expanded, setExpanded] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Record<string, any>>({});
  const [activeTab, setActiveTab] = useState<"ativas" | "mei" | "paralisadas" | "baixadas">("ativas");

  useEffect(() => {
    const load = async () => {
      const { data } = await supabase.from("pessoal").select("*").eq("competencia", competencia);
      const map: Record<string, any> = {};
      data?.forEach(p => { map[p.empresa_id] = p; });
      setPessoalData(map);
    };
    load();
  }, [competencia]);

  const filtered = empresas.filter(e => {
    const matchSearch = e.nome_empresa?.toLowerCase().includes(search.toLowerCase()) || e.cnpj?.includes(search);

    let matchTab = false;
    if (activeTab === "ativas") {
      matchTab = (!e.situacao || e.situacao === "ativa") && e.porte_empresa !== "mei";
    } else if (activeTab === "mei") {
      matchTab = (!e.situacao || e.situacao === "ativa") && e.porte_empresa === "mei";
    } else if (activeTab === "paralisadas") {
      matchTab = e.situacao === "paralisada";
    } else if (activeTab === "baixadas") {
      matchTab = e.situacao === "baixada";
    }

    return matchSearch && matchTab;
  });

  const toggleExpand = (id: string) => {
    if (expanded === id) { setExpanded(null); return; }
    setExpanded(id);
    const existing = pessoalData[id] || {};
    setEditForm(prev => ({
      ...prev, [id]: {
        forma_envio: existing.forma_envio || "", qtd_funcionarios: existing.qtd_funcionarios || 0,
        qtd_pro_labore: existing.qtd_pro_labore || 0,
        possui_vt: existing.possui_vt || false, possui_va: existing.possui_va || false,
        possui_vc: existing.possui_vc || false, possui_recibos: existing.possui_recibos || false,
        qtd_recibos: existing.qtd_recibos || 0,
        vt_status: existing.vt_status || "pendente", vt_data_envio: existing.vt_data_envio || "",
        va_status: existing.va_status || "pendente", va_data_envio: existing.va_data_envio || "",
        vc_status: existing.vc_status || "pendente", vc_data_envio: existing.vc_data_envio || "",
        inss_status: existing.inss_status || "pendente", inss_data_envio: existing.inss_data_envio || "",
        fgts_status: existing.fgts_status || "pendente", fgts_data_envio: existing.fgts_data_envio || "",
        dctf_web_gerada: existing.dctf_web_gerada || false, dctf_web_data_envio: existing.dctf_web_data_envio || "",
      }
    }));
  };

  const handleSave = async (empresaId: string) => {
    const form = editForm[empresaId];
    const existing = pessoalData[empresaId];
    try {
      const payload = {
        empresa_id: empresaId, competencia, forma_envio: form.forma_envio || null,
        qtd_funcionarios: parseInt(form.qtd_funcionarios) || 0, qtd_pro_labore: parseInt(form.qtd_pro_labore) || 0,
        possui_vt: form.possui_vt || false, possui_va: form.possui_va || false,
        possui_vc: form.possui_vc || false, possui_recibos: form.possui_recibos || false,
        qtd_recibos: parseInt(form.qtd_recibos) || 0,
        vt_status: form.vt_status as any, vt_data_envio: form.vt_data_envio || null,
        va_status: form.va_status as any, va_data_envio: form.va_data_envio || null,
        vc_status: form.vc_status as any, vc_data_envio: form.vc_data_envio || null,
        inss_status: form.inss_status as any, inss_data_envio: form.inss_data_envio || null,
        fgts_status: form.fgts_status as any, fgts_data_envio: form.fgts_data_envio || null,
        dctf_web_gerada: form.dctf_web_gerada || false, dctf_web_data_envio: form.dctf_web_data_envio || null,
      };
      if (existing?.id) {
        await supabase.from("pessoal").update(payload).eq("id", existing.id);
      } else {
        await supabase.from("pessoal").insert(payload);
      }
      toast.success("Dados do pessoal salvos!");
      const { data } = await supabase.from("pessoal").select("*").eq("competencia", competencia);
      const map: Record<string, any> = {};
      data?.forEach(p => { map[p.empresa_id] = p; });
      setPessoalData(map);
    } catch (err: any) { toast.error(err.message); }
  };

  const updateForm = (empresaId: string, field: string, value: any) => {
    setEditForm(prev => ({ ...prev, [empresaId]: { ...prev[empresaId], [field]: value } }));
  };

  const inputCls = "w-full px-3 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none";
  const labelCls = "block text-xs font-medium text-muted-foreground mb-1";
  const completedCount = filtered.filter(e => pessoalData[e.id]?.dctf_web_gerada).length;

  if (loading) {
    return <div className="flex items-center justify-center h-64"><div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>;
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-end gap-4">
        <input type="month" value={competencia} onChange={e => setCompetencia(e.target.value)} className="px-4 py-2.5 border border-border rounded-xl bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none font-semibold" />
      </div>
      <div className="grid grid-cols-3 gap-4">
        <div className="stat-card"><p className="text-xs text-muted-foreground uppercase">Empresas</p><p className="text-2xl font-bold text-primary mt-1">{filtered.length}</p></div>
        <div className="stat-card"><p className="text-xs text-muted-foreground uppercase">Concluídas</p><p className="text-2xl font-bold text-success mt-1">{completedCount}</p></div>
        <div className="stat-card"><p className="text-xs text-muted-foreground uppercase">Pendentes</p><p className="text-2xl font-bold text-warning mt-1">{filtered.length - completedCount}</p></div>
      </div>
      <div className="relative max-w-sm"><Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" /><input type="text" placeholder="Buscar empresa..." value={search} onChange={e => setSearch(e.target.value)} className="w-full pl-9 pr-4 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" /></div>

      <div className="flex border-b border-border overflow-x-auto no-scrollbar">
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "ativas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("ativas")}
        >
          Empresas Ativas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "mei"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("mei")}
        >
          Empresas MEI
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "paralisadas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("paralisadas")}
        >
          Empresas Paralisadas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "baixadas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("baixadas")}
        >
          Empresas Baixadas
        </button>
      </div>

      <div className="space-y-3">
        {filtered.map(emp => {
          const isOpen = expanded === emp.id;
          const form = editForm[emp.id] || {};
          const done = pessoalData[emp.id]?.dctf_web_gerada;
          return (
            <div key={emp.id} className="module-card !p-0 overflow-hidden">
              <div className="flex items-center justify-between p-4 cursor-pointer hover:bg-muted/30 transition-colors" onClick={() => toggleExpand(emp.id)}>
                <div className="flex items-center gap-3">{done ? <CheckCircle size={18} className="text-success" /> : <Circle size={18} className="text-muted-foreground" />}<div><p className="font-medium text-card-foreground">{emp.nome_empresa}</p><p className="text-xs text-muted-foreground">{emp.cnpj || "—"}</p></div></div>
                <div className="flex items-center gap-2"><span className={`badge-status ${done ? "badge-success" : "badge-warning"}`}>{done ? "Concluído" : "Pendente"}</span>{isOpen ? <ChevronUp size={16} className="text-muted-foreground" /> : <ChevronDown size={16} className="text-muted-foreground" />}</div>
              </div>
              {isOpen && (
                <div className="border-t border-border p-5 space-y-5 bg-muted/10">
                  {/* Informações */}
                  <div><h3 className="text-sm font-semibold text-card-foreground mb-3">Informações</h3>
                    <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                      <div><label className={labelCls}>Forma de Envio</label><input value={form.forma_envio || ""} onChange={e => updateForm(emp.id, "forma_envio", e.target.value)} className={inputCls} /></div>
                      <div><label className={labelCls}>Qtd Funcionários</label><input type="number" value={form.qtd_funcionarios || 0} onChange={e => updateForm(emp.id, "qtd_funcionarios", e.target.value)} className={inputCls} /></div>
                      <div><label className={labelCls}>Qtd Pró-labore</label><input type="number" value={form.qtd_pro_labore || 0} onChange={e => updateForm(emp.id, "qtd_pro_labore", e.target.value)} className={inputCls} /></div>
                    </div>
                  </div>

                  {/* Trabalhistas */}
                  <div><h3 className="text-sm font-semibold text-card-foreground mb-3">Trabalhistas - {competencia}</h3>
                    <div className="space-y-3">
                      {/* Recibos - campo de quantidade */}
                      <div className="grid grid-cols-3 gap-3 items-center">
                        <label className="flex items-center gap-2 text-sm font-medium text-card-foreground cursor-pointer">
                          <input type="checkbox" checked={form.possui_recibos || false} onChange={e => updateForm(emp.id, "possui_recibos", e.target.checked)} className="w-4 h-4 rounded border-border text-primary" /> Recibos
                        </label>
                        {form.possui_recibos ? (
                          <div><label className={labelCls}>Qtd Recibos</label><input type="number" value={form.qtd_recibos || 0} onChange={e => updateForm(emp.id, "qtd_recibos", e.target.value)} className={inputCls} /></div>
                        ) : <div />}
                        <div />
                      </div>
                      {/* VT, VA, VC - checkbox + status + data */}
                      {[
                        { label: "VT", checkKey: "possui_vt", statusKey: "vt_status", dateKey: "vt_data_envio" },
                        { label: "VA", checkKey: "possui_va", statusKey: "va_status", dateKey: "va_data_envio" },
                        { label: "VC", checkKey: "possui_vc", statusKey: "vc_status", dateKey: "vc_data_envio" },
                      ].map(item => (
                        <div key={item.label} className="grid grid-cols-3 gap-3 items-center">
                          <label className="flex items-center gap-2 text-sm font-medium text-card-foreground cursor-pointer">
                            <input type="checkbox" checked={form[item.checkKey] || false} onChange={e => updateForm(emp.id, item.checkKey, e.target.checked)} className="w-4 h-4 rounded border-border text-primary" /> {item.label}
                          </label>
                          {form[item.checkKey] ? (
                            <>
                              <select value={form[item.statusKey] || "pendente"} onChange={e => updateForm(emp.id, item.statusKey, e.target.value)} className={inputCls}>
                                <option value="pendente">Pendente</option><option value="gerada">Gerada</option><option value="enviada">Enviada</option>
                              </select>
                              <input type="date" value={form[item.dateKey] || ""} onChange={e => updateForm(emp.id, item.dateKey, e.target.value)} className={inputCls} />
                            </>
                          ) : (<><div /><div /></>)}
                        </div>
                      ))}
                    </div>
                  </div>

                  {/* Encargos */}
                  <div><h3 className="text-sm font-semibold text-card-foreground mb-3">Encargos - {competencia}</h3>
                    <div className="space-y-3">
                      {[{ label: "INSS", statusKey: "inss_status", dateKey: "inss_data_envio" }, { label: "FGTS", statusKey: "fgts_status", dateKey: "fgts_data_envio" }].map(enc => (
                        <div key={enc.label} className="grid grid-cols-3 gap-3 items-center">
                          <span className="text-sm font-medium text-card-foreground">{enc.label}</span>
                          <select value={form[enc.statusKey] || "pendente"} onChange={e => updateForm(emp.id, enc.statusKey, e.target.value)} className={inputCls}>
                            <option value="pendente">Pendente</option><option value="gerada">Gerada</option><option value="enviada">Enviada</option>
                          </select>
                          <input type="date" value={form[enc.dateKey] || ""} onChange={e => updateForm(emp.id, enc.dateKey, e.target.value)} className={inputCls} />
                        </div>
                      ))}
                      <div className="grid grid-cols-3 gap-3 items-center">
                        <span className="text-sm font-medium text-card-foreground">DCTF Web</span>
                        <select value={form.dctf_web_gerada ? "sim" : "nao"} onChange={e => updateForm(emp.id, "dctf_web_gerada", e.target.value === "sim")} className={inputCls}>
                          <option value="nao">Não Gerada</option><option value="sim">Gerada</option>
                        </select>
                        {form.dctf_web_gerada ? (
                          <input type="date" value={form.dctf_web_data_envio || ""} onChange={e => updateForm(emp.id, "dctf_web_data_envio", e.target.value)} className={inputCls} />
                        ) : <div />}
                      </div>
                    </div>
                  </div>

                  <div className="flex justify-end"><button onClick={() => handleSave(emp.id)} className="flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold text-primary-foreground shadow-md" style={{ background: "var(--gradient-primary)" }}><Save size={14} /> Salvar</button></div>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default PessoalPage;

import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { FileBadge, FileText, Download, Eye, Clock, ShieldCheck, Search } from "lucide-react";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { toast } from "sonner";

const PortalCertidoesPage: React.FC = () => {
    const { userData } = useAuth();
    const [certidoes, setCertidoes] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState("");

    useEffect(() => {
        const loadCertidoes = async () => {
            if (!userData?.empresaId) return;

            const { data, error } = await supabase
                .from("certidoes")
                .select("*")
                .eq("empresa_id", userData.empresaId);

            if (error) {
                toast.error("Erro ao carregar certidões");
            } else {
                setCertidoes(data || []);
            }
            setLoading(false);
        };

        loadCertidoes();
    }, [userData]);

    const filtered = certidoes.filter(c =>
        c.tipo_certidao?.toLowerCase().includes(search.toLowerCase())
    );

    const calcDias = (data?: string | null) => {
        if (!data) return 999;
        return Math.ceil((new Date(data).getTime() - Date.now()) / 86400000);
    };

    if (loading) {
        return <div className="flex items-center justify-center h-64"><div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>;
    }

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                <div className="flex items-center gap-3">
                    <div className="w-12 h-12 rounded-2xl bg-primary/10 flex items-center justify-center text-primary shadow-inner">
                        <FileBadge size={24} />
                    </div>
                    <div>
                        <h1 className="text-2xl font-bold tracking-tight">Certidões Negativas (CND)</h1>
                        <p className="text-muted-foreground">Regularidade fiscal da sua empresa</p>
                    </div>
                </div>

                <div className="relative max-w-xs w-full">
                    <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
                    <Input
                        placeholder="Buscar certidão..."
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        className="pl-9 bg-card/50"
                    />
                </div>
            </div>

            {filtered.length === 0 ? (
                <Card className="border-dashed border-2 bg-muted/20">
                    <CardContent className="flex flex-col items-center justify-center py-12 text-center">
                        <ShieldCheck size={48} className="text-muted-foreground/30 mb-4" />
                        <p className="text-lg font-medium text-muted-foreground">
                            {search ? "Nenhuma certidão corresponde à sua busca." : "Nenhuma certidão anexada no momento."}
                        </p>
                    </CardContent>
                </Card>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {filtered.map((cert) => {
                        const dias = calcDias(cert.vencimento);
                        const isVencendo = dias <= 30 && dias >= 0;
                        const isVencido = dias < 0;

                        return (
                            <Card key={cert.id} className="overflow-hidden border-none shadow-md hover:shadow-lg transition-shadow bg-card/50 backdrop-blur-sm">
                                <CardHeader className="pb-2 border-b border-border/10 mb-2">
                                    <div className="flex items-center justify-between">
                                        <CardTitle className="text-base font-bold flex items-center gap-2">
                                            <FileText size={16} className="text-primary" />
                                            {cert.tipo_certidao}
                                        </CardTitle>
                                        <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-wider ${isVencido ? "bg-destructive/10 text-destructive" :
                                            isVencendo ? "bg-amber-500/10 text-amber-500" :
                                                "bg-green-500/10 text-green-500"
                                            }`}>
                                            {isVencido ? "Vencida" : isVencendo ? "A Vencer" : "Válida"}
                                        </span>
                                    </div>
                                </CardHeader>
                                <CardContent className="space-y-4">
                                    <div className="space-y-2">
                                        <div className="flex items-center justify-between text-xs">
                                            <span className="text-muted-foreground flex items-center gap-1">
                                                <Clock size={12} /> Validade:
                                            </span>
                                            <span className={`font-semibold ${isVencido ? "text-destructive" : isVencendo ? "text-amber-500" : ""}`}>
                                                {cert.vencimento ? new Date(cert.vencimento).toLocaleDateString("pt-BR") : "Indeterminada"}
                                            </span>
                                        </div>
                                    </div>

                                    <div className="flex gap-2 pt-2 border-t border-border/50">
                                        {cert.arquivo_url ? (
                                            <>
                                                <Button
                                                    variant="ghost"
                                                    size="sm"
                                                    className="flex-1 gap-2 text-xs"
                                                    onClick={() => window.open(cert.arquivo_url, "_blank")}
                                                >
                                                    <Eye size={14} /> Ver
                                                </Button>
                                                <Button
                                                    variant="secondary"
                                                    size="sm"
                                                    className="flex-1 gap-2 text-xs"
                                                    onClick={() => {
                                                        const a = document.createElement("a");
                                                        a.href = cert.arquivo_url;
                                                        a.download = `${cert.tipo_certidao}.pdf`;
                                                        a.target = "_blank";
                                                        a.click();
                                                    }}
                                                >
                                                    <Download size={14} /> Baixar
                                                </Button>
                                            </>
                                        ) : (
                                            <div className="w-full py-2 px-3 rounded-lg bg-muted text-center text-[10px] text-muted-foreground italic">
                                                Documento não anexado pela contabilidade
                                            </div>
                                        )}
                                    </div>
                                </CardContent>
                            </Card>
                        );
                    })}
                </div>
            )}
        </div>
    );
};

export default PortalCertidoesPage;

import React from "react";
import { useAuth } from "@/contexts/AuthContext";
import {
    Building2, FileText, CheckCircle, AlertCircle,
    ArrowRight, Download, MessageSquare, Clock, Search
} from "lucide-react";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { supabase } from "@/integrations/supabase/client";

const PortalDashboardPage: React.FC = () => {
    const { userData } = useAuth();
    const [empresa, setEmpresa] = React.useState<any>(null);
    const [counts, setCounts] = React.useState({ lics: 0, certs: 0, msgs: 0 });

    React.useEffect(() => {
        const load = async () => {
            if (!userData?.empresaId) return;

            // Get company name
            const { data: emp } = await supabase.from("empresas").select("nome_empresa").eq("id", userData.empresaId).single();
            if (emp) setEmpresa(emp);

            // Get counts
            const { count: licCount } = await supabase.from("licencas").select("*", { count: 'exact', head: true }).eq("empresa_id", userData.empresaId);
            const { count: certCount } = await supabase.from("certidoes").select("*", { count: 'exact', head: true }).eq("empresa_id", userData.empresaId);
            const { count: msgCount } = await supabase.from("internal_messages" as any).select("*", { count: 'exact', head: true }).eq("empresa_id", userData.empresaId).eq("lida", false).eq("direcao", "escritorio_para_cliente");

            setCounts({
                lics: licCount || 0,
                certs: certCount || 0,
                msgs: msgCount || 0
            });
        };
        load();
    }, [userData]);

    const stats = [
        { label: "Licenças Ativas", value: counts.lics.toString(), icon: FileText, color: "text-amber-500", bg: "bg-amber-500/10" },
        { label: "Certidões Disponíveis", value: counts.certs.toString(), icon: CheckCircle, color: "text-green-500", bg: "bg-green-500/10" },
        { label: "Mensagens Não Lidas", value: counts.msgs.toString(), icon: MessageSquare, color: "text-blue-500", bg: "bg-blue-500/10" },
    ];

    return (
        <div className="space-y-8 animate-fade-in">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h1 className="text-3xl font-bold tracking-tight">Bem-vindo, {userData?.nome}!</h1>
                    <p className="text-muted-foreground mt-1 text-lg">
                        Acompanhe a situação da sua empresa em tempo real.
                    </p>
                </div>
                <div className="flex items-center gap-3 bg-card p-4 rounded-2xl border border-border shadow-sm">
                    <div className="w-12 h-12 rounded-xl bg-primary/10 flex items-center justify-center text-primary">
                        <Building2 size={24} />
                    </div>
                    <div>
                        <p className="text-xs font-bold text-muted-foreground uppercase tracking-widest">Sua Empresa</p>
                        <p className="font-bold text-card-foreground truncate max-w-[200px]">
                            {empresa?.nome_empresa || "Carregando..."}
                        </p>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {stats.map((stat) => (
                    <Card key={stat.label} className="border-none shadow-md overflow-hidden group hover:shadow-lg transition-all">
                        <CardHeader className="flex flex-row items-center justify-between pb-2">
                            <CardTitle className="text-sm font-bold text-muted-foreground uppercase tracking-tight">
                                {stat.label}
                            </CardTitle>
                            <div className={`p-2 rounded-lg ${stat.bg} ${stat.color} group-hover:scale-110 transition-transform`}>
                                <stat.icon size={20} />
                            </div>
                        </CardHeader>
                        <CardContent>
                            <div className="text-3xl font-bold">{stat.value}</div>
                        </CardContent>
                    </Card>
                ))}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {/* Documentos Recentes */}
                <section className="space-y-4">
                    <div className="flex items-center justify-between">
                        <h3 className="text-xl font-bold flex items-center gap-2">
                            <FileText className="text-primary" size={22} /> Documentos Recentes
                        </h3>
                        <Button variant="ghost" size="sm" className="text-primary font-bold">Ver Todos</Button>
                    </div>
                    <div className="bg-card rounded-2xl border border-border overflow-hidden shadow-sm">
                        {[1, 2, 3].map((_, i) => (
                            <div key={i} className="flex items-center justify-between p-4 border-b border-border last:border-0 hover:bg-muted/30 transition-colors">
                                <div className="flex items-center gap-3">
                                    <div className="w-10 h-10 rounded-lg bg-muted flex items-center justify-center text-muted-foreground">
                                        <FileText size={18} />
                                    </div>
                                    <div>
                                        <p className="font-bold text-sm">Folha de Pagamento - 02/2026</p>
                                        <p className="text-xs text-muted-foreground">Disponibilizado em 05/03/2026</p>
                                    </div>
                                </div>
                                <Button variant="outline" size="icon" className="h-8 w-8 rounded-full">
                                    <Download size={14} />
                                </Button>
                            </div>
                        ))}
                    </div>
                </section>

                {/* Status de Processos */}
                <section className="space-y-4">
                    <div className="flex items-center justify-between">
                        <h3 className="text-xl font-bold flex items-center gap-2">
                            <Clock className="text-primary" size={22} /> Status de Processos
                        </h3>
                        <Button variant="ghost" size="sm" className="text-primary font-bold">Ver Todos</Button>
                    </div>
                    <div className="bg-card rounded-2xl border border-border p-6 shadow-sm">
                        <div className="relative pl-8 space-y-8">
                            <div className="absolute left-[15px] top-2 bottom-2 w-0.5 bg-muted" />

                            <div className="relative">
                                <div className="absolute -left-[24px] top-0 w-4 h-4 rounded-full bg-green-500 ring-4 ring-background" />
                                <div>
                                    <p className="font-bold text-sm">Abertura de Empresa</p>
                                    <p className="text-xs text-muted-foreground">Etapa: Arquivamento na Junta</p>
                                    <div className="mt-2 text-[10px] font-bold px-2 py-0.5 bg-green-500/10 text-green-500 rounded-full inline-block uppercase">
                                        Concluído
                                    </div>
                                </div>
                            </div>

                            <div className="relative">
                                <div className="absolute -left-[24px] top-0 w-4 h-4 rounded-full bg-primary ring-4 ring-background animate-pulse" />
                                <div>
                                    <p className="font-bold text-sm">Alteração Contratual</p>
                                    <p className="text-xs text-muted-foreground">Etapa: Coleta de Assinaturas</p>
                                    <div className="mt-2 text-[10px] font-bold px-2 py-0.5 bg-primary/10 text-primary rounded-full inline-block uppercase animate-pulse">
                                        Em Andamento
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </section>
            </div>

            {/* Informativos/Mensagens */}
