import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { CalendarClock, ShieldAlert, History, ArrowRight, Building2, UserCircle, MapPin, Scale, FileSignature, Briefcase, Zap } from "lucide-react";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { toast } from "sonner";

const PortalVencimentosPage: React.FC = () => {
    const { userData } = useAuth();
    const [vencimentos, setVencimentos] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const loadVencimentos = async () => {
            if (!userData?.empresaId) return;

            const results = [];

            // 1. Licenças
            const { data: lics } = await supabase.from("licencas").select("*").eq("empresa_id", userData.empresaId).not("vencimento", "is", null);
            if (lics) results.push(...lics.map(l => ({ tipo: "Licença", titulo: l.tipo_licenca, data: l.vencimento, id: l.id })));

            // 2. Certidões
            const { data: certs } = await supabase.from("certidoes").select("*").eq("empresa_id", userData.empresaId).not("vencimento", "is", null);
            if (certs) results.push(...certs.map(c => ({ tipo: "Certidão", titulo: c.tipo_certidao, data: c.vencimento, id: c.id })));

            // 3. Certificados Digitais
            const { data: digi } = await supabase.from("certificados_digitais").select("*").eq("empresa_id", userData.empresaId).not("data_vencimento", "is", null);
            if (digi) results.push(...digi.map(d => ({ tipo: "Certificado Digital", titulo: "e-CNPJ / e-CPF", data: d.data_vencimento, id: d.id })));

            setVencimentos(results.sort((a, b) => new Date(a.data).getTime() - new Date(b.data).getTime()));
            setLoading(false);
        };

        loadVencimentos();
    }, [userData]);

    const calcDias = (data: string) => Math.ceil((new Date(data).getTime() - Date.now()) / 86400000);

    if (loading) {
        return <div className="flex items-center justify-center h-64"><div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>;
    }

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="flex items-center gap-3">
                <div className="w-12 h-12 rounded-2xl bg-amber-500/10 flex items-center justify-center text-amber-500 shadow-inner">
                    <CalendarClock size={24} />
                </div>
                <div>
                    <h1 className="text-2xl font-bold tracking-tight">Próximos Vencimentos</h1>
                    <p className="text-muted-foreground">Fique atento aos prazos e renovações</p>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="lg:col-span-2 space-y-4">
                    {vencimentos.length === 0 ? (
                        <Card className="bg-muted/10 border-dashed">
                            <CardContent className="py-12 text-center text-muted-foreground">
                                Nenhum vencimento registrado para os próximos períodos.
                            </CardContent>
                        </Card>
                    ) : (
                        vencimentos.map((v, i) => {
                            const dias = calcDias(v.data);
                            const isVencido = dias < 0;
                            const isCritico = dias <= 7 && dias >= 0;

                            return (
                                <div key={i} className="flex items-center justify-between p-4 bg-card rounded-xl border border-border shadow-sm hover:shadow-md transition-all group">
                                    <div className="flex items-center gap-4">
                                        <div className={`w-10 h-10 rounded-lg flex items-center justify-center ${isVencido ? "bg-destructive/10 text-destructive" :
                                            isCritico ? "bg-amber-500/10 text-amber-500" :
                                                "bg-primary/10 text-primary"
                                            }`}>
                                            {isVencido ? <ShieldAlert size={20} /> : <History size={20} />}
                                        </div>
                                        <div>
                                            <p className="text-xs text-muted-foreground uppercase tracking-widest font-bold">{v.tipo}</p>
                                            <p className="font-bold text-card-foreground group-hover:text-primary transition-colors">{v.titulo}</p>
                                        </div>
                                    </div>
                                    <div className="text-right">
                                        <p className={`font-bold ${isVencido ? "text-destructive" : isCritico ? "text-amber-500" : "text-card-foreground"}`}>
                                            {new Date(v.data).toLocaleDateString("pt-BR")}
                                        </p>
                                        <p className="text-[10px] text-muted-foreground">
                                            {isVencido ? `Vencido há ${Math.abs(dias)} dias` : `${dias} dias restantes`}
                                        </p>
                                    </div>
                                </div>
                            );
                        })
                    )}
                </div>

                <div className="space-y-6">
                    <Card className="bg-primary/5 border-primary/20">
                        <CardHeader>
                            <CardTitle className="text-sm font-bold flex items-center gap-2">
                                <ShieldAlert size={16} className="text-primary" /> Sugestões de Renovação
                            </CardTitle>
                        </CardHeader>
                        <CardContent className="text-xs space-y-4 text-muted-foreground leading-relaxed">
                            <p>Recomendamos iniciar o processo de renovação de licenças municipais com pelo menos <strong>45 dias</strong> de antecedência.</p>
                            <p>Certificados digitais tipo A1 expiram em 1 ano. Entre em contato para agendar a renovação.</p>
                            <ArrowRight size={24} className="text-primary opacity-20 ml-auto" />
                        </CardContent>
                    </Card>
                </div>
            </div>
        </div>
    );
};

export default PortalVencimentosPage;

import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Search, AlertTriangle, CheckCircle, Clock, ChevronDown, ChevronUp, Save, Building2 } from "lucide-react";
import { toast } from "sonner";
import { useEmpresas } from "@/hooks/useEmpresas";

const calcDias = (data?: string | null) => { if (!data) return 999; return Math.ceil((new Date(data).getTime() - Date.now()) / 86400000); };

const ProcuracoesPage: React.FC = () => {
  const { empresas, loading } = useEmpresas("procuracoes");
  const [procData, setProcData] = useState<Record<string, any>>({});
  const [search, setSearch] = useState("");
  const [filterStatus, setFilterStatus] = useState("todos");
  const [expanded, setExpanded] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Record<string, any>>({});
  const [activeTab, setActiveTab] = useState<"ativas" | "mei" | "paralisadas" | "baixadas">("ativas");

  useEffect(() => {
    const load = async () => {
      const { data: procs } = await supabase.from("procuracoes").select("*");
      const map: Record<string, any> = {};
      procs?.forEach(p => { map[p.empresa_id] = p; });
      setProcData(map);
    };
    load();
  }, []);

  const empresasWithProc = empresas.map(emp => {
    const proc = procData[emp.id] || {};
    const dias = calcDias(proc.data_vencimento);
    const status = dias === 999 ? "sem_dados" : dias < 0 ? "vencida" : dias <= 30 ? "proxima" : "ativa";
    return { ...emp, proc, dias, status };
  });

  const filtered = empresasWithProc.filter(e => {
    const matchSearch = e.nome_empresa?.toLowerCase().includes(search.toLowerCase()) || e.cnpj?.includes(search);
    const matchStatus = filterStatus === "todos" || e.status === filterStatus;

    let matchTab = false;
    if (activeTab === "ativas") {
      matchTab = (!e.situacao || e.situacao === "ativa") && e.porte_empresa !== "mei";
    } else if (activeTab === "mei") {
      matchTab = (!e.situacao || e.situacao === "ativa") && e.porte_empresa === "mei";
    } else if (activeTab === "paralisadas") {
      matchTab = e.situacao === "paralisada";
    } else if (activeTab === "baixadas") {
      matchTab = e.situacao === "baixada";
    }

    return matchSearch && matchStatus && matchTab;
  });

  const counts = {
    ativas: filtered.filter(e => e.status === "ativa").length,
    proximas: filtered.filter(e => e.status === "proxima").length,
    vencidas: filtered.filter(e => e.status === "vencida").length,
    semDados: filtered.filter(e => e.status === "sem_dados").length
  };

  const toggleExpand = (id: string) => {
    if (expanded === id) { setExpanded(null); return; }
    setExpanded(id);
    const emp = empresasWithProc.find(e => e.id === id);
    if (emp) setEditForm(prev => ({ ...prev, [id]: { data_cadastro: emp.proc.data_cadastro || "", data_vencimento: emp.proc.data_vencimento || "", observacao: emp.proc.observacao || "" } }));
  };

  const handleSave = async (empresaId: string) => {
    const form = editForm[empresaId];
    const existing = procData[empresaId];
    try {
      if (existing?.id) {
        await supabase.from("procuracoes").update({ data_cadastro: form.data_cadastro || null, data_vencimento: form.data_vencimento || null, observacao: form.observacao || null }).eq("id", existing.id);
      } else {
        await supabase.from("procuracoes").insert({ empresa_id: empresaId, data_cadastro: form.data_cadastro || null, data_vencimento: form.data_vencimento || null, observacao: form.observacao || null });
      }
      toast.success("Procuração atualizada!");
      // Reload
      const { data: procs } = await supabase.from("procuracoes").select("*");
      const map: Record<string, any> = {};
      procs?.forEach(p => { map[p.empresa_id] = p; });
      setProcData(map);
    } catch (err: any) { toast.error(err.message); }
  };

  const inputCls = "w-full px-3 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none";
  const labelCls = "block text-xs font-medium text-muted-foreground mb-1";

  if (loading) {
    return <div className="flex items-center justify-center h-64"><div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>;
  }

  return (
    <div className="space-y-6 animate-fade-in">

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {[{ label: "Ativas", count: counts.ativas, cls: "text-success", bg: "bg-success/10", icon: <CheckCircle size={20} /> }, { label: "Próximas", count: counts.proximas, cls: "text-warning", bg: "bg-warning/10", icon: <Clock size={20} /> }, { label: "Vencidas", count: counts.vencidas, cls: "text-destructive", bg: "bg-destructive/10", icon: <AlertTriangle size={20} /> }, { label: "Sem Dados", count: counts.semDados, cls: "text-muted-foreground", bg: "bg-muted", icon: <AlertTriangle size={20} /> }].map(s => (
          <div key={s.label} className="stat-card flex items-center justify-between"><div><p className="text-xs text-muted-foreground uppercase tracking-wide">{s.label}</p><p className={`text-2xl font-bold mt-1 ${s.cls}`}>{s.count}</p></div><div className={`w-10 h-10 rounded-xl flex items-center justify-center ${s.bg} ${s.cls}`}>{s.icon}</div></div>
        ))}
      </div>
      <div className="flex flex-col sm:flex-row gap-3">
        <div className="relative flex-1 max-w-sm"><Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" /><input type="text" placeholder="Buscar empresa..." value={search} onChange={e => setSearch(e.target.value)} className="w-full pl-9 pr-4 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" /></div>
        <div className="flex gap-2 flex-wrap">{[{ key: "todos", label: "Todos" }, { key: "ativa", label: "Ativas" }, { key: "proxima", label: "Próximas" }, { key: "vencida", label: "Vencidas" }, { key: "sem_dados", label: "Sem Dados" }].map(f => (<button key={f.key} onClick={() => setFilterStatus(f.key)} className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-colors ${filterStatus === f.key ? "bg-primary text-primary-foreground" : "bg-muted text-muted-foreground hover:text-foreground"}`}>{f.label}</button>))}</div>
      </div>
      <div className="flex border-b border-border overflow-x-auto no-scrollbar">
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "ativas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("ativas")}
        >
          Empresas Ativas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "mei"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("mei")}
        >
          Empresas MEI
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "paralisadas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("paralisadas")}
        >
          Empresas Paralisadas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "baixadas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("baixadas")}
        >
          Empresas Baixadas
        </button>
      </div>
      <div className="space-y-3">
        {filtered.map(emp => {
          const isOpen = expanded === emp.id;
          const form = editForm[emp.id] || {};
          const statusCls = emp.status === "vencida" ? "badge-danger" : emp.status === "proxima" ? "badge-warning" : emp.status === "ativa" ? "badge-success" : "badge-gray";
          const statusLabel = emp.status === "vencida" ? "Vencida" : emp.status === "proxima" ? "Próxima" : emp.status === "ativa" ? "Ativa" : "Sem dados";
          return (
            <div key={emp.id} className="module-card !p-0 overflow-hidden">
              <div className="flex items-center justify-between p-4 cursor-pointer hover:bg-muted/30 transition-colors" onClick={() => toggleExpand(emp.id)}>
                <div className="flex items-center gap-3"><div className="w-9 h-9 rounded-lg bg-primary/10 flex items-center justify-center flex-shrink-0"><Building2 size={16} className="text-primary" /></div><div><p className="font-medium text-card-foreground">{emp.nome_empresa}</p><p className="text-xs text-muted-foreground">{emp.cnpj || "—"}</p></div></div>
                <div className="flex items-center gap-3">{emp.proc.data_vencimento && <span className="text-xs text-muted-foreground">Venc: {new Date(emp.proc.data_vencimento).toLocaleDateString("pt-BR")}</span>}<span className={`badge-status ${statusCls}`}>{statusLabel}</span>{isOpen ? <ChevronUp size={16} className="text-muted-foreground" /> : <ChevronDown size={16} className="text-muted-foreground" />}</div>
              </div>
              {isOpen && (
                <div className="border-t border-border p-5 space-y-4 bg-muted/10">
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    <div><label className={labelCls}>Data de Cadastro</label><input type="date" value={form.data_cadastro || ""} onChange={e => setEditForm(prev => ({ ...prev, [emp.id]: { ...prev[emp.id], data_cadastro: e.target.value } }))} className={inputCls} /></div>
                    <div><label className={labelCls}>Data de Validade</label><input type="date" value={form.data_vencimento || ""} onChange={e => setEditForm(prev => ({ ...prev, [emp.id]: { ...prev[emp.id], data_vencimento: e.target.value } }))} className={inputCls} /></div>
                    <div><label className={labelCls}>Observação</label><input value={form.observacao || ""} onChange={e => setEditForm(prev => ({ ...prev, [emp.id]: { ...prev[emp.id], observacao: e.target.value } }))} className={inputCls} /></div>
                  </div>
                  <div className="flex justify-end"><button onClick={() => handleSave(emp.id)} className="flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold text-primary-foreground shadow-md" style={{ background: "var(--gradient-primary)" }}><Save size={14} /> Salvar</button></div>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default ProcuracoesPage;

import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Search, Plus, ChevronDown, ChevronUp, Save, CheckCircle, Circle, Users, Building2 } from "lucide-react";
import { toast } from "sonner";
import { useEmpresas } from "@/hooks/useEmpresas";

const regimeLabels: Record<string, string> = { simples: "Simples Nacional", lucro_presumido: "Lucro Presumido", lucro_real: "Lucro Real", mei: "MEI" };

const RecalculosPage: React.FC = () => {
  const { empresas, loading } = useEmpresas("recalculos");
  const [parcelamentos, setParcelamentos] = useState<any[]>([]);
  const [recalculos, setRecalculos] = useState<any[]>([]);

  const [search, setSearch] = useState("");
  const [competencia, setCompetencia] = useState(new Date().toISOString().slice(0, 7));
  const [expanded, setExpanded] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Record<string, any>>({});
  const [activeTab, setActiveTab] = useState<"ativas" | "paralisadas" | "baixadas">("ativas");

  // Inline Form State
  const [showNovoForm, setShowNovoForm] = useState(false);
  const [newRecalculo, setNewRecalculo] = useState({
    empresa_id: "",
    parcelamento_id: "",
    modulo_origem: "Fiscal",
    guia: "",
    data_recalculo: "",
    data_envio: "",
    forma_envio: "",
  });

  const loadData = async () => {
    // Load Parcelamentos (Clients)
    const { data: parcs } = await supabase.from("parcelamentos").select("*").order("nome_pessoa_fisica");
    setParcelamentos(parcs || []);

    // Load Recalculos
    const { data: recs } = await supabase
      .from("recalculos")
      .select(`
        *, 
        empresas(nome_empresa, cnpj, regime_tributario, situacao),
        parcelamentos(nome_pessoa_fisica, cpf_pessoa_fisica, tipo_parcelamento)
      `)
      .eq("competencia", competencia)
      .order("created_at", { ascending: false });
    setRecalculos(recs || []);
  };

  useEffect(() => {
    loadData();
  }, [competencia]);

  const filtered = recalculos.filter(r => {
    const nomeEmpresa = r.empresas?.nome_empresa || "";
    const nomePessoa = r.parcelamentos?.nome_pessoa_fisica || "";
    const termoBusca = search.toLowerCase();

    const matchSearch = nomeEmpresa.toLowerCase().includes(termoBusca) ||
      nomePessoa.toLowerCase().includes(termoBusca) ||
      r.guia?.toLowerCase().includes(termoBusca) ||
      r.modulo_origem?.toLowerCase().includes(termoBusca);

    let matchTab = false;
    // Se for parcelamento, mostra em "Ativas" por padrão, já que não tem a "situação" da empresa diretamente atrelada ao PF
    const situacao = r.empresas?.situacao;
    if (activeTab === "ativas") {
      matchTab = !situacao || situacao === "ativa";
    } else if (activeTab === "paralisadas") {
      matchTab = situacao === "paralisada";
    } else if (activeTab === "baixadas") {
      matchTab = situacao === "baixada";
    }

    return matchSearch && matchTab;
  });

  const toggleExpand = (id: string, recalculo: any) => {
    if (expanded === id) { setExpanded(null); return; }
    setExpanded(id);
    setEditForm({
      ...editForm,
      [id]: {
        status: recalculo.status || "pendente",
        data_envio: recalculo.data_envio || "",
        forma_envio: recalculo.forma_envio || "",
      }
    });
  };

  const handleSaveUpdate = async (id: string) => {
    const form = editForm[id];
    try {
      const { error } = await supabase.from("recalculos").update({
        status: form.status,
        data_envio: form.data_envio || null,
        forma_envio: form.forma_envio || null,
      }).eq("id", id);

      if (error) throw error;
      toast.success("Recálculo atualizado com sucesso!");
      loadData();
    } catch (err: any) {
      toast.error(err.message);
    }
  };

  const updateForm = (id: string, field: string, value: any) => {
    setEditForm(prev => ({ ...prev, [id]: { ...prev[id], [field]: value } }));
  };

  const handleCreateRecalculo = async () => {
    try {
      const isParcelamento = newRecalculo.modulo_origem === "Parcelamentos";

      if (isParcelamento && !newRecalculo.parcelamento_id) {
        toast.error("Selecione o Cliente do Parcelamento");
        return;
      }
      if (!isParcelamento && !newRecalculo.empresa_id) {
        toast.error("Selecione a Empresa");
        return;
      }
      if (!newRecalculo.guia) {
        toast.error("Preencha a descrição da Guia");
        return;
      }

      const payload = {
        empresa_id: isParcelamento ? null : newRecalculo.empresa_id,
        parcelamento_id: isParcelamento ? newRecalculo.parcelamento_id : null,
        modulo_origem: newRecalculo.modulo_origem,
        guia: newRecalculo.guia,
        competencia,
        data_recalculo: newRecalculo.data_recalculo || null,
        data_envio: newRecalculo.data_envio || null,
        forma_envio: newRecalculo.forma_envio || null,
        status: "pendente" as any
      };

      const { error } = await supabase.from("recalculos").insert(payload);
      if (error) throw error;

      toast.success("Recálculo cadastrado com sucesso!");
      setShowNovoForm(false);
      setNewRecalculo({ empresa_id: "", parcelamento_id: "", modulo_origem: "Fiscal", guia: "", data_recalculo: "", data_envio: "", forma_envio: "" });
      loadData();
    } catch (err: any) {
      toast.error("Erro ao salvar recálculo: " + err.message);
    }
  };

  const inputCls = "w-full px-3 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none transition-all";
  const labelCls = "block text-xs font-medium text-muted-foreground mb-1";
  const completedCount = filtered.filter(r => r.status === "enviada" || r.status === "gerada").length;

  if (loading) {
    return <div className="flex items-center justify-center h-64"><div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>;
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-end gap-4">
        <div className="flex items-center gap-3 w-full sm:w-auto">
          <label className="text-sm font-medium text-muted-foreground whitespace-nowrap hidden sm:block">Mês:</label>
          <input
            type="month"
            value={competencia}
            onChange={e => setCompetencia(e.target.value)}
            className="w-full sm:w-auto px-4 py-2 border border-border rounded-xl bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none font-semibold shadow-sm"
          />
          <button
            onClick={() => setShowNovoForm(!showNovoForm)}
            className={`flex items-center justify-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold transition-all shadow-md w-full sm:w-auto ${showNovoForm
              ? "bg-muted text-foreground border border-border hover:bg-muted/80"
              : "text-primary-foreground hover:opacity-90 active:scale-95"
              }`}
            style={!showNovoForm ? { background: "var(--gradient-primary)" } : {}}
          >
            {showNovoForm ? "Cancelar" : <><Plus size={16} /> Cadastrar Recálculo</>}
          </button>
        </div>
      </div>

      {showNovoForm && (
        <div className="bg-card border border-primary/20 p-5 rounded-xl shadow-sm animate-fade-in">
          <h2 className="text-lg font-bold text-card-foreground mb-4 flex items-center gap-2"><Plus size={18} className="text-primary" /> Novo Recálculo - {competencia}</h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className={labelCls}>Módulo de Origem</label>
              <select
                value={newRecalculo.modulo_origem}
                onChange={e => setNewRecalculo({ ...newRecalculo, modulo_origem: e.target.value, empresa_id: "", parcelamento_id: "" })}
                className={inputCls}
              >
                <option value="Fiscal">Fiscal</option>
                <option value="Pessoal">Pessoal / RH</option>
                <option value="Licenças">Licenças</option>
                <option value="Parcelamentos">Parcelamentos</option>
              </select>
            </div>

            {newRecalculo.modulo_origem === "Parcelamentos" ? (
              <div>
                <label className={labelCls}>Cliente do Parcelamento</label>
                <select value={newRecalculo.parcelamento_id} onChange={e => setNewRecalculo({ ...newRecalculo, parcelamento_id: e.target.value })} className={inputCls}>
                  <option value="">Selecione o cliente...</option>
                  {parcelamentos.map(p => (
                    <option key={p.id} value={p.id}>{p.nome_pessoa_fisica}</option>
                  ))}
                </select>
              </div>
            ) : (
              <div>
                <label className={labelCls}>Empresa</label>
                <select value={newRecalculo.empresa_id} onChange={e => setNewRecalculo({ ...newRecalculo, empresa_id: e.target.value })} className={inputCls}>
                  <option value="">Selecione a empresa...</option>
                  {empresas.map(emp => (
                    <option key={emp.id} value={emp.id}>{emp.nome_empresa}</option>
                  ))}
                </select>
              </div>
            )}

            <div>
              <label className={labelCls}>Guia (Descrição manual)</label>
              <input value={newRecalculo.guia} onChange={e => setNewRecalculo({ ...newRecalculo, guia: e.target.value })} className={inputCls} placeholder="Ex: DAS Maior, INSS Ref..." />
            </div>

            <div>
              <label className={labelCls}>Forma de Envio</label>
              <input value={newRecalculo.forma_envio} onChange={e => setNewRecalculo({ ...newRecalculo, forma_envio: e.target.value })} className={inputCls} placeholder="Ex: WhatsApp, Email..." />
            </div>

            <div>
              <label className={labelCls}>Data do Recálculo</label>
              <input type="date" value={newRecalculo.data_recalculo} onChange={e => setNewRecalculo({ ...newRecalculo, data_recalculo: e.target.value })} className={inputCls} />
            </div>

            <div>
              <label className={labelCls}>Data de Envio</label>
              <input type="date" value={newRecalculo.data_envio} onChange={e => setNewRecalculo({ ...newRecalculo, data_envio: e.target.value })} className={inputCls} />
            </div>
          </div>

          <div className="mt-5 flex justify-end">
            <button onClick={handleCreateRecalculo} className="flex items-center gap-2 px-6 py-2 rounded-lg text-sm font-semibold text-primary-foreground shadow-md transition-all hover:opacity-90" style={{ background: "var(--gradient-primary)" }}>
              <Save size={16} /> Salvar Recálculo
            </button>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
        <div className="stat-card"><p className="text-xs text-muted-foreground uppercase font-medium">Total de Guias</p><p className="text-2xl font-bold text-primary mt-1">{filtered.length}</p></div>
        <div className="stat-card"><p className="text-xs text-muted-foreground uppercase font-medium">Concluídas</p><p className="text-2xl font-bold text-success mt-1">{completedCount}</p></div>
        <div className="stat-card"><p className="text-xs text-muted-foreground uppercase font-medium">Pendentes</p><p className="text-2xl font-bold text-warning mt-1">{filtered.length - completedCount}</p></div>
      </div>

      <div className="relative max-w-md">
        <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
        <input type="text" placeholder="Buscar por cliente, empresa, guia ou módulo..." value={search} onChange={e => setSearch(e.target.value)} className="w-full pl-9 pr-4 py-2.5 border border-border rounded-xl bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none shadow-sm transition-all" />
      </div>

      <div className="flex border-b border-border overflow-x-auto no-scrollbar">
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "ativas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("ativas")}
        >
          Empresas Ativas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "paralisadas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("paralisadas")}
        >
          Empresas Paralisadas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "baixadas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("baixadas")}
        >
          Empresas Baixadas
        </button>
      </div>

      <div className="space-y-3">
        {filtered.length === 0 ? (
          <div className="module-card text-center py-12 text-muted-foreground border border-dashed border-border rounded-xl">
            {search ? "Nenhum resultado encontrado para a busca." : "Nenhum recálculo cadastrado para esta competência."}
          </div>
        ) : (
          filtered.map(r => {
            const isOpen = expanded === r.id;
            const form = editForm[r.id] || {};
            const done = r.status === "enviada" || r.status === "gerada";

            // Determine display names based on Origin
            const isParcelamento = r.modulo_origem === "Parcelamentos";
            const displayName = isParcelamento ? r.parcelamentos?.nome_pessoa_fisica : r.empresas?.nome_empresa;
            const displayDoc = isParcelamento ? r.parcelamentos?.cpf_pessoa_fisica : r.empresas?.cnpj;
            const displayExtra = isParcelamento ? r.parcelamentos?.tipo_parcelamento : regimeLabels[r.empresas?.regime_tributario];

            return (
              <div key={r.id} className="module-card !p-0 overflow-hidden">
                <div className="flex flex-col sm:flex-row sm:items-center justify-between p-4 cursor-pointer hover:bg-muted/30 transition-colors gap-4" onClick={() => toggleExpand(r.id, r)}>
                  <div className="flex items-start sm:items-center gap-3">
                    <div className="mt-1 sm:mt-0">
                      {done ? <CheckCircle size={20} className="text-success" /> : <Circle size={20} className="text-muted-foreground" />}
                    </div>
                    <div>
                      <div className="flex flex-wrap items-center gap-2">
                        <p className="font-semibold text-card-foreground text-sm sm:text-base">{displayName}</p>
                        <span className="text-[10px] font-bold px-2 py-0.5 rounded-full bg-primary/10 text-primary uppercase tracking-wider whitespace-nowrap flex items-center gap-1">
                          {isParcelamento ? <Users size={10} /> : <Building2 size={10} />}
                          {r.modulo_origem}
                        </span>
                      </div>
                      <p className="text-xs text-muted-foreground mt-1">
                        <strong className="text-foreground">{r.guia}</strong> • {displayDoc || "S/N"} {displayExtra ? `• ${displayExtra}` : ""}
                      </p>
                    </div>
                  </div>
                  <div className="flex items-center justify-between sm:justify-end gap-3 w-full sm:w-auto mt-2 sm:mt-0">
                    <span className={`badge-status ${done ? "badge-success" : "badge-warning"}`}>{done ? "Concluído" : "Pendente"}</span>
                    {isOpen ? <ChevronUp size={18} className="text-muted-foreground" /> : <ChevronDown size={18} className="text-muted-foreground" />}
                  </div>
                </div>

                {isOpen && (
                  <div className="border-t border-border bg-muted/10">
                    <div className="p-5 space-y-5">
                      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                        <div>
                          <label className={labelCls}>Status da Guia</label>
                          <select value={form.status || "pendente"} onChange={e => updateForm(r.id, "status", e.target.value)} className={inputCls}>
                            <option value="pendente">Pendente para Envio</option>
                            <option value="gerada">Em Andamento</option>
                            <option value="enviada">Concluída / Enviada</option>
                          </select>
                        </div>
                        <div>
                          <label className={labelCls}>Data de Envio</label>
                          <input type="date" value={form.data_envio || ""} onChange={e => updateForm(r.id, "data_envio", e.target.value)} className={inputCls} />
                        </div>
                        <div>
                          <label className={labelCls}>Forma de Envio</label>
                          <input value={form.forma_envio || ""} onChange={e => updateForm(r.id, "forma_envio", e.target.value)} className={inputCls} placeholder="Ex: Email, WhatsApp..." />
                        </div>
                      </div>
                      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 text-xs text-muted-foreground border-t border-border pt-4 mt-2">
                        <span className="bg-background px-3 py-1.5 rounded-md border border-border inline-block">
                          📆 Data Base do Recálculo: <strong className="text-foreground">{r.data_recalculo ? new Date(r.data_recalculo).toLocaleDateString('pt-BR') : "Não informada"}</strong>
                        </span>
                        <button onClick={() => handleSaveUpdate(r.id)} className="flex items-center justify-center gap-2 px-6 py-2 rounded-lg text-sm font-semibold text-primary-foreground shadow-md transition-all hover:opacity-90 active:scale-95 w-full sm:w-auto" style={{ background: "var(--gradient-primary)" }}>
                          <Save size={14} /> Atualizar Guia
                        </button>
                      </div>
                    </div>
                  </div>
                )}
              </div>
            );
          })
        )}
      </div>
    </div>
  );
};

export default RecalculosPage;

import React, { useState, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useNavigate } from "react-router-dom";
import { Loader2, Lock, CheckCircle2, AlertCircle } from "lucide-react";
import { toast } from "sonner";
import logoAudipreve from "@/assets/logo-audipreve.png";

const ResetPasswordPage: React.FC = () => {
    const navigate = useNavigate();
    const [password, setPassword] = useState("");
    const [confirmPassword, setConfirmPassword] = useState("");
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");
    const [success, setSuccess] = useState(false);

    useEffect(() => {
        // Verificar se há erro na URL (ex: link expirado)
        const hash = window.location.hash;
        if (hash && hash.includes("error_description")) {
            const params = new URLSearchParams(hash.substring(1));
            const errorDesc = params.get("error_description");
            if (errorDesc) {
                setError(decodeURIComponent(errorDesc).replace(/\+/g, ' '));
            }
        }

        // Verificar se chegamos aqui via link de reset
        const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
            if (event !== "PASSWORD_RECOVERY") {
                // Se não for evento de recuperação, e não tiver sessão, testar o que fazer
                // Não forçamos redirect pra mostrar o erro primeiro
            }
        });

        return () => subscription.unsubscribe();
    }, []);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError("");

        if (password.length < 8) {
            setError("A senha deve ter pelo menos 8 caracteres.");
            return;
        }

        if (password !== confirmPassword) {
            setError("As senhas não coincidem.");
            return;
        }

        setLoading(true);
        try {
            const { error: updateError } = await supabase.auth.updateUser({
                password: password,
            });

            if (updateError) throw updateError;

            setSuccess(true);
            toast.success("Senha alterada com sucesso!");
            setTimeout(() => navigate("/login"), 3000);
        } catch (err: any) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
    };

    if (success) {
        return (
            <div className="min-h-screen flex items-center justify-center p-4">
                <div className="bg-card border border-border rounded-2xl shadow-xl w-full max-w-md p-8 text-center space-y-6">
                    <div className="w-16 h-16 bg-success/10 text-success rounded-full flex items-center justify-center mx-auto">
                        <CheckCircle2 size={32} />
                    </div>
                    <h2 className="text-2xl font-bold">Senha Alterada!</h2>
                    <p className="text-muted-foreground">
                        Sua senha foi redefinida com sucesso. Você será redirecionado para o login em instantes.
                    </p>
                    <button onClick={() => navigate("/login")} className="w-full py-3 rounded-xl font-bold bg-primary text-primary-foreground transition-all">
                        Ir para o Login Agora
                    </button>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen flex items-center justify-center p-4">
            <div className="bg-card border border-border rounded-2xl shadow-xl w-full max-w-md overflow-hidden p-8 space-y-8 animate-fade-in">
                <div className="text-center">
                    <img src={logoAudipreve} alt="Audipreve" className="w-20 h-20 object-contain mx-auto mb-6" />
                    <h2 className="text-2xl font-bold text-card-foreground">Nova Senha</h2>
                    <p className="text-muted-foreground mt-2 text-sm">Defina sua nova senha de acesso.</p>
                </div>

                <form onSubmit={handleSubmit} className="space-y-6">
                    <div className="space-y-4">
                        <div>
                            <label className="block text-sm font-semibold text-muted-foreground mb-1.5 ml-1">Nova Senha</label>
                            <div className="relative">
                                <Lock size={18} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-muted-foreground" />
                                <input
                                    type="password"
                                    placeholder="********"
                                    value={password}
                                    onChange={e => setPassword(e.target.value)}
                                    required
                                    className="w-full pl-11 pr-4 py-3 border border-border rounded-xl bg-background focus:ring-2 focus:ring-primary outline-none transition-all"
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-semibold text-muted-foreground mb-1.5 ml-1">Confirmar Senha</label>
                            <div className="relative">
                                <Lock size={18} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-muted-foreground" />
                                <input
                                    type="password"
                                    placeholder="********"
                                    value={confirmPassword}
                                    onChange={e => setConfirmPassword(e.target.value)}
                                    required
                                    className="w-full pl-11 pr-4 py-3 border border-border rounded-xl bg-background focus:ring-2 focus:ring-primary outline-none transition-all"
                                />
                            </div>
                        </div>
                    </div>

                    {error && (
                        <div className="flex gap-3 p-4 bg-destructive/10 border border-destructive/20 rounded-xl text-destructive">
                            <AlertCircle size={18} className="shrink-0 mt-0.5" />
                            <p className="text-sm font-medium">{error}</p>
                        </div>
                    )}

                    <button
                        type="submit"
                        disabled={loading}
                        className="w-full py-4 rounded-xl font-bold text-primary-foreground shadow-lg transition-all hover:scale-[1.02] disabled:opacity-50"
                        style={{ background: "var(--gradient-primary)" }}
                    >
                        {loading ? <Loader2 className="animate-spin mx-auto" size={20} /> : "Redefinir Senha"}
                    </button>
                </form>
            </div>
        </div>
    );
};

export default ResetPasswordPage;

import React, { useEffect, useState } from "react";
import { useParams, useNavigate, useLocation } from "react-router-dom";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import { useAuth } from "@/contexts/AuthContext";
import { ArrowLeft, Save, Building2, MapPin, Users, ScrollText, Plus, Trash2, Crown, Calendar as CalendarIcon, FileText, Settings, Shield, CheckCircle, Upload, Eye } from "lucide-react";
import { maskCNPJ, maskCPF } from "@/lib/utils";

interface Socio { id?: string; nome: string; cpf: string; administrador: boolean; }
interface LicencaRow { id?: string; tipo_licenca: string; status: string | null; vencimento: string | null; numero_processo: string | null; }
interface Endereco { logradouro: string; numero: string; bairro: string; cidade: string; estado: string; cep: string; }

const emptyEndereco: Endereco = { logradouro: "", numero: "", bairro: "", cidade: "", estado: "", cep: "" };

const tabs = [
  { id: "dados", label: "Dados Gerais", icon: <Building2 size={16} /> },
  { id: "endereco", label: "Endereço", icon: <MapPin size={16} /> },
  { id: "socios", label: "Sócios", icon: <Users size={16} /> },
  { id: "licencas", label: "Licenças Municipais", icon: <ScrollText size={16} /> },
  { id: "configuracoes", label: "Configurações", icon: <Settings size={16} /> },
];

const licencaLabels: Record<string, string> = { alvara: "Alvará de Funcionamento", vigilancia_sanitaria: "Vigilância Sanitária", corpo_bombeiros: "Corpo de Bombeiros", meio_ambiente: "Meio Ambiente" };
const licencaTipoLabels: Record<string, string> = { definitiva: "Definitiva", dispensada: "Dispensada", com_vencimento: "Com Vencimento", em_processo: "Em Processo" };
const estados = ["AC", "AL", "AP", "AM", "BA", "CE", "DF", "ES", "GO", "MA", "MT", "MS", "MG", "PA", "PB", "PR", "PE", "PI", "RJ", "RN", "RS", "RO", "RR", "SC", "SP", "SE", "TO"];

const AVAILABLE_MODULES = [
  { id: 'societario', label: 'Societário' },
  { id: 'agendamentos', label: 'Agendamentos' },
  { id: 'fiscal', label: 'Fiscal' },
  { id: 'pessoal', label: 'Pessoal' },
  { id: 'licencas', label: 'Licenças' },
  { id: 'certificados', label: 'Certificados Digitais' },
  { id: 'certidoes', label: 'Certidões Negativas' },
  { id: 'procuracoes', label: 'Procurações' },
  { id: 'vencimentos', label: 'Vencimentos' },
  { id: 'parcelamentos', label: 'Parcelamentos' },
  { id: 'recalculos', label: 'Recálculos' },
  { id: 'honorarios', label: 'Honorários' },
  { id: 'declaracoes_anuais', label: 'Declarações Anuais' },
  { id: 'declaracoes_mensais', label: 'Declarações Mensais' },
];

const SocietarioEmpresaPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const location = useLocation();
  const state = location.state as { nome?: string; processoId?: string } | null;
  const isNew = id === "nova";
  const [activeTab, setActiveTab] = useState("dados");
  const [loading, setLoading] = useState(!isNew);
  const [saving, setSaving] = useState(false);

  // Form state
  const [nomeEmpresa, setNomeEmpresa] = useState("");
  const [cnpj, setCnpj] = useState("");
  const [dataAbertura, setDataAbertura] = useState("");
  const [porteEmpresa, setPorteEmpresa] = useState("");
  const [regimeTributario, setRegimeTributario] = useState("simples");
  const [naturezaJuridica, setNaturezaJuridica] = useState("");
  const [situacao, setSituacao] = useState("ativa");
  const [endereco, setEndereco] = useState<Endereco>({ ...emptyEndereco });
  const [socios, setSocios] = useState<Socio[]>([]);
  const [licencas, setLicencas] = useState<LicencaRow[]>([]);
  const [newSocio, setNewSocio] = useState<Socio>({ nome: "", cpf: "", administrador: false });

  // Config params
  const { userData } = useAuth();
  const isAdmin = userData?.isAdmin || false;
  const [modulosAtivos, setModulosAtivos] = useState<string[]>(AVAILABLE_MODULES.map(m => m.id));
  const [profiles, setProfiles] = useState<any[]>([]);
  const [userAcessos, setUserAcessos] = useState<Record<string, string[]>>({});
  const [selectedUserId, setSelectedUserId] = useState<string | null>(null);

  useEffect(() => {
    const fetchProfiles = async () => {
      if (!isAdmin) return;

      const { data: profiles } = await supabase.from("profiles").select("*").eq("ativo", true);
      if (!profiles) return;

      const userIds = profiles.map(p => p.user_id);
      const [{ data: roles }, { data: access }] = await Promise.all([
        supabase.from("user_roles").select("user_id, role").in("user_id", userIds),
        supabase.from("empresa_acessos").select("user_id").in("user_id", userIds)
      ]);

      const clientIds = new Set([
        ...(roles?.filter(r => (r.role as any) === 'client').map(r => r.user_id) || []),
        ...(access?.map(a => a.user_id) || [])
      ]);

      const internalProfiles = profiles.filter(p => !clientIds.has(p.user_id));
      setProfiles(internalProfiles);
    };
    fetchProfiles();

    if (isNew) {
      if (state?.nome) {
        setNomeEmpresa(state.nome);
      }
      // Initialize default licencas
      setLicencas(Object.keys(licencaLabels).map(tipo => ({ tipo_licenca: tipo, status: null, vencimento: null, numero_processo: null })));
      return;
    }
    const load = async () => {
      const { data: emp } = await supabase.from("empresas").select("*").eq("id", id).single();
      if (emp) {
        setNomeEmpresa(emp.nome_empresa);
        setCnpj(emp.cnpj || "");
        setDataAbertura(emp.data_abertura || "");
        setPorteEmpresa(emp.porte_empresa || "");
        setRegimeTributario(emp.regime_tributario || "simples");
        setNaturezaJuridica(emp.natureza_juridica || "");
        setSituacao(emp.situacao || "ativa");
        const addr = (emp.endereco as any) || {};
        setEndereco({ ...emptyEndereco, ...addr });
        setModulosAtivos(emp.modulos_ativos || AVAILABLE_MODULES.map(m => m.id));
      }

      // Load acessos só se for admin
      if (isAdmin) {
        const { data: acessos } = await supabase.from("empresa_acessos").select("*").eq("empresa_id", id);
        const acessosMap: Record<string, string[]> = {};
        if (acessos) {
          acessos.forEach(a => { acessosMap[a.user_id] = a.modulos_permitidos; });
        }
        setUserAcessos(acessosMap);
      }

      const { data: sociosData } = await supabase.from("socios").select("*").eq("empresa_id", id);
      setSocios((sociosData || []).map(s => ({ id: s.id, nome: s.nome, cpf: s.cpf || "", administrador: s.administrador || false })));

      const { data: licData } = await supabase.from("licencas").select("*").eq("empresa_id", id);
      const existingTypes = new Set((licData || []).map(l => l.tipo_licenca));
      const allLicencas = [
        ...(licData || []).map(l => ({ id: l.id, tipo_licenca: l.tipo_licenca, status: l.status, vencimento: l.vencimento, numero_processo: l.numero_processo })),
        ...Object.keys(licencaLabels).filter(t => !existingTypes.has(t)).map(t => ({ tipo_licenca: t, status: null, vencimento: null, numero_processo: null })),
      ];
      setLicencas(allLicencas);
      setLoading(false);
    };
    load();
  }, [id, isNew]);

  const handleSave = async () => {
    if (!nomeEmpresa.trim()) { toast.error("Nome da empresa é obrigatório"); return; }
    setSaving(true);
    try {
      const empresaData = {
        nome_empresa: nomeEmpresa, cnpj: cnpj || null,
        data_abertura: dataAbertura || null, porte_empresa: porteEmpresa || null,
        regime_tributario: regimeTributario as any, natureza_juridica: naturezaJuridica || null,
        situacao: situacao as any, endereco: endereco as any,
        modulos_ativos: modulosAtivos
      };

      let empresaId = id;
      if (isNew) {
        const { data, error } = await supabase.from("empresas").insert(empresaData).select("id").single();
        if (error) throw error;
        empresaId = data.id;
      } else {
        const { error } = await supabase.from("empresas").update(empresaData).eq("id", id);
        if (error) throw error;
      }

      // Save socios - delete all and re-insert
      if (!isNew) {
        await supabase.from("socios").delete().eq("empresa_id", empresaId!);
      }
      if (socios.length > 0) {
        const { error: socError } = await supabase.from("socios").insert(
          socios.map(s => ({ empresa_id: empresaId!, nome: s.nome, cpf: s.cpf || null, administrador: s.administrador }))
        );
        if (socError) throw socError;
      }

      // Save licencas - delete all and re-insert
      if (!isNew) {
        await supabase.from("licencas").delete().eq("empresa_id", empresaId!);
      }
      const licToInsert = licencas.filter(l => l.status);
      if (licToInsert.length > 0) {
        const { error: licError } = await supabase.from("licencas").insert(
          licToInsert.map(l => ({
            empresa_id: empresaId!, tipo_licenca: l.tipo_licenca,
            status: l.status as any, vencimento: l.vencimento || null, numero_processo: l.numero_processo || null,
          }))
        );
        if (licError) throw licError;
      }

      // Save user acessos (Only Admins can do this)
      if (isAdmin) {
        if (!isNew && empresaId) {
          await supabase.from("empresa_acessos").delete().eq("empresa_id", empresaId);
        }
        const acessosToInsert = Object.entries(userAcessos).map(([uid, mods]) => ({
          empresa_id: empresaId!, user_id: uid, modulos_permitidos: mods
        }));

        if (acessosToInsert.length > 0) {
          const { error: accError } = await supabase.from("empresa_acessos").insert(acessosToInsert);
          if (accError) throw accError;
        }
      }

      if (isNew && state?.processoId) {
        await supabase.from("processos_societarios" as any).update({ status: 'concluido' }).eq("id", state.processoId);
      }

      toast.success(isNew ? "Empresa cadastrada com sucesso!" : "Empresa atualizada com sucesso!");
      if (isNew) navigate(`/societario`);
      else navigate(`/societario`);
    } catch (err: any) {
      toast.error("Erro ao salvar: " + err.message);
    }
    setSaving(false);
  };

  const addSocio = () => {
    if (!newSocio.nome.trim()) { toast.error("Nome do sócio é obrigatório"); return; }
    setSocios(prev => [...prev, { ...newSocio }]);
    setNewSocio({ nome: "", cpf: "", administrador: false });
    toast.success("Sócio adicionado!");
  };

  const removeSocio = (index: number) => {
    setSocios(prev => prev.filter((_, i) => i !== index));
    toast.success("Sócio removido!");
  };

  const toggleAdmin = (index: number) => {
    setSocios(prev => prev.map((s, i) => i === index ? { ...s, administrador: !s.administrador } : s));
  };

  const updateLicenca = (tipo: string, field: string, value: string) => {
    setLicencas(prev => prev.map(l => l.tipo_licenca === tipo ? { ...l, [field]: value } : l));
  };

  if (loading) {
    return <div className="flex items-center justify-center h-64"><div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>;
  }

  const inputCls = "w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none transition-colors";
  const labelCls = "block text-sm font-medium text-card-foreground mb-1.5";

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
        <div className="flex items-center gap-3">
          <button onClick={() => navigate("/societario")} className="p-2 rounded-lg hover:bg-muted text-muted-foreground hover:text-foreground transition-colors"><ArrowLeft size={20} /></button>
        </div>
        <div className="flex gap-2">
          {!isNew && (
            <button
              onClick={async () => {
                if (!cnpj) { toast.error("CNPJ é necessário para criar acesso."); return; }
                const cleanCNPJ = cnpj.replace(/\D/g, "");
                const email = `${cleanCNPJ}@audipreve.com`;

                toast.loading("Criando acesso...", { id: "sync" });

                try {
                  const { data: { session } } = await supabase.auth.getSession();
                  if (!session?.access_token) throw new Error("Não autenticado");

                  const { data, error } = await supabase.functions.invoke("create-user", {
                    body: {
                      email,
                      nome: nomeEmpresa,
                      password: cleanCNPJ,
                      role: 'client',
                      empresa_id: id
                    }
                  });

                  if (error) {
                    // Check if error is "already registered"
                    let msg = error.message;
                    try {
                      const body = await (error as any).context?.json();
                      if (body?.code === "user_already_exists") {
                        toast.success("Acesso já existe para esta empresa.", { id: "sync" });
                        return;
                      }
                      if (body?.error) msg = body.error;
                    } catch (e) { }
                    throw new Error(msg);
                  }

                  toast.success("Acesso criado com sucesso!", { id: "sync" });
                } catch (err: any) {
                  toast.error("Erro: " + err.message, { id: "sync" });
                }
              }}
              className="flex items-center gap-2 px-4 py-2.5 rounded-xl text-sm font-semibold bg-info/10 text-info hover:bg-info/20 transition-all shadow-sm"
            >
              <Shield size={16} /> Criar Acesso Portal
            </button>
          )}
          <button onClick={handleSave} disabled={saving} className="flex items-center gap-2 px-5 py-2.5 rounded-xl text-sm font-semibold text-primary-foreground shadow-md hover:shadow-lg transition-all disabled:opacity-50" style={{ background: "var(--gradient-primary)" }}>
            <Save size={16} /> {saving ? "Salvando..." : "Salvar"}
          </button>
        </div>
      </div>

      <div className="flex gap-1 bg-muted/50 rounded-xl p-1 overflow-x-auto">
        {tabs.filter(t => isAdmin || t.id !== "configuracoes").map((tab) => (
          <button key={tab.id} onClick={() => setActiveTab(tab.id)} className={`flex items-center gap-2 px-4 py-2.5 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${activeTab === tab.id ? "bg-card text-card-foreground shadow-sm" : "text-muted-foreground hover:text-foreground"}`}>
            {tab.icon}{tab.label}
          </button>
        ))}
      </div>

      <div className="module-card">
        {activeTab === "dados" && (
          <div className="space-y-6">
            <h2 className="text-lg font-semibold text-card-foreground flex items-center gap-2"><Building2 size={20} className="text-primary" /> Dados Gerais</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
              <div className="md:col-span-2"><label className={labelCls}>Nome da Empresa *</label><input value={nomeEmpresa} onChange={e => setNomeEmpresa(e.target.value)} className={inputCls} placeholder="Razão Social" /></div>
              <div><label className={labelCls}>CNPJ</label><input value={cnpj} onChange={e => setCnpj(maskCNPJ(e.target.value))} className={inputCls} placeholder="00.000.000/0000-00" /></div>
              <div><label className={labelCls}>Data de Abertura</label><input type="date" value={dataAbertura} onChange={e => setDataAbertura(e.target.value)} className={inputCls} /></div>
              <div><label className={labelCls}>Porte da Empresa</label><select value={porteEmpresa} onChange={e => setPorteEmpresa(e.target.value)} className={inputCls}><option value="">Selecione</option><option value="mei">MEI</option><option value="me">Microempresa (ME)</option><option value="epp">Empresa de Pequeno Porte (EPP)</option><option value="medio">Médio Porte</option><option value="grande">Grande Porte</option></select></div>
              <div><label className={labelCls}>Regime Tributário</label><select value={regimeTributario} onChange={e => setRegimeTributario(e.target.value)} className={inputCls}><option value="simples">Simples Nacional</option><option value="lucro_presumido">Lucro Presumido</option><option value="lucro_real">Lucro Real</option><option value="mei">MEI</option></select></div>
              <div><label className={labelCls}>Natureza Jurídica</label><select value={naturezaJuridica} onChange={e => setNaturezaJuridica(e.target.value)} className={inputCls}><option value="">Selecione</option><option value="ei">Empresário Individual (EI)</option><option value="eireli">EIRELI</option><option value="ltda">Sociedade Limitada (LTDA)</option><option value="slu">Sociedade Limitada Unipessoal (SLU)</option><option value="sa">Sociedade Anônima (S.A.)</option><option value="ss">Sociedade Simples</option><option value="mei">MEI</option></select></div>
              <div><label className={labelCls}>Situação</label><select value={situacao} onChange={e => setSituacao(e.target.value)} className={inputCls}><option value="ativa">Ativa</option><option value="paralisada">Paralisada</option><option value="baixada">Baixada</option></select></div>
            </div>
          </div>
        )}

        {activeTab === "endereco" && (
          <div className="space-y-6">
            <h2 className="text-lg font-semibold text-card-foreground flex items-center gap-2"><MapPin size={20} className="text-primary" /> Endereço</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
              <div className="md:col-span-2"><label className={labelCls}>Logradouro</label><input value={endereco.logradouro} onChange={e => setEndereco({ ...endereco, logradouro: e.target.value })} className={inputCls} placeholder="Rua, Avenida..." /></div>
              <div><label className={labelCls}>Número</label><input value={endereco.numero} onChange={e => setEndereco({ ...endereco, numero: e.target.value })} className={inputCls} /></div>
              <div><label className={labelCls}>Bairro</label><input value={endereco.bairro} onChange={e => setEndereco({ ...endereco, bairro: e.target.value })} className={inputCls} /></div>
              <div><label className={labelCls}>Cidade</label><input value={endereco.cidade} onChange={e => setEndereco({ ...endereco, cidade: e.target.value })} className={inputCls} /></div>
              <div><label className={labelCls}>Estado</label><select value={endereco.estado} onChange={e => setEndereco({ ...endereco, estado: e.target.value })} className={inputCls}><option value="">Selecione</option>{estados.map(uf => <option key={uf} value={uf}>{uf}</option>)}</select></div>
              <div><label className={labelCls}>CEP</label><input value={endereco.cep} onChange={e => setEndereco({ ...endereco, cep: e.target.value })} className={inputCls} placeholder="00000-000" /></div>
            </div>
          </div>
        )}

        {activeTab === "socios" && (
          <div className="space-y-6">
            <h2 className="text-lg font-semibold text-card-foreground flex items-center gap-2"><Users size={20} className="text-primary" /> Quadro Societário</h2>
            <div className="p-4 bg-muted/30 rounded-xl border border-border space-y-4">
              <p className="text-sm font-medium text-card-foreground">Adicionar Sócio</p>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 items-end">
                <div><label className={labelCls}>Nome Completo *</label><input value={newSocio.nome} onChange={e => setNewSocio({ ...newSocio, nome: e.target.value })} className={inputCls} placeholder="Nome do sócio" /></div>
                <div><label className={labelCls}>CPF</label><input value={newSocio.cpf} onChange={e => setNewSocio({ ...newSocio, cpf: maskCPF(e.target.value) })} className={inputCls} placeholder="000.000.000-00" /></div>

                <div className="flex items-center gap-3">
                  <label className="flex items-center gap-2 text-sm cursor-pointer"><input type="checkbox" checked={newSocio.administrador} onChange={e => setNewSocio({ ...newSocio, administrador: e.target.checked })} className="w-4 h-4 rounded border-border text-primary focus:ring-primary" /> Administrador</label>
                  <button onClick={addSocio} className="flex items-center gap-1 px-4 py-2.5 rounded-lg text-sm font-semibold text-primary-foreground" style={{ background: "var(--gradient-primary)" }}><Plus size={14} /> Adicionar</button>
                </div>
              </div>
            </div>
            {socios.length === 0 ? (
              <div className="text-center py-8 text-muted-foreground"><Users size={40} className="mx-auto mb-3 opacity-30" /><p className="font-medium">Nenhum sócio cadastrado</p></div>
            ) : (
              <div className="space-y-3">
                {socios.map((socio, idx) => (
                  <div key={idx} className="flex items-center justify-between p-4 bg-card rounded-xl border border-border hover:shadow-sm transition-shadow">
                    <div className="flex items-center gap-3">
                      <div className={`w-10 h-10 rounded-full flex items-center justify-center ${socio.administrador ? "bg-warning/20 text-warning" : "bg-muted text-muted-foreground"}`}>
                        {socio.administrador ? <Crown size={18} /> : <Users size={18} />}
                      </div>
                      <div>
                        <p className="font-medium text-card-foreground">{socio.nome}</p>
                        <p className="text-xs text-muted-foreground">CPF: {socio.cpf || "—"} {socio.administrador && <span className="ml-2 badge-status badge-warning text-[10px]">Administrador</span>}</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-2">
                      <button onClick={() => toggleAdmin(idx)} className="p-2 rounded-lg hover:bg-muted transition-colors text-muted-foreground hover:text-warning" title="Alternar administrador"><Crown size={15} /></button>
                      <button onClick={() => removeSocio(idx)} className="p-2 rounded-lg hover:bg-destructive/10 transition-colors text-muted-foreground hover:text-destructive" title="Remover"><Trash2 size={15} /></button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {activeTab === "licencas" && (
          <div className="space-y-6">
            <h2 className="text-lg font-semibold text-card-foreground flex items-center gap-2"><ScrollText size={20} className="text-primary" /> Licenças Municipais</h2>
            <div className="space-y-4">
              {licencas.map((licenca) => (
                <div key={licenca.tipo_licenca} className="p-5 bg-muted/30 rounded-xl border border-border space-y-4">
                  <div className="flex items-center gap-2"><FileText size={16} className="text-primary" /><h3 className="font-semibold text-card-foreground">{licencaLabels[licenca.tipo_licenca]}</h3></div>
                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                    <div><label className={labelCls}>Status</label><select value={licenca.status || ""} onChange={e => updateLicenca(licenca.tipo_licenca, "status", e.target.value)} className={inputCls}><option value="">Não definido</option><option value="definitiva">Definitiva</option><option value="dispensada">Dispensada</option><option value="com_vencimento">Com Vencimento</option><option value="em_processo">Em Processo</option></select></div>
                    {licenca.status === "com_vencimento" && <div><label className={labelCls}>Data de Vencimento</label><input type="date" value={licenca.vencimento || ""} onChange={e => updateLicenca(licenca.tipo_licenca, "vencimento", e.target.value)} className={inputCls} /></div>}
                    {licenca.status === "em_processo" && <div><label className={labelCls}>Nº do Processo</label><input value={licenca.numero_processo || ""} onChange={e => updateLicenca(licenca.tipo_licenca, "numero_processo", e.target.value)} className={inputCls} placeholder="Número do processo" /></div>}
                  </div>
                  {licenca.status && (
                    <div className="flex items-center gap-2">
                      <span className={`badge-status ${licenca.status === "definitiva" ? "badge-success" : licenca.status === "dispensada" ? "badge-gray" : licenca.status === "com_vencimento" ? "badge-warning" : "badge-info"}`}>{licencaTipoLabels[licenca.status]}</span>
                      {licenca.status === "com_vencimento" && licenca.vencimento && <span className="text-xs text-muted-foreground flex items-center gap-1"><CalendarIcon size={12} /> {new Date(licenca.vencimento).toLocaleDateString("pt-BR")}</span>}
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === "configuracoes" && (
          <div className="space-y-8">
            <h2 className="text-lg font-semibold text-card-foreground flex items-center gap-2"><Settings size={20} className="text-primary" /> Configurações Gerais</h2>

            <div className="space-y-4">
              <h3 className="font-medium text-card-foreground">Módulos Ativos</h3>
              <p className="text-sm text-muted-foreground">Selecione em quais módulos esta empresa deve aparecer.</p>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3 p-4 bg-muted/30 rounded-xl border border-border">
                {AVAILABLE_MODULES.map(mod => (
                  <label key={mod.id} className="flex items-center gap-2 text-sm cursor-pointer p-2 hover:bg-muted rounded-lg transition-colors">
                    <input
                      type="checkbox"
                      checked={modulosAtivos.includes(mod.id)}
                      onChange={e => {
                        if (e.target.checked) setModulosAtivos(prev => [...prev, mod.id]);
                        else setModulosAtivos(prev => prev.filter(m => m !== mod.id));
                      }}
                      className="w-4 h-4 rounded border-border text-primary focus:ring-primary"
                    />
                    {mod.label}
                  </label>
                ))}
              </div>
            </div>

            <div className="space-y-4">
              <h3 className="font-medium text-card-foreground">Restrição de Acesso por Usuário</h3>
              <p className="text-sm text-muted-foreground">Oculte módulos específicos para determinados perfis. Por padrão, todos os usuários possuem acesso a todos os módulos ativos da empresa.</p>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="md:col-span-1 space-y-2 max-h-[400px] overflow-y-auto pr-2">
                  {profiles.map(prof => (
                    <button
                      key={prof.id}
                      onClick={() => setSelectedUserId(prof.user_id)}
                      className={`w-full text-left p-3 rounded-xl border transition-all ${selectedUserId === prof.user_id ? "bg-primary/10 border-primary/30 text-primary" : "bg-card border-border hover:border-primary/30 text-card-foreground"}`}
                    >
                      <p className="font-medium text-sm">{prof.nome_completo || "Usuário"}</p>
                      <p className="text-xs opacity-70 mt-0.5">{prof.cpf || "Sem CPF"}</p>
                    </button>
                  ))}
                  {profiles.length === 0 && <p className="text-sm text-muted-foreground">Nenhum usuário ativo carregado.</p>}
                </div>

                <div className="md:col-span-2">
                  {selectedUserId ? (
                    <div className="p-5 bg-card rounded-xl border border-border space-y-4">
                      {(() => {
                        const selectedProf = profiles.find(p => p.user_id === selectedUserId);
                        return <h4 className="font-semibold text-card-foreground mb-4">Permissões para {selectedProf?.nome_completo}</h4>;
                      })()}
                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        {AVAILABLE_MODULES.map(mod => {
                          const userMods = userAcessos[selectedUserId] || modulosAtivos;
                          const isAllowed = userMods.includes(mod.id);
                          const isModActive = modulosAtivos.includes(mod.id);

                          return (
                            <label key={mod.id} className={`flex items-center gap-2 text-sm p-3 rounded-lg border transition-all ${!isModActive ? "opacity-50 cursor-not-allowed bg-muted/50" : "cursor-pointer hover:bg-muted bg-background"}`}>
                              <input
                                type="checkbox"
                                disabled={!isModActive}
                                checked={isAllowed && isModActive}
                                onChange={e => {
                                  const currentMods = userAcessos[selectedUserId] || [...modulosAtivos];
                                  let newMods = [];
                                  if (e.target.checked) {
                                    newMods = [...currentMods, mod.id];
                                  } else {
                                    newMods = currentMods.filter(m => m !== mod.id);
                                  }
                                  setUserAcessos(prev => ({ ...prev, [selectedUserId]: newMods }));
                                }}
                                className="w-4 h-4 rounded border-border text-primary focus:ring-primary disabled:opacity-50"
                              />
                              <span className={!isModActive ? "line-through text-muted-foreground" : "text-foreground"}>{mod.label}</span>
                            </label>
                          );
                        })}
                      </div>
                      <div className="bg-info/10 text-info p-3 rounded-lg text-xs mt-4 flex gap-2 items-start opacity-80">
                        <span className="mt-0.5">ℹ️</span>
                        <p>Módulos desativados na aba "Módulos Ativos" ficarão inacessíveis independentemente desta configuração individual.</p>
                      </div>
                    </div>
                  ) : (
                    <div className="h-[250px] flex items-center justify-center bg-muted/30 rounded-xl border border-dashed border-border p-6 text-center text-muted-foreground">
                      <div>
                        <Users size={32} className="mx-auto mb-3 opacity-30" />
                        <p className="font-medium">Selecione um usuário ao lado</p>
                        <p className="text-sm opacity-70 mt-1">Para configurar permissões específicas</p>
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default SocietarioEmpresaPage;

import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useNavigate } from "react-router-dom";
import {
  Plus, Search, Edit2, Trash2, Eye, Building2, Filter,
  ChevronDown, Activity, Clock, CheckCircle, AlertCircle,
  FileText, ArrowRight, History, X, Check, ChevronUp, User, MessageSquare,
  Star
} from "lucide-react";
import { toast } from "sonner";
import { TableSkeleton, PageHeaderSkeleton } from "@/components/PageSkeleton";
import { syncCompanyClients } from "@/lib/sync-clients";
import { RefreshCw } from "lucide-react";

interface Empresa {
  id: string; nome_empresa: string; cnpj: string | null; regime_tributario: string | null;
  situacao: string | null; porte_empresa: string | null; natureza_juridica: string | null;
  data_abertura: string | null; created_at: string | null; socios_count?: number;
}

interface DetalhesPasso {
  enviado_por?: string;
  observacoes?: string;
}

interface Processo {
  id: string; tipo: string; nome_empresa: string | null; empresa_id: string | null;
  numero_processo: string | null; data_inicio: string; status: string;
  envio_dbe_at: string | null; envio_fcn_at: string | null; envio_contrato_at: string | null;
  envio_taxa_at: string | null; assinatura_contrato_at: string | null;
  arquivamento_junta_at: string | null; foi_deferido: boolean; foi_arquivado: boolean;
  em_exigencia: boolean; exigencia_motivo: string | null; exigencia_respondida: boolean;
  detalhes_passos: Record<string, DetalhesPasso>;
}

const regimeLabels: Record<string, string> = {
  simples: "Simples Nacional", lucro_presumido: "Lucro Presumido", lucro_real: "Lucro Real", mei: "MEI",
};
const situacaoConfig: Record<string, { label: string; cls: string }> = {
  ativa: { label: "Ativa", cls: "badge-success" },
  paralisada: { label: "Paralisada", cls: "badge-warning" },
  baixada: { label: "Baixada", cls: "badge-danger" },
};

const tipoProcessoLabels: Record<string, string> = {
  abertura: "Abertura de Empresa",
  alteracao: "Alteração de Empresa",
  baixa: "Baixa de Empresa",
  abertura_mei: "Abertura de MEI",
  baixa_mei: "Baixa de MEI",
};

const passosConfig = [
  { id: 'envio_dbe_at', label: 'Envio do DBE' },
  { id: 'envio_fcn_at', label: 'Envio da FCN' },
  { id: 'envio_contrato_at', label: 'Envio do Contrato' },
  { id: 'envio_taxa_at', label: 'Envio da Taxa' },
  { id: 'assinatura_contrato_at', label: 'Assinatura' },
  { id: 'arquivamento_junta_at', label: 'Arquivamento' },
];

const SocietarioPage: React.FC = () => {
  const [activeMainTab, setActiveMainTab] = useState<"empresas" | "processos">("empresas");
  const [empresas, setEmpresas] = useState<Empresa[]>([]);
  const [processos, setProcessos] = useState<Processo[]>([]);
  const [loadingInitial, setLoadingInitial] = useState(true);
  const [isFavorite, setIsFavorite] = useState(false);
  const [search, setSearch] = useState("");
  const [filterSituacao, setFilterSituacao] = useState("todas");
  const [filterRegime, setFilterRegime] = useState("todos");
  const [showFilters, setShowFilters] = useState(false);
  const [activeTab, setActiveTab] = useState<"ativas" | "paralisadas" | "baixadas" | "mei">("ativas");
  const [showNovoProcesso, setShowNovoProcesso] = useState(false);
  const [novoProcessoData, setNovoProcessoData] = useState({ tipo: 'abertura', nome_empresa: '', numero_processo: '', data_inicio: new Date().toISOString().split('T')[0] });
  const [expandedProcesso, setExpandedProcesso] = useState<string | null>(null);
  const [processoToDelete, setProcessoToDelete] = useState<{ id: string, nome: string } | null>(null);

  const navigate = useNavigate();

  const fetchEmpresas = async () => {
    const { data } = await supabase.from("empresas").select("*").order("nome_empresa");
    const { data: sociosData } = await supabase.from("socios").select("empresa_id");
    const sociosCounts: Record<string, number> = {};
    sociosData?.forEach(s => { sociosCounts[s.empresa_id] = (sociosCounts[s.empresa_id] || 0) + 1; });
    setEmpresas((data || []).map(e => ({ ...e, socios_count: sociosCounts[e.id] || 0 })));
  };

  const fetchProcessos = async () => {
    const { data } = await supabase.from("processos_societarios" as any).select("*").order("created_at", { ascending: false });
    setProcessos((data as unknown as Processo[]) || []);
  };

  useEffect(() => {
    const init = async () => {
      setLoadingInitial(true);
      await Promise.all([fetchEmpresas(), fetchProcessos()]);
      setLoadingInitial(false);
    };
    init();
  }, []);

  // Realtime subscriptions
  useEffect(() => {
    const channel = supabase.channel("societario_changes")
      .on("postgres_changes", { event: "*", schema: "public", table: "empresas" }, () => fetchEmpresas())
      .on("postgres_changes", { event: "*", schema: "public", table: "processos_societarios" as any }, () => fetchProcessos())
      .subscribe();
    return () => { supabase.removeChannel(channel); };
  }, []);

  const handleCreateProcesso = async () => {
    if (!novoProcessoData.nome_empresa) { toast.error("Preencha o nome da empresa"); return; }
    const { error } = await supabase.from("processos_societarios" as any).insert([novoProcessoData]);
    if (error) toast.error("Erro ao criar: " + error.message);
    else { toast.success("Processo iniciado!"); setShowNovoProcesso(false); fetchProcessos(); }
  };

  const openDeleteConfirm = (id: string, nome: string) => {
    setProcessoToDelete({ id, nome });
  };

  const executeDeleteProcesso = async () => {
    if (!processoToDelete) return;
    const { id } = processoToDelete;
    setProcessoToDelete(null); // Fecha o modal imediatamente para não bloquear UI

    const { error } = await supabase.from("processos_societarios" as any).delete().eq("id", id);
    if (error) toast.error("Erro ao excluir: " + error.message);
    else { toast.success("Processo excluído!"); fetchProcessos(); }
  };

  const updatePasso = async (id: string, campo: string, value: any) => {
    const { error } = await supabase.from("processos_societarios" as any).update({ [campo]: value }).eq("id", id);
    if (error) toast.error("Erro: " + error.message);
    else fetchProcessos();
  };

  const updateDetalhePasso = async (id: string, stepId: string, field: string, value: string) => {
    const processo = processos.find(p => p.id === id);
    if (!processo) return;
    const novosDetalhes = { ...processo.detalhes_passos };
    novosDetalhes[stepId] = { ...novosDetalhes[stepId], [field]: value };
    const { error } = await supabase.from("processos_societarios" as any).update({ detalhes_passos: novosDetalhes }).eq("id", id);
    if (error) toast.error("Erro ao salvar detalhes: " + error.message);
    else fetchProcessos();
  };

  const filteredEmpresas = empresas.filter((e) => {
    const matchSearch = e.nome_empresa?.toLowerCase().includes(search.toLowerCase()) || e.cnpj?.includes(search);
    const matchSituacao = filterSituacao === "todas" || e.situacao === filterSituacao;
    const matchRegime = filterRegime === "todos" || e.regime_tributario === filterRegime;
    let matchTab = false;
    if (activeTab === "ativas") matchTab = !e.situacao || e.situacao === "ativa";
    else if (activeTab === "paralisadas") matchTab = e.situacao === "paralisada";
    else if (activeTab === "baixadas") matchTab = e.situacao === "baixada";
    else if (activeTab === "mei") matchTab = e.porte_empresa === "mei" && (!e.situacao || e.situacao === "ativa");
    return matchSearch && matchSituacao && matchRegime && matchTab;
  });

  const stats = {
    ativas: empresas.filter(e => !e.situacao || e.situacao === "ativa").length,
    paralisadas: empresas.filter(e => e.situacao === "paralisada").length,
    baixadas: empresas.filter(e => e.situacao === "baixada").length,
    mei: empresas.filter(e => e.porte_empresa === "mei" && (!e.situacao || e.situacao === "ativa")).length,
    processosAtivos: processos.filter(p => p.status === 'em_andamento').length,
  };

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Main Tabs */}
      <div className="flex border-b border-border">
        <button onClick={() => setActiveMainTab("empresas")} className={`pb-3 px-6 text-sm font-bold transition-all border-b-2 ${activeMainTab === "empresas" ? "border-primary text-primary" : "border-transparent text-muted-foreground hover:text-foreground"}`}>
          <div className="flex items-center gap-2 underline-offset-8">
            <Building2 size={18} /> EMPRESAS
          </div>
        </button>
        <button onClick={() => setActiveMainTab("processos")} className={`pb-3 px-6 text-sm font-bold transition-all border-b-2 ${activeMainTab === "processos" ? "border-primary text-primary" : "border-transparent text-muted-foreground hover:text-foreground"}`}>
          <div className="flex items-center gap-2">
            <Activity size={18} /> PROCESSOS
            {stats.processosAtivos > 0 && <span className="bg-primary text-primary-foreground text-[10px] px-1.5 py-0.5 rounded-full">{stats.processosAtivos}</span>}
          </div>
        </button>
      </div>

      {loadingInitial ? (
        <div className="space-y-8">
          <PageHeaderSkeleton />
          <TableSkeleton rows={8} />
        </div>
      ) : (
        <>
          {activeMainTab === "empresas" && (
            <div className="space-y-6 animate-in slide-in-from-left-2 duration-300">
              <div className="flex justify-between items-center">
                <h1 className="text-2xl font-bold text-card-foreground">Societário</h1>
                <div className="flex gap-2">
                  <button
                    onClick={() => setIsFavorite(!isFavorite)}
                    className={`p-2.5 rounded-xl border transition-all ${isFavorite ? "bg-amber-500/10 border-amber-500/50 text-amber-500" : "bg-card border-border text-muted-foreground hover:bg-muted"}`}
                    title={isFavorite ? "Remover dos Favoritos" : "Adicionar aos Favoritos"}
                  >
                    <Star size={20} fill={isFavorite ? "currentColor" : "none"} />
                  </button>
                  <button
                    onClick={async () => {
                      const confirmed = window.confirm("Isso irá criar e confirmar o acesso de todas as empresas cadastradas que ainda não possuem login. Deseja continuar?");
                      if (!confirmed) return;

                      const id = toast.loading("Sincronizando acessos...", { duration: 0 });
                      try {
                        const result = await syncCompanyClients((curr, total) => {
                          toast.loading(`Sincronizando: ${curr}/${total}...`, { id });
                        });
                        toast.success(`Sincronização concluída! ${result?.synced} acessos criados/corrigidos.`, { id });
                      } catch (err: any) {
                        toast.error("Erro na sincronização: " + err.message, { id });
                      }
                    }}
                    className="flex items-center gap-2 px-4 py-2.5 rounded-xl text-sm font-bold bg-muted text-muted-foreground hover:bg-muted/80 transition-all border border-border"
                    title="Sincronizar todos os acessos do portal"
                  >
                    <RefreshCw size={18} />
                    Sincronizar Acessos
                  </button>
                  <button onClick={() => navigate("/societario/nova")} className="flex items-center gap-2 px-5 py-2.5 rounded-xl text-sm font-bold text-primary-foreground shadow-md hover:shadow-lg transition-all" style={{ background: "var(--gradient-primary)" }}>
                    <Plus size={18} /> Nova Empresa
                  </button>
                </div>
              </div>

              <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
                {[{ label: "Ativas", value: stats.ativas, cls: "badge-success" }, { label: "MEI", value: stats.mei, cls: "bg-info/10 text-info border-info/20" }, { label: "Paralisadas", value: stats.paralisadas, cls: "badge-warning" }, { label: "Baixadas", value: stats.baixadas, cls: "badge-danger" }].map((s) => (
                  <div key={s.label} className="stat-card flex items-center justify-between">
                    <div><p className="text-xs text-muted-foreground font-bold uppercase tracking-wider">{s.label}</p><p className="text-2xl font-bold text-card-foreground mt-1">{s.value}</p></div>
                    <span className={`badge-status ${s.cls} text-lg px-4 py-1.5`}>{s.value}</span>
                  </div>
                ))}
              </div>

              <div className="module-card">
                <div className="flex flex-col sm:flex-row gap-3 items-start sm:items-center">
                  <div className="relative flex-1 w-full"><Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" /><input type="text" placeholder="Buscar por nome ou CNPJ..." value={search} onChange={(e) => setSearch(e.target.value)} className="w-full pl-9 pr-4 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" /></div>
                  <button onClick={() => setShowFilters(!showFilters)} className={`flex items-center gap-2 px-4 py-2.5 rounded-lg text-sm font-medium border transition-colors ${showFilters ? "border-primary bg-primary/10 text-primary" : "border-border text-muted-foreground hover:text-foreground hover:bg-muted"}`}><Filter size={16} /> Filtros <ChevronDown size={14} className={`transition-transform ${showFilters ? "rotate-180" : ""}`} /></button>
                </div>
                {showFilters && (
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mt-4 pt-4 border-t border-border animate-in slide-in-from-top-2">
                    <div>
                      <label className="block text-xs font-bold text-muted-foreground mb-1 uppercase tracking-tight">Regime</label>
                      <select value={filterRegime} onChange={(e) => setFilterRegime(e.target.value)} className="w-full px-3 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none">
                        <option value="todos">Todos</option>
                        <option value="simples">Simples Nacional</option>
                        <option value="lucro_presumido">Lucro Presumido</option>
                        <option value="lucro_real">Lucro Real</option>
                        <option value="mei">MEI</option>
                      </select>
                    </div>
                    <div>
                      <label className="block text-xs font-bold text-muted-foreground mb-1 uppercase tracking-tight">Situação (Geral)</label>
                      <select value={filterSituacao} onChange={(e) => setFilterSituacao(e.target.value)} className="w-full px-3 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none">
                        <option value="todas">Todas</option>
                        <option value="ativa">Ativa</option>
                        <option value="paralisada">Paralisada</option>
                        <option value="baixada">Baixada</option>
                      </select>
                    </div>
                    <div className="flex items-end">
                      <button
                        onClick={() => { setSearch(""); setFilterSituacao("todas"); setFilterRegime("todos"); }}
                        className="text-xs text-primary font-bold hover:underline py-2"
                      >
                        Limpar Filtros
                      </button>
                    </div>
                  </div>
                )}
              </div>

              <div className="flex border-b border-border overflow-x-auto no-scrollbar pt-2">
                {["ativas", "mei", "paralisadas", "baixadas"].map(t => (
                  <button key={t} onClick={() => setActiveTab(t as any)} className={`px-5 py-3 text-sm font-bold border-b-2 transition-all whitespace-nowrap ${activeTab === t ? "border-primary text-primary" : "border-transparent text-muted-foreground hover:text-foreground"}`}>{t === 'ativas' ? 'Empresas Ativas' : t === 'mei' ? 'Empresas MEI' : t === 'paralisadas' ? 'Paralisadas' : 'Baixadas'}</button>
                ))}
              </div>

              <div className="module-card overflow-x-auto p-0 border-t-0 rounded-t-none">
                <table className="data-table">
                  <thead><tr><th>Empresa</th><th>CNPJ</th><th>Regime</th><th>Situação</th><th>Sócios</th><th className="text-right">Ações</th></tr></thead>
                  <tbody>
                    {filteredEmpresas.length === 0 ? (
                      <tr><td colSpan={6} className="text-center py-12 text-muted-foreground"><p className="font-medium">Nenhuma empresa encontrada</p></td></tr>
                    ) : filteredEmpresas.map((emp) => {
                      const sit = situacaoConfig[emp.situacao || "ativa"] || situacaoConfig.ativa;
                      return (
                        <tr key={emp.id} className="cursor-pointer group" onClick={() => navigate(`/societario/${emp.id}`)}>
                          <td><div className="flex items-center gap-3"><div className="w-9 h-9 rounded-lg bg-primary/10 flex items-center justify-center transition-transform group-hover:scale-110"><Building2 size={16} className="text-primary" /></div><span className="font-semibold text-card-foreground">{emp.nome_empresa}</span></div></td>
                          <td className="text-muted-foreground font-mono text-xs">{emp.cnpj || "—"}</td>
                          <td className="text-muted-foreground">{regimeLabels[emp.regime_tributario || ""] || "—"}</td>
                          <td><span className={`badge-status ${sit.cls}`}>{sit.label}</span></td>
                          <td className="text-muted-foreground">{emp.socios_count || 0}</td>
                          <td className="text-right" onClick={(e) => e.stopPropagation()}>
                            <div className="flex items-center justify-end gap-1">
                              <button onClick={() => navigate(`/societario/${emp.id}`)} className="p-2 rounded-lg hover:bg-muted text-muted-foreground hover:text-primary"><Eye size={15} /></button>
                              <button onClick={() => navigate(`/societario/${emp.id}`)} className="p-2 rounded-lg hover:bg-muted text-muted-foreground hover:text-primary"><Edit2 size={15} /></button>
                            </div>
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {activeMainTab === "processos" && (
            <div className="space-y-6 animate-in slide-in-from-right-2 duration-300">
              <div className="flex justify-between items-center">
                <h3 className="text-lg font-bold text-card-foreground flex items-center gap-2"><History size={20} className="text-primary" /> Processos Societários</h3>
                <button onClick={() => setShowNovoProcesso(true)} className="flex items-center gap-2 px-5 py-2.5 rounded-xl text-sm font-bold text-primary-foreground shadow-md transition-all" style={{ background: "var(--gradient-primary)" }}>
                  <Plus size={18} /> Novo Processo
                </button>
              </div>

              {showNovoProcesso && (
                <div className="module-card bg-muted/20 border-primary/30 animate-in zoom-in-95 duration-200">
                  <div className="flex items-center justify-between mb-4"><h4 className="font-bold text-primary flex items-center gap-2"><Plus size={16} /> Iniciar Novo Processo</h4><button onClick={() => setShowNovoProcesso(false)} className="p-1 hover:bg-muted rounded-md"><X size={18} /></button></div>
                  <div className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
                    <div><label className="text-xs font-bold text-muted-foreground block mb-1 uppercase tracking-tight">TIPO DE PROCESSO</label><select value={novoProcessoData.tipo} onChange={e => setNovoProcessoData({ ...novoProcessoData, tipo: e.target.value })} className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm outline-none focus:ring-2 focus:ring-primary">{Object.entries(tipoProcessoLabels).map(([k, v]) => <option key={k} value={k}>{v}</option>)}</select></div>
                    <div className="md:col-span-1"><label className="text-xs font-bold text-muted-foreground block mb-1 uppercase tracking-tight">NOME DA EMPRESA</label><input value={novoProcessoData.nome_empresa} onChange={e => setNovoProcessoData({ ...novoProcessoData, nome_empresa: e.target.value })} placeholder="Ex: Nova LTDA" className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm outline-none" /></div>
                    <div><label className="text-xs font-bold text-muted-foreground block mb-1 uppercase tracking-tight">Nº PROCESSO</label><input value={novoProcessoData.numero_processo} onChange={e => setNovoProcessoData({ ...novoProcessoData, numero_processo: e.target.value })} placeholder="Número se houver" className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm outline-none" /></div>
                    <button onClick={handleCreateProcesso} className="w-full py-2.5 bg-primary text-primary-foreground rounded-lg text-sm font-bold hover:opacity-90">Iniciar</button>
                  </div>
                </div>
              )}

              <div className="space-y-4">
                {processos.length === 0 ? (
                  <div className="module-card text-center py-12 text-muted-foreground"><Activity size={40} className="mx-auto mb-3 opacity-20" /><p>Nenhum processo iniciado</p></div>
                ) : processos.map(p => {
                  const isExpanded = expandedProcesso === p.id;

                  return (
                    <div key={p.id} className={`module-card border-l-4 transition-all overflow-hidden ${isExpanded ? "border-l-primary shadow-lg ring-1 ring-primary/20" : "border-l-muted hover:border-l-primary/50"}`}>
                      {/* Accordion Header (Summary) */}
                      <div
                        className="flex flex-col md:flex-row items-center justify-between gap-4 cursor-pointer"
                        onClick={() => setExpandedProcesso(isExpanded ? null : p.id)}
                      >
                        <div className="flex items-center gap-4 flex-1">
                          <div className={`w-12 h-12 rounded-xl flex items-center justify-center transition-colors ${isExpanded ? "bg-primary text-primary-foreground" : "bg-primary/10 text-primary"}`}>
                            <Building2 size={24} />
                          </div>
                          <div className="flex-1">
                            <div className="flex items-center gap-2">
                              <h4 className="font-bold text-card-foreground text-lg">{p.nome_empresa || "Sem Nome"}</h4>
                              {p.status === 'concluido' && <span className="badge-status badge-success text-[10px]">Concluído</span>}
                            </div>
                            <div className="flex flex-wrap gap-x-4 gap-y-1 mt-1">
                              <span className="text-xs font-bold text-primary uppercase tracking-tighter">{tipoProcessoLabels[p.tipo] || p.tipo}</span>
                              {p.numero_processo && <span className="text-xs text-muted-foreground font-mono"># {p.numero_processo}</span>}
                              <span className="text-xs text-muted-foreground flex items-center gap-1"><Clock size={12} /> {new Date(p.data_inicio).toLocaleDateString()}</span>
                            </div>
                          </div>
                        </div>

                        <div className="flex items-center gap-2">
                          <button
                            onClick={(e) => { e.stopPropagation(); openDeleteConfirm(p.id, p.nome_empresa || "Sem Nome"); }}
                            className="p-2 rounded-lg hover:bg-destructive/10 text-muted-foreground hover:text-destructive transition-colors"
                          >
                            <Trash2 size={18} />
                          </button>
                          <div className="p-2 rounded-full hover:bg-muted text-primary transition-transform">
                            {isExpanded ? <ChevronUp size={24} /> : <ChevronDown size={24} />}
                          </div>
                        </div>
                      </div>

                      {/* Accordion Body (Details - Vertical Timeline) */}
                      {isExpanded && (
                        <div className="mt-8 pt-6 border-t border-border animate-in slide-in-from-top-2 duration-300 space-y-8">
                          <div className="space-y-6">
                            {passosConfig.map((step, idx) => {
                              const isDone = !!(p as any)[step.id];
                              const prevStepId = idx > 0 ? passosConfig[idx - 1].id : null;
                              const isPrevDone = prevStepId ? !!(p as any)[prevStepId] : true;
                              const isBlockedByExigencia = step.id === 'arquivamento_junta_at' && !p.foi_deferido && !p.exigencia_respondida;
                              const canComplete = !isDone && isPrevDone && !isBlockedByExigencia;

                              const detalhes = (p.detalhes_passos && p.detalhes_passos[step.id]) || {};

                              return (
                                <div key={step.id} className="relative pl-10">
                                  {/* Line Connector */}
                                  {idx < passosConfig.length - 1 && (
                                    <div className={`absolute left-4 top-8 bottom-0 w-0.5 -ml-px ${isDone ? "bg-primary" : "bg-muted"}`} />
                                  )}

                                  {/* Icon Circle */}
                                  <div className={`absolute left-0 top-0 w-8 h-8 rounded-full border-2 flex items-center justify-center transition-all ${isDone ? "bg-primary border-primary text-primary-foreground" : isPrevDone ? "border-primary/50 text-primary" : "border-muted text-muted-foreground"}`}>
                                    {isDone ? <Check size={16} strokeWidth={3} /> : <span className="text-xs font-bold">{idx + 1}</span>}
                                  </div>

                                  <div className="grid grid-cols-1 md:grid-cols-12 gap-6 items-start">
                                    {/* Title & Status */}
                                    <div className="md:col-span-4">
                                      <h5 className={`font-bold transition-colors ${isDone ? "text-primary" : "text-card-foreground"}`}>{step.label}</h5>
                                      <div className="flex items-center gap-2 mt-1">
                                        <button
                                          onClick={() => {
                                            if (isDone) return;
                                            if (!isPrevDone) { toast.error("Conclua a etapa anterior"); return; }
                                            if (isBlockedByExigencia) { toast.error("Aguardando Deferimento ou Resposta de Exigência"); return; }
                                            updatePasso(p.id, step.id, new Date().toISOString());
                                          }}
                                          className={`text-[10px] font-bold px-2 py-0.5 rounded-full uppercase transition-all ${isDone ? "bg-green-500 text-white" : canComplete ? "bg-primary text-white hover:scale-105 cursor-pointer" : "bg-muted text-muted-foreground cursor-not-allowed"}`}
                                        >
                                          {isDone ? "Concluído" : "Marcar Concluído"}
                                        </button>
                                        {isDone && <span className="text-[10px] font-mono text-muted-foreground">{new Date((p as any)[step.id]).toLocaleString()}</span>}
                                      </div>
                                    </div>

                                    {/* Form Details */}
                                    <div className="md:col-span-8 grid grid-cols-1 sm:grid-cols-2 gap-4">
                                      <div className="space-y-1">
                                        <label className="text-[10px] font-bold text-muted-foreground flex items-center gap-1 uppercase tracking-tighter">
                                          <User size={10} /> Enviado por
                                        </label>
                                        <input
                                          type="text"
                                          value={detalhes.enviado_por || ''}
                                          onChange={e => updateDetalhePasso(p.id, step.id, 'enviado_por', e.target.value)}
                                          placeholder="Quem enviou?"
                                          className="w-full px-3 py-1.5 border border-border rounded-lg bg-background text-sm focus:ring-1 focus:ring-primary outline-none"
                                        />
                                      </div>
                                      <div className="space-y-1">
                                        <label className="text-[10px] font-bold text-muted-foreground flex items-center gap-1 uppercase tracking-tighter">
                                          <MessageSquare size={10} /> Observações
                                        </label>
                                        <textarea
                                          value={detalhes.observacoes || ''}
                                          onChange={e => updateDetalhePasso(p.id, step.id, 'observacoes', e.target.value)}
                                          placeholder="Ocorrências..."
                                          rows={1}
                                          className="w-full px-3 py-1.5 border border-border rounded-lg bg-background text-sm focus:ring-1 focus:ring-primary outline-none resize-none"
                                        />
                                      </div>
                                    </div>
                                  </div>
                                </div>
                              );
                            })}
                          </div>

                          {/* Assinatura Gate Controls */}
                          {p.assinatura_contrato_at && !p.arquivamento_junta_at && (
                            <div className="p-5 rounded-2xl bg-primary/5 border border-primary/20 space-y-4">
                              <div className="flex items-center justify-between">
                                <h5 className="text-xs font-bold text-primary uppercase tracking-widest">Controle Pós-Assinatura</h5>
                                <div className="flex gap-2">
                                  <button
                                    onClick={() => updatePasso(p.id, 'foi_deferido', !p.foi_deferido)}
                                    className={`flex items-center gap-1.5 px-4 py-2 rounded-xl text-xs font-bold transition-all ${p.foi_deferido ? "bg-green-500 text-white shadow-md shadow-green-500/20" : "bg-card border border-border text-muted-foreground hover:bg-green-50"}`}
                                  >
                                    {p.foi_deferido ? <CheckCircle size={14} /> : <div className="w-3 h-3 rounded-full border-2 border-current" />} DEFERIDO
                                  </button>
                                  <button
                                    onClick={() => updatePasso(p.id, 'em_exigencia', !p.em_exigencia)}
                                    className={`flex items-center gap-1.5 px-4 py-2 rounded-xl text-xs font-bold transition-all ${p.em_exigencia ? "bg-warning text-white shadow-md shadow-warning/20" : "bg-card border border-border text-muted-foreground hover:bg-warning/5"}`}
                                  >
                                    <AlertCircle size={14} /> EM EXIGÊNCIA
                                  </button>
                                </div>
                              </div>

                              {p.em_exigencia && (
                                <div className="space-y-3 animate-in fade-in slide-in-from-top-2">
                                  <div>
                                    <label className="text-[10px] font-bold text-muted-foreground block mb-1 uppercase tracking-tighter">Motivo da Exigência</label>
                                    <textarea
                                      value={p.exigencia_motivo || ''}
                                      onChange={e => updatePasso(p.id, 'exigencia_motivo', e.target.value)}
                                      placeholder="Descreva detalhadamente..."
                                      className="w-full px-4 py-2 border border-warning/30 rounded-xl bg-background text-sm focus:ring-1 focus:ring-warning outline-none shadow-inner"
                                    />
                                  </div>
                                  <div className="flex justify-end">
                                    <button
                                      onClick={() => { updatePasso(p.id, 'exigencia_respondida', true); updatePasso(p.id, 'em_exigencia', false); }}
                                      className="px-6 py-2 bg-warning text-white rounded-xl text-xs font-bold hover:shadow-lg transition-all"
                                    >
                                      EXIGÊNCIA RESPONDIDA
                                    </button>
                                  </div>
                                </div>
                              )}
                            </div>
                          )}

                          {/* Finalize Button */}
                          {p.arquivamento_junta_at && p.status !== 'concluido' && (
                            <div className="flex justify-center pt-4">
                              <button
                                onClick={() => navigate("/societario/nova", { state: { nome: p.nome_empresa, processoId: p.id } })}
                                className="group flex items-center gap-3 px-10 py-4 rounded-2xl bg-green-500 text-white font-bold text-base shadow-xl hover:shadow-green-500/30 transition-all hover:-translate-y-1 active:scale-95"
                              >
                                <CheckCircle size={22} className="group-hover:scale-110 transition-transform" /> FINALIZAR PROCESSO E CADASTRAR EMPRESA
                                <ArrowRight size={18} />
                              </button>
                            </div>
                          )}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {/* Modal de Confirmação de Exclusão */}
          {processoToDelete && (
            <div className="fixed inset-0 bg-background/80 backdrop-blur-sm z-50 flex items-center justify-center p-4 animate-in fade-in duration-200">
              <div className="bg-card w-full max-w-sm rounded-2xl shadow-xl border border-border overflow-hidden animate-in zoom-in-95 duration-200">
                <div className="p-6">
                  <div className="w-12 h-12 rounded-full bg-destructive/10 text-destructive flex items-center justify-center mb-4">
                    <Trash2 size={24} />
                  </div>
                  <h2 className="text-xl font-bold text-card-foreground">Excluir Processo</h2>
                  <p className="text-muted-foreground mt-2 text-sm leading-relaxed">
                    Tem certeza que deseja excluir o processo da empresa <strong className="text-foreground">{processoToDelete.nome}</strong>? Esta ação não pode ser desfeita.
                  </p>
                </div>
                <div className="p-4 border-t border-border bg-muted/30 flex justify-end gap-3">
                  <button
                    onClick={() => setProcessoToDelete(null)}
                    className="px-5 py-2.5 rounded-xl text-sm font-bold text-muted-foreground hover:bg-muted hover:text-foreground transition-colors"
                  >
                    Cancelar
                  </button>
                  <button
                    onClick={executeDeleteProcesso}
                    className="px-5 py-2.5 rounded-xl text-sm font-bold bg-destructive text-destructive-foreground hover:bg-destructive/90 transition-all shadow-sm active:scale-95"
                  >
                    Sim, Excluir
                  </button>
                </div>
              </div>
            </div>
          )}
        </>
      )}
    </div>
  );
};

export default SocietarioPage;

import React, { useState } from "react";
import { useAuth } from "@/contexts/AuthContext";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import { useNavigate } from "react-router-dom";
import logoAudipreve from "@/assets/logo-audipreve.png";

const TermosPage: React.FC = () => {
  const { user, refreshUserData } = useAuth();
  const navigate = useNavigate();
  const [accepted, setAccepted] = useState(false);
  const [acceptedLgpd, setAcceptedLgpd] = useState(false);
  const [saving, setSaving] = useState(false);

  const handleAccept = async () => {
    if (!accepted || !acceptedLgpd) {
      toast.error("Você precisa aceitar ambos os termos para continuar");
      return;
    }
    setSaving(true);
    try {
      const { error } = await supabase.from("profiles").update({
        terms_accepted_at: new Date().toISOString(),
      }).eq("user_id", user!.id);
      if (error) throw error;
      await refreshUserData();
      toast.success("Termos aceitos com sucesso!");
      navigate("/dashboard", { replace: true });
    } catch (err: any) {
      toast.error("Erro: " + err.message);
    } finally {
      setSaving(false);
    }
  };

