export default VencimentosPage;

import React, { useState, useEffect } from "react";
import { useAuth } from "@/contexts/AuthContext";
import { supabase } from "@/integrations/supabase/client";
import { useNavigate } from "react-router-dom";
import { Loader2, ShieldCheck, Mail, RefreshCw } from "lucide-react";
import { toast } from "sonner";
import logoAudipreve from "@/assets/logo-audipreve.png";

const VerificationPage: React.FC = () => {
    const { user, userData, refreshUserData } = useAuth();
    const navigate = useNavigate();
    const [code, setCode] = useState("");
    const [loading, setLoading] = useState(false);
    const [sending, setSending] = useState(false);

    useEffect(() => {
        if (userData?.firstAccessDone) {
            navigate("/dashboard", { replace: true });
        } else {
            sendCode();
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [userData]);

    const sendCode = async () => {
        if (sending) return;
        setSending(true);
        try {
            const { error } = await supabase.functions.invoke("send-verification-code", {
                body: { action: "send" },
            });
            if (error) throw error;
            toast.success("Código enviado para o seu e-mail!");
        } catch (err: any) {
            toast.error("Erro ao enviar código: " + err.message);
        } finally {
            setSending(false);
        }
    };

    const handleVerify = async (e: React.FormEvent) => {
        e.preventDefault();
        if (code.length < 6) {
            toast.error("O código deve ter 6 dígitos");
            return;
        }

        setLoading(true);
        try {
            const { data, error } = await supabase.functions.invoke("send-verification-code", {
                body: { action: "verify", code },
            });

            if (error) throw error;
            if (data?.error) throw new Error(data.error);

            toast.success("Acesso verificado com sucesso!");
            await refreshUserData();
            navigate("/dashboard", { replace: true });
        } catch (err: any) {
            toast.error(err.message === "Código inválido" ? "Código incorreto. Tente novamente." : err.message);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center p-4">
            <div className="bg-card border border-border rounded-2xl shadow-xl w-full max-w-md overflow-hidden p-8 space-y-8 animate-in fade-in zoom-in duration-300">
                <div className="text-center">
                    <img src={logoAudipreve} alt="Audipreve" className="w-20 h-20 object-contain mx-auto mb-6" />
                    <div className="inline-flex items-center justify-center w-12 h-12 rounded-full bg-primary/10 text-primary mb-4">
                        <ShieldCheck size={24} />
                    </div>
                    <h2 className="text-2xl font-bold text-card-foreground">Verificação de Segurança</h2>
                    <p className="text-muted-foreground mt-2 text-sm leading-relaxed">
                        Como este é seu primeiro acesso, enviamos um código de 6 dígitos para <strong>{user?.email}</strong>.
                    </p>
                </div>

                <form onSubmit={handleVerify} className="space-y-6">
                    <div className="space-y-2">
                        <label className="text-sm font-semibold text-muted-foreground ml-1">Código de Verificação</label>
                        <input
                            type="text"
                            maxLength={6}
                            value={code}
                            onChange={(e) => setCode(e.target.value.replace(/\D/g, ""))}
                            className="w-full text-center text-3xl font-black tracking-[0.5em] h-16 border-2 border-border rounded-xl bg-background focus:ring-4 focus:ring-primary/20 focus:border-primary outline-none transition-all"
                            placeholder="000000"
                            required
                        />
                    </div>

                    <button
                        type="submit"
                        disabled={loading}
                        className="w-full py-4 rounded-xl font-bold text-primary-foreground shadow-lg transition-all hover:scale-[1.02] disabled:opacity-50"
                        style={{ background: "var(--gradient-primary)" }}
                    >
                        {loading ? <Loader2 className="animate-spin mx-auto" size={20} /> : "Verificar e Entrar"}
                    </button>
                </form>

                <div className="text-center">
                    <button
                        onClick={sendCode}
                        disabled={sending}
                        className="text-sm font-medium text-primary hover:underline flex items-center justify-center gap-2 mx-auto disabled:opacity-50"
                    >
                        {sending ? <Loader2 className="animate-spin" size={14} /> : <RefreshCw size={14} />}
                        Não recebeu o código? Reenviar
                    </button>
                </div>
            </div>
        </div>
    );
};

export default VerificationPage;

import { createClient } from "https://esm.sh/@supabase/supabase-js@2.39.7";

const allowedModules = ["societario", "fiscal", "pessoal", "certidoes", "certificados", "licencas", "procuracoes", "honorarios", "obrigacoes", "parcelamentos", "recalculos", "vencimentos"];

Deno.serve(async (req) => {
  const origin = req.headers.get("origin");
  const corsHeaders = {
    "Access-Control-Allow-Origin": origin || "*",
    "Access-Control-Allow-Methods": "POST, OPTIONS",
    "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
  };

  if (req.method === "OPTIONS") {
    return new Response("ok", { headers: corsHeaders });
  }

  try {
    const authHeader = req.headers.get("authorization");
    if (!authHeader) {
      return new Response(JSON.stringify({
        error: "Não autenticado",
        code: "no_auth_header"
      }), { status: 401, headers: { ...corsHeaders, "Content-Type": "application/json" } });
    }

    const supabaseUrl = Deno.env.get("SUPABASE_URL");
    const supabaseServiceKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");

    if (!supabaseUrl || !supabaseServiceKey) {
      return new Response(JSON.stringify({
        error: "Configuração do servidor incompleta",
        code: "env_vars_missing"
      }), { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } });
    }

    const supabaseAdmin = createClient(supabaseUrl, supabaseServiceKey);
    const token = authHeader.replace("Bearer ", "");

    const { data: { user: caller }, error: authError } = await supabaseAdmin.auth.getUser(token);

    if (authError || !caller) {
      return new Response(JSON.stringify({
        error: "Sessão inválida",
        code: "auth_token_invalid"
      }), { status: 401, headers: { ...corsHeaders, "Content-Type": "application/json" } });
    }

    const body = await req.json();
    const { email, nome, cpf, isAdmin: makeAdmin, modules, role, empresa_id, password } = body;

    if (!email) {
      return new Response(JSON.stringify({ error: "Email é obrigatório" }), { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } });
    }

    // Check if user already exists
    const { data: userDataObj, error: listError } = await supabaseAdmin.auth.admin.listUsers();
    if (listError) throw listError;

    const existingUser = userDataObj.users.find((u: any) => u.email === email);
    let userId;

    if (existingUser) {
      const { data: updated, error: updateError } = await supabaseAdmin.auth.admin.updateUserById(existingUser.id, {
        password: password || "Mudar@Audipreve123",
        email_confirm: true,
        user_metadata: {
          full_name: nome,
          nome_completo: nome,
          role: role || (makeAdmin ? 'admin' : 'user'),
          empresa_id: empresa_id
        }
      });
      if (updateError) throw updateError;
      userId = updated.user.id;
    } else {
      const { data: userData, error: createError } = await supabaseAdmin.auth.admin.createUser({
        email,
        password: password || "Mudar@Audipreve123",
        email_confirm: true,
        user_metadata: {
          full_name: nome,
          nome_completo: nome,
          role: role || (makeAdmin ? 'admin' : 'user'),
          empresa_id: empresa_id
        }
      });
      if (createError) throw createError;
      userId = userData.user.id;
    }

    const isClientRole = role === 'client' || !!empresa_id;

    // Profiles upsert - Only safe columns
    const { error: profileError } = await supabaseAdmin.from("profiles").upsert({
      user_id: userId,
      full_name: nome,
      nome_completo: nome,
      cpf: cpf || null,
      profile_completed: isClientRole,
      first_access_done: isClientRole
    }, { onConflict: 'user_id' });

    if (profileError) {
      console.error("Profile upsert error:", profileError);
      // We continue anyway as the user is created
    }

    // Role assignment
    if (makeAdmin || role === 'admin') {
      await supabaseAdmin.from("user_roles").upsert({ user_id: userId, role: "admin" }, { onConflict: 'user_id,role' });
    } else {
      // Ensure they have 'user' role at least
      await supabaseAdmin.from("user_roles").upsert({ user_id: userId, role: "user" }, { onConflict: 'user_id,role' });
    }

    // Client assignment (empresa_acessos)
    if (role === 'client' || empresa_id) {
      const { error: accessError } = await supabaseAdmin.from("empresa_acessos").upsert({
        user_id: userId,
        empresa_id: empresa_id,
        modulos_permitidos: allowedModules // Default all for now or pass from body
      }, { onConflict: 'user_id,empresa_id' });

      if (accessError) console.error("Access upsert error:", accessError);
    } else if (modules && typeof modules === 'object') {
      // User Module Permissions assignment (for internal users)
      const moduleInserts = Object.entries(modules)
        .filter(([_, isGranted]) => isGranted === true)
        .map(([moduleName, _]) => ({
          user_id: userId,
          module_name: moduleName
        }));

      if (moduleInserts.length > 0) {
        // Clear existing permissions just in case it's an update
        await supabaseAdmin.from("user_module_permissions").delete().eq("user_id", userId);

        const { error: modulesError } = await supabaseAdmin.from("user_module_permissions").insert(moduleInserts);
        if (modulesError) console.error("Modules insert error:", modulesError);
      }
    }

    return new Response(JSON.stringify({ success: true, user_id: userId }), {
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });

  } catch (err: any) {
    console.error("create-user error:", err);
    return new Response(JSON.stringify({
      error: "Erro interno",
      details: err.message
    }), {
      status: 400,
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  }
});

import { createClient } from "https://esm.sh/@supabase/supabase-js@2.39.7";

Deno.serve(async (req) => {
  const origin = req.headers.get("origin");
  const corsHeaders = {
    "Access-Control-Allow-Origin": origin || "*",
    "Access-Control-Allow-Methods": "POST, OPTIONS",
    "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
  };

  if (req.method === "OPTIONS") {
    return new Response("ok", { headers: corsHeaders });
  }

  try {
    const authHeader = req.headers.get("authorization");
    if (!authHeader) {
      return new Response(JSON.stringify({ error: "Não autenticado" }), {
        status: 401, headers: { ...corsHeaders, "Content-Type": "application/json" }
      });
    }

    const supabaseUrl = Deno.env.get("SUPABASE_URL");
    const supabaseServiceKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");

    if (!supabaseUrl || !supabaseServiceKey) {
      throw new Error("Variáveis de ambiente do Supabase ausentes.");
    }

    const supabaseAdmin = createClient(supabaseUrl, supabaseServiceKey);
    const token = authHeader.replace("Bearer ", "");

    // Get the caller user securely
    const { data: { user }, error: userError } = await supabaseAdmin.auth.getUser(token);
    if (userError || !user) throw new Error("Unauthorized Token");

    // Check if the caller is an admin
    const { data: roles } = await supabaseAdmin.from("user_roles").select("role").eq("user_id", user.id);
    const isAdmin = roles?.some(r => r.role === 'admin');
    if (!isAdmin) throw new Error("Apenas administradores podem gerenciar usuários.");

    // Parse payload
    const body = await req.json();
    const { action, target_user_id, module, enable } = body;

    if (!action || !target_user_id) throw new Error("Action e target_user_id são obrigatórios.");

    if (action === "toggleModule") {
      if (!module) throw new Error("Module é obrigatório.");
      if (enable) {
        await supabaseAdmin.from("user_module_permissions").insert({ user_id: target_user_id, module_name: module });
      } else {
        await supabaseAdmin.from("user_module_permissions").delete().eq("user_id", target_user_id).eq("module_name", module);
      }
    }
    else if (action === "toggleAdmin") {
      if (enable) {
        await supabaseAdmin.from("user_roles").insert({ user_id: target_user_id, role: "admin" });
      } else {
        await supabaseAdmin.from("user_roles").delete().eq("user_id", target_user_id).eq("role", "admin");
      }
    }
    else if (action === "deleteUser") {
      await supabaseAdmin.from("profiles").delete().eq("user_id", target_user_id);
      const { error: deleteError } = await supabaseAdmin.auth.admin.deleteUser(target_user_id);
      if (deleteError) throw deleteError;
    }
    else {
      throw new Error(`Ação desconhecida: ${action}`);
    }

    return new Response(JSON.stringify({ success: true }), {
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });

  } catch (err: any) {
    console.error("manage-user error:", err);
    return new Response(JSON.stringify({ error: err.message }), {
      status: 400,
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  }
});

import { createClient } from "https://esm.sh/@supabase/supabase-js@2.39.7";

const corsHeaders = {
    "Access-Control-Allow-Origin": "*",
    "Access-Control-Allow-Methods": "POST, OPTIONS",
    "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
};

Deno.serve(async (req) => {
    if (req.method === "OPTIONS") {
        return new Response("ok", { headers: corsHeaders });
    }

    try {
        console.log("send-verification-code: [PASSO 1] Início");
        const RESEND_API_KEY = Deno.env.get("RESEND_API_KEY");
        const supabaseUrl = Deno.env.get("SUPABASE_URL");
        const supabaseServiceKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
        const supabaseAnonKey = Deno.env.get("SUPABASE_ANON_KEY");

        if (!RESEND_API_KEY || !supabaseUrl || !supabaseServiceKey || !supabaseAnonKey) {
            console.error("send-verification-code: [ERRO 500] Env vars faltando");
            return new Response(JSON.stringify({
                error: "Configuração do servidor incompleta (Env vars missing)",
                resend_present: !!RESEND_API_KEY,
                url_present: !!supabaseUrl,
                service_present: !!supabaseServiceKey,
                anon_present: !!supabaseAnonKey
            }), { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } });
        }

        const authHeader = req.headers.get("authorization");
        if (!authHeader) {
            console.warn("send-verification-code: [ERRO 401] Sem header Auth");
            return new Response(JSON.stringify({ error: "Não autenticado (Header Authorization ausente)" }), { status: 401, headers: { ...corsHeaders, "Content-Type": "application/json" } });
        }

        const supabaseAdmin = createClient(supabaseUrl, supabaseServiceKey);
        const supabaseUser = createClient(supabaseUrl, supabaseAnonKey, {
            global: { headers: { Authorization: authHeader } }
        });

        console.log("send-verification-code: [PASSO 2] Validando usuário...");
        const { data: { user }, error: authError } = await supabaseUser.auth.getUser();
        if (authError || !user) {
            console.error("send-verification-code: [ERRO 401] Auth check failed:", authError?.message);
            return new Response(JSON.stringify({ error: "Token inválido ou sessão expirada", details: authError?.message }), { status: 401, headers: { ...corsHeaders, "Content-Type": "application/json" } });
        }

        console.log("send-verification-code: [PASSO 3] Usuário validado:", user.id, user.email);

        const body = await req.json();
        const { action } = body;
        console.log("send-verification-code: [PASSO 4] Ação recebida:", action);

        if (action === "send") {
            const code = Math.floor(100000 + Math.random() * 900000).toString();
            const expiresAt = new Date(Date.now() + 10 * 60 * 1000).toISOString(); // 10 min

            console.log("send-verification-code: [PASSO 5] Salvando código no DB...");
            const { error: dbError } = await supabaseAdmin.from("profiles").update({
                verification_code: code,
                verification_code_expires_at: expiresAt
            }).eq("user_id", user.id);

            if (dbError) {
                console.error("send-verification-code: [ERRO DB]", dbError.message);
                throw new Error("Erro ao salvar código de verificação: " + dbError.message);
            }

            // Enviar email via Resend
            console.log("send-verification-code: [PASSO 6] Enviando e-mail via Resend...");
            if (!user.email) throw new Error("E-mail do usuário não encontrado na sessão.");

            const res = await fetch("https://api.resend.com/emails", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": `Bearer ${RESEND_API_KEY}`,
                },
                body: JSON.stringify({
                    from: "Audipreve <gestor@audiprevecontabilidade.com.br>",
                    to: [user.email],
                    subject: `${code} é seu código de verificação Audipreve`,
                    html: `
                        <div style="font-family: sans-serif; max-width: 600px; margin: auto; padding: 20px; border: 1px solid #eee; border-radius: 10px;">
                            <h2 style="color: #333 text-align: center;">Verificação de Segurança</h2>
                            <p>Olá,</p>
                            <p>Você está realizando seu primeiro acesso ou recuperando sua senha no sistema Audipreve. Use o código abaixo para verificar sua identidade:</p>
                            <div style="background: #f4f4f4; padding: 20px; text-align: center; font-size: 32px; font-weight: bold; letter-spacing: 5px; color: #000; border-radius: 8px; margin: 20px 0;">
                                ${code}
                            </div>
                            <p style="font-size: 14px; color: #666;">Este código expira em 10 minutos. Se você não solicitou este acesso, ignore este e-mail.</p>
                            <hr style="border: none; border-top: 1px solid #eee; margin: 20px 0;" />
                            <p style="font-size: 12px; color: #999; text-align: center;">Audipreve Contabilidade</p>
                        </div>
                    `,
                }),
            });

            if (!res.ok) {
                const errorData = await res.json();
                console.error("send-verification-code: [ERRO Resend]", errorData);

                // Bypass condition removed to surface actual Resend errors

                throw new Error("Falha ao enviar e-mail: " + (errorData.message || JSON.stringify(errorData)));
            }

            console.log("send-verification-code: [PASSO 7] Sucesso!");
            return new Response(JSON.stringify({ success: true, message: "Código enviado" }), {
                headers: { ...corsHeaders, "Content-Type": "application/json" },
            });
        }

        if (action === "verify") {
            const { code } = body;
            console.log("send-verification-code: [PASSO 5v] Verificando código...");
            const { data: profile, error: selectError } = await supabaseAdmin.from("profiles")
                .select("verification_code, verification_code_expires_at")
                .eq("user_id", user.id)
                .single();

            if (selectError) throw new Error("Erro ao buscar perfil: " + selectError.message);

            if (!profile || profile.verification_code !== code) {
                console.warn("send-verification-code: [ERRO 400] Código incorreto");
                return new Response(JSON.stringify({ error: "Código inválido" }), { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } });
            }

            if (new Date() > new Date(profile.verification_code_expires_at)) {
                console.warn("send-verification-code: [ERRO 400] Código expirado");
                return new Response(JSON.stringify({ error: "Código expirado" }), { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } });
            }

            console.log("send-verification-code: [PASSO 6v] Marcando como verificado...");
            const { error: updateError } = await supabaseAdmin.from("profiles").update({
                first_access_done: true,
                verification_code: null,
                verification_code_expires_at: null
            }).eq("user_id", user.id);

            if (updateError) throw updateError;

            console.log("send-verification-code: [PASSO 7v] Verificado com sucesso!");
            return new Response(JSON.stringify({ success: true }), {
                headers: { ...corsHeaders, "Content-Type": "application/json" },
            });
        }

        return new Response(JSON.stringify({ error: "Ação inválida" }), { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } });

    } catch (err: any) {
        console.error("send-verification-code: [ERRO FATAL]", err.message);
        return new Response(JSON.stringify({ error: err.message, stack: err.stack }), {
            status: 400,
            headers: { ...corsHeaders, "Content-Type": "application/json" },
        });
    }
});
